-- Poems batch 135
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('047992e8-9846-4ea1-8ff2-144dd2e7cc57','詠荷花中小蓮蓬','楊萬里','宋','宋诗','song-poetry','','[]','山蜂愁雨損蜂兒，葉底安巢更倒垂。',32,'全唐诗/poet.song.142000.json','["山蜂愁雨損蜂兒，葉底安巢更倒垂。", "只有荷蜂不愁雨，蠟房仰卧萬花枝。"]'),
('8267bfac-a6d3-430e-a278-b0630aa045a7','病中屏肉味獨茹菜羹飯甚美','楊萬里','宋','宋诗','song-poetry','','[]','雲子香抄玉色鮮，菜羹新煮翠茸纖。',64,'全唐诗/poet.song.142000.json','["雲子香抄玉色鮮，菜羹新煮翠茸纖。", "人間膾炙無此味，天上酥陀恐爾甜。", "渾是土膏含雨露，何須醤豉與醯鹽。", "茹毛禍首雍巫出，饞到熊蹯未屬厭。"]'),
('3fd6b18e-8048-455b-a694-ce92d95c74cb','木犀芙蓉盛開','楊萬里','宋','宋诗','song-poetry','','[]','先生深住萬山村，霧裹雲包不見痕。',32,'全唐诗/poet.song.142000.json','["先生深住萬山村，霧裹雲包不見痕。", "也被閑人知去處，芙蓉巷裏木犀門。"]'),
('c1e4fe2d-6581-44f0-8553-4b804ba9975f','賀張功父寺丞新長鳳雛','楊萬里','宋','宋诗','song-poetry','','[]','念君只欠一英雛，萬事今君足也無。',64,'全唐诗/poet.song.142000.json','["念君只欠一英雛，萬事今君足也無。", "想見碧梧森翠竹，敢嘲老蚌出明珠。", "只今小德轉春鳥，後日熊兒捉蹇馿。", "自古相門長出相，煙樓一撞莫教輸。"]'),
('9bf5e262-8238-41f5-b8c8-47115313a589','題彭孝求碧雲飛觀','楊萬里','宋','宋诗','song-poetry','','[]','寸雲如絮起青原，飛空化作一碧山。',64,'全唐诗/poet.song.142000.json','["寸雲如絮起青原，飛空化作一碧山。", "天風吹上南斗邊，砰然墮在快閣前。", "老彭有孫拉雲住，海蜃吐樓壓雲去。", "日暮佳人來不來，朗誦湯休斷腸句。"]'),
('0cf19e11-060a-4da8-9f1f-b394725c290d','跋劉敏叔梅蘭竹石四清圖','楊萬里','宋','宋诗','song-poetry','','[]','老夫老伴竹千竿，湖石江梅更畹蘭。',32,'全唐诗/poet.song.142000.json','["老夫老伴竹千竿，湖石江梅更畹蘭。", "不道外人將短紙，一時捲去也無端。"]'),
('834737d4-00e7-4673-b7ac-7d4cc30b95dd','戲跋朱元晦楚辭解二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','注易箋詩解魯論，一帆徑度浴沂天。',32,'全唐诗/poet.song.142000.json','["注易箋詩解魯論，一帆徑度浴沂天。", "無端又被湘纍喚，去看西川競渡船。"]'),
('17d30333-76b3-4916-b85e-860afc28272a','戲跋朱元晦楚辭解二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','霜後藜枯無可羹，饑吟長作候蟲聲。',32,'全唐诗/poet.song.142000.json','["霜後藜枯無可羹，饑吟長作候蟲聲。", "藏神上訴天應泣，支賜江蘺與杜蘅。"]'),
('0614d0d9-c92c-40f8-b6f2-1d6454b04ea1','贈劉漢卿太醫','楊萬里','宋','宋诗','song-poetry','','[]','爐底金丹妙入神，月中玉兔擣成塵。',32,'全唐诗/poet.song.142000.json','["爐底金丹妙入神，月中玉兔擣成塵。", "臣門如市心如水，只要陰功活萬人。"]'),
('3be09fd9-a800-4748-afa3-90e14f543833','鵝兒黄似酒','楊萬里','宋','宋诗','song-poetry','','[]','野水浮天碧，鵝兒弄日黄。',72,'全唐诗/poet.song.142000.json','["野水浮天碧，鵝兒弄日黄。", "傍人殊秀色，似酒更風光。", "破殻雙翎嫩，眠沙百草香。", "却將金鬰鬯，試比菊衣裳。", "未博山陰墨，先娛錦里觴。", "滄波兼鳳沼，莫遣後鶖鶬。"]'),
('9be6a400-23d8-4f4b-9581-f61581196090','送清江王守赴召','楊萬里','宋','宋诗','song-poetry','','[]','世言富貴易得家世難，有賢父兄子弟未渠賢。',205,'全唐诗/poet.song.142000.json','["世言富貴易得家世難，有賢父兄子弟未渠賢。", "君不見祖孫父子兄與弟，根蘭樹玉枝亦桂。", "魏晉以來誰子家，只數江淮一王氏。", "世言淮水若絕渠不昌，不知淮水有絕渠更長。", "請看南朝到吾宋，中間人物無闕空。", "有曾有旦繼茂弘，即今紫樞繼子明。", "昔纔一人今三人，後者玉振前金聲。", "阿樞更有金玉阿兄子，兩有剛方兼豈弟。", "清江五馬來自東，三年一日一春風。", "又聞一節喚歸去，父老攔街遮不住。", "喚它父老且細聽，朝家也要好公卿。", "父老莫與朝家爭，打鼓發船催速行。"]'),
('b860180f-fa35-4551-a18a-6d5303b2d3d8','贈玉婿時可','楊萬里','宋','宋诗','song-poetry','','[]','忠襄先生有賢甥，盧溪先生有賢孫。',96,'全唐诗/poet.song.142000.json','["忠襄先生有賢甥，盧溪先生有賢孫。", "只今二十能綴文，超然下筆如有神。", "忠襄大節爭日月，盧溪清風敵霜雪。", "兩家不是無家法，何須外人問衣鉢。", "老夫卧病南溪旁，芙蓉紅盡菊半黄。", "子來問訊維摩詰，分似家風一瓣香。"]'),
('b40a53f5-00ff-429a-bc0d-27457e0ff763','題安成劉伯深爵瑞里報德堂上白爵圖','楊萬里','宋','宋诗','song-poetry','','[]','君不見書臺之北爵瑞里，安成令君旌孝子。',117,'全唐诗/poet.song.142000.json','["君不見書臺之北爵瑞里，安成令君旌孝子。", "報德堂前松造天，卜宅浩然老居士。", "居士元無一物遺，子孫只有牙籤三萬存。", "郎君飯此三萬軸，落紙雲煙動場屋。", "雪中負土成先塋，感得路人雙涕零。", "更傳雪爵雲上墮，天表孝子踏雪行。", "即看黄告來告弟，是時雪爵應再至。"]'),
('92c997e1-149b-4b8d-b786-4b684702d748','益公新作三層百尺新樓署曰圍山觀賀以唐律二章  其一','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','萬峰飛入子城頭，千里長江几上流。',64,'全唐诗/poet.song.142000.json','["萬峰飛入子城頭，千里長江几上流。", "外面週遭蒼玉笋，虛空幻出水晶樓。", "簾開雪月非三界，人立雲霄更九州。", "一騎紅塵北來底，平章軍國惱公不。"]'),
('a1b8cb27-fed3-4692-bd33-f7286f39b20a','益公新作三層百尺新樓署曰圍山觀賀以唐律二章  其二','楊萬里','宋','宋诗','song-poetry','','[]','崖谷求仙底有仙，金梯上去即仙源。',64,'全唐诗/poet.song.142000.json','["崖谷求仙底有仙，金梯上去即仙源。", "山川第一江西景，風月無邊相國園。", "十倍黄樓況黄閣，千尋青筆是青原。", "寫成脚力猶强句，燈火笙歌特地村。"]'),
('4a559b18-f3f1-44d3-ba42-630dfdba4a99','送丁卿季吏部赴召','楊萬里','宋','宋诗','song-poetry','','[]','吾州史君五十年，不曾召節來日邊。',176,'全唐诗/poet.song.142000.json','["吾州史君五十年，不曾召節來日邊。", "老夫送人作太守，不曾送人上九天。", "玉皇去年選丁寬，遣來螺浦蘇煢鰥。", "玉皇今年喚渠還，州民遮道不得前。", "文儒佳政萬口傳，近世能吏了不關。", "道渠豈弟父母然，凜如冰霜照人寒。", "道渠明斷神一般，秋毫不擾田里安。", "一州天下孰後先，要渠筆橐侍甘泉。", "尚書履聲再接連，更進一步百尺竿。", "紫樞黄閤半武間，梅花滿枝雪滿山。", "雪花能舞梅能言，滿餞史君金玉船。"]'),
('379b6541-a8e7-4a51-98db-ef8d1b33cac3','庚申東園花發二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','曉風細細復鮮鮮，也不鳴條也不喧。',32,'全唐诗/poet.song.142000.json','["曉風細細復鮮鮮，也不鳴條也不喧。", "却被花枝勾引著，掀桃舞柳恣它顛。"]'),
('e6443587-cd25-467a-a21f-f8873d9c0cd8','庚申東園花發二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','桃蹊李徑舊分栽，紅白教它各自開。',32,'全唐诗/poet.song.142000.json','["桃蹊李徑舊分栽，紅白教它各自開。", "可是桃花逞顔色，一枝穿過李花來。"]'),
('67649873-5e0f-4671-b75d-aaf496fbf8dd','與子仁登天柱岡過胡家塘蓴塘歸東園四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','嫩晴無日也無風，政是春光酒樣醲。',32,'全唐诗/poet.song.142000.json','["嫩晴無日也無風，政是春光酒樣醲。", "行到中峰元未覺，回頭已度打頭峰。"]'),
('01f6f237-b200-4097-938a-a8a419cd530e','與子仁登天柱岡過胡家塘蓴塘歸東園四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','胡床脚底萬峰寒，拄杖錐尖亂蘚斑。',32,'全唐诗/poet.song.142000.json','["胡床脚底萬峰寒，拄杖錐尖亂蘚斑。", "天柱岡頭行未飽，相携更上一重山。"]'),
('9c02d1e8-ffd1-4edf-a8e7-66905ca81688','與子仁登天柱岡過胡家塘蓴塘歸東園四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','數間茅屋傍山根，一隊兒童出竹門。',32,'全唐诗/poet.song.142000.json','["數間茅屋傍山根，一隊兒童出竹門。", "只愛行穿楊柳渡，不知失却李花村。"]'),
('52433bdf-1182-495a-a527-02d96fc27287','與子仁登天柱岡過胡家塘蓴塘歸東園四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','厭看家園桃李春，踏青行徧四山村。',32,'全唐诗/poet.song.142000.json','["厭看家園桃李春，踏青行徧四山村。", "芳菲看盡還歸看，看得園花特地新。"]'),
('46598db0-07d9-4409-a447-fe4d5137198e','登度雪臺','楊萬里','宋','宋诗','song-poetry','','[]','金沙歲歲占先回，不等荼糜一併來。',32,'全唐诗/poet.song.142000.json','["金沙歲歲占先回，不等荼糜一併來。", "今歲香紅與香雪，兩花同日忽齊開。"]'),
('030f99e1-1dc5-4188-86ff-bce4e4d1b4a1','山莊李花','楊萬里','宋','宋诗','song-poetry','','[]','山莊又報李花穠，火急來看細雨中。',32,'全唐诗/poet.song.142000.json','["山莊又報李花穠，火急來看細雨中。", "除却斷腸千樹雪，別無春恨訴東風。"]'),
('dd08f548-37fc-4895-a23d-d535ebc19950','送韓漕華文移節江東','楊萬里','宋','宋诗','song-poetry','','[]','公家文公天斗星，可雙孟氏再六經。',160,'全唐诗/poet.song.142000.json','["公家文公天斗星，可雙孟氏再六經。", "姓名不上凌煙去，只與日月爭光明。", "君家魏國天一柱，拄天無傾日無霧。", "唯天唯堯唯永昭，臯旦以還俱避路。", "只今百年三百年，文獻衣被芝與蘭。", "華文使者典刑存，一生流坎晚乃騫。", "臺家拔士兼人門，如君兩有今誰先。", "德星纔照翼軫地，寒士驩呼細民喜。", "鍾山石城何物神，奪與東民天不嗔。", "寄語東民也未穩，渠是鸞臺鳳閣人。"]'),
('df7efc85-2963-498d-8e3e-c29d7b691eb9','太寧郡夫人張氏挽詞二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','蓋世金甌譜，傳家象笏囊。',48,'全唐诗/poet.song.142000.json','["蓋世金甌譜，傳家象笏囊。", "藁砧八葉相，桂子一枝香。", "葱嶺參西學，蘭陔揜北堂。", "能詩飽經史，箇是女班揚。"]'),
('7fc526b5-6c22-48f4-acc8-af6e27943732','太寧郡夫人張氏挽詞二首  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我憶定齋老，壺觴父子間。',48,'全唐诗/poet.song.142000.json','["我憶定齋老，壺觴父子間。", "西湖梅半落，東館月初彎。", "俄頃王姑酒，嶔岑杜母山。", "升堂遲一拜，作誄費頻刪。"]'),
('ea2ee6c1-0981-4f7f-889d-37ae6aae2825','送周起宗經幹赴桂林帥幕','楊萬里','宋','宋诗','song-poetry','','[]','乃翁昔夢飛入月，東字分明篆銀闕。',128,'全唐诗/poet.song.142000.json','["乃翁昔夢飛入月，東字分明篆銀闕。", "明朝占夢占者云，一甲八人更何說。", "紹興大對奏集英，天風吹下臚傳聲。", "作者七人拜恩了，乃翁甲科第八名。", "十年一武可鳳沼，邵陽別駕今宿草。", "子今端能讀父書，伏犀美髯一似渠。", "當時父執今左相，鴻鈞播作幕府梧。", "問天一雪乃翁屈，早入鵷行綴簪笏。"]'),
('25004c79-84c1-4795-aaf3-41185fe9863b','故太恭人董氏挽詞五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','誰別夫人孝，惟天與病姑。',48,'全唐诗/poet.song.142000.json','["誰別夫人孝，惟天與病姑。", "每云吾婦在，底用別人扶。", "愉色春相似，彌年倦更無。", "蒼蒼不汝報，種黍定生菰。"]'),
('6ddacd4e-9208-4cb1-a1ec-351997ccdba1','故太恭人董氏挽詞五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','貧是儒家事，誰貧奉直如。',48,'全唐诗/poet.song.142000.json','["貧是儒家事，誰貧奉直如。", "也無一瓢飲，劣有半床書。", "婦婦能攻苦，卿卿不負渠。", "竟令鴻與侃，相繼大吾閭。"]'),
('6e706354-e129-4fd3-ab42-ac6e9b57042e','故太恭人董氏挽詞五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','親見卿爲月，頻移使者星。',48,'全唐诗/poet.song.142000.json','["親見卿爲月，頻移使者星。", "藻虛南澗碧，萱落北堂青。", "遺下新褕狄，空傳訓寧馨。", "又孫還又子，玉樹滿階庭。"]'),
('3247c577-248b-4f9d-98ff-5d081fe4813d','故太恭人董氏挽詞五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','九秩開鴻算，前春祝壽觴。',48,'全唐诗/poet.song.142000.json','["九秩開鴻算，前春祝壽觴。", "秦淮作椒柏，鍾阜當星香。", "花壓藤輿重，游回繡幰涼。", "諸臺誰有母，羨殺綵衣郎。"]'),
('5edc1f9a-9a9a-4b55-8167-58b785e1870b','故太恭人董氏挽詞五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','溧縣初栖鳳，金陵復木牛。',48,'全唐诗/poet.song.142000.json','["溧縣初栖鳳，金陵復木牛。", "重來喜城郭，一夕閟山丘。", "終始非無數，東西豈自由。", "銘旌二千里，處處哭歸舟。"]'),
('c8580a83-458a-438c-b9ef-805ce12aa849','十一月十九日折梅二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','初愛寒香一朶斜，又逢奇朶出高丫。',32,'全唐诗/poet.song.142000.json','["初愛寒香一朶斜，又逢奇朶出高丫。", "折來折去花多了，忘却前花與後花。"]'),
('7c6ce5a6-712b-4642-9099-319ed534fc01','十一月十九日折梅二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','也知春向歲前回，不道春前早有梅。',32,'全唐诗/poet.song.142000.json','["也知春向歲前回，不道春前早有梅。", "折得數枝撚歸去，蜂兒一路趁人來。"]'),
('c545cb2d-5b65-4179-9aed-8b12532be587','謝張功父送近詩集','楊萬里','宋','宋诗','song-poetry','','[]','十年不夢軟紅塵，惱亂閑心得我嗔。',64,'全唐诗/poet.song.142000.json','["十年不夢軟紅塵，惱亂閑心得我嗔。", "兩夜連繙約齋集，雙明再見帝城春。", "鶑花世界輸公等，泉石膏肓歎病身。", "近代風騷四詩將，非君摩壘更何人。"]'),
('1bf556d4-c334-42bb-82fd-ce2ebc7ee920','贛守張子智舍人寄詩送酒和韻謝之','楊萬里','宋','宋诗','song-poetry','','[]','誰言天上張公子，飛下崆峒看曉晴。',64,'全唐诗/poet.song.142000.json','["誰言天上張公子，飛下崆峒看曉晴。", "爲愛東坡題八境，却同嚴助厭承明。", "詩來風雨荒涼後，語带江山紫翠橫。", "更遣麯生相暖熱，十年同社再尋盟。"]'),
('f6182152-f349-4dc3-8494-2c2147888601','送趙判官端國趁班改秩','楊萬里','宋','宋诗','song-poetry','','[]','金陵一見恍如夢，君爲過客儂相送。',144,'全唐诗/poet.song.142000.json','["金陵一見恍如夢，君爲過客儂相送。", "廬陵再見春欲殘，君來入幕儂挂冠。", "是時猛虎初出境，赤子凜如兵在頸。", "帝選良牧蘇疲民，前趙後丁廉且仁。", "更得君作幕下賓，四年千里日日春。", "與君相逢又相別，人生聚散如霜葉。", "桂林一枝三十年，諸公交章薦遺賢。", "去揖侍郎趁立班，端能別我南溪邊。", "爲我一醉春風前，看君摶風上九天。"]'),
('b0ff096f-bc46-4433-ac85-97166953db53','送周彥敷通判之官臨川','楊萬里','宋','宋诗','song-poetry','','[]','益國今姬旦，治中小呂申。',48,'全唐诗/poet.song.142000.json','["益國今姬旦，治中小呂申。", "留家視蘭膳，疋馬見州民。", "慈訓二六句，寒窗三十春。", "校書天祿閣，才子即雲津。"]'),
('0c67b7d9-0e29-40cc-8224-337f0f45b51e','送曾文卿入京','楊萬里','宋','宋诗','song-poetry','','[]','如君大似陸雲龍，一歕詞場萬馬空。',64,'全唐诗/poet.song.142000.json','["如君大似陸雲龍，一歕詞場萬馬空。", "文透退之關捩子，騷傳正則祖家風。", "三年拄笏南雲裏，兩手投竿西日中。", "璧水蓬山剩虛席，儤筵趁取牡丹紅。"]'),
('43ce1618-027a-4855-932a-918092c12a38','送趙英仲司戶','楊萬里','宋','宋诗','song-poetry','','[]','紹興人物趙戶部，身作長城護瓜步。',96,'全唐诗/poet.song.142000.json','["紹興人物趙戶部，身作長城護瓜步。", "佛狸送死緣有人，猨臂不侯得非數。", "只今曾孫戶掾公，吏能官政有祖風。", "南山可摇判難奪，東海不冤陰有功。", "吾州上了本曹印，謁帝明光當得覲。", "秋風正緊送摶扶，九萬程塗人莫問。"]'),
('c6be5a2f-6829-4e3a-8791-1f324c2357b7','送聶士友通判上印入朝','楊萬里','宋','宋诗','song-poetry','','[]','君家樞相扶天極，氣凌霜雪忠貫日。',128,'全唐诗/poet.song.142000.json','["君家樞相扶天極，氣凌霜雪忠貫日。", "史家有筆歎無人，今有此人無此筆。", "君侯名家千里駒，拱璧盈尺徑寸珠。", "合登清廟薦六瑚，合參豹尾隨屬車。", "胡爲小緩雲間翮，朅來螺浦分風月。", "開軒不與俗客談，明月清風入牙頰。", "只今上印去朝天，春風玉笋催綴班。", "相門有相君勉旃，凌煙再寫進賢冠。"]'),
('d30c91fa-19e3-4489-87c2-4d21ee0a50ab','送次公子之官安仁監稅','楊萬里','宋','宋诗','song-poetry','','[]','汝仕今差晚，家庭莫恨離。',48,'全唐诗/poet.song.142000.json','["汝仕今差晚，家庭莫恨離。", "學須官事了，廉忌世人知。", "爭進非身福，臨民只母慈。", "關征豈得已，龍斷欲何爲。"]'),
('161a539f-f6d9-4482-a915-29e8be2d53aa','寄題南城吳子直子常上舍兄弟社倉','楊萬里','宋','宋诗','song-poetry','','[]','有虞有宋雙重華，兩聖一心民一家。',144,'全唐诗/poet.song.142000.json','["有虞有宋雙重華，兩聖一心民一家。", "綠針刺水農事起，重華愁早從此始。", "黄雲登場萬寶秋，重華對天失却愁。", "二十八年臨玉座，太半光陰愁裏過。", "天顔憂喜丞相知，常平使者陳便宜。", "倡爲社倉首建溪，旴江吳札承君師。", "伯霜仲雪發爾私，支奇虐魃手莫施。", "活幾侲子幾凍黎，詔子文孫孫又子。", "箇是重華聖人意，無論十世百千世。"]'),
('da48bf7e-2b95-44a9-b81a-e898c9599162','題劉翔卿蔚然樓二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','誠叟顛狂與醉題，艮翁珍重灑瓌詞。',32,'全唐诗/poet.song.142000.json','["誠叟顛狂與醉題，艮翁珍重灑瓌詞。", "山稜莫學詩肩瘦，月寫雲描總是詩。"]'),
('91c23244-5000-455c-9cd9-3948bb5b96e0','題劉翔卿蔚然樓二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','樓上青編入骨香，樓前碧岫透簾光。',32,'全唐诗/poet.song.142000.json','["樓上青編入骨香，樓前碧岫透簾光。", "乘風飛上廣寒殿，下看秋容一點蒼。"]'),
('1d92ab3a-0a9f-4935-88ad-cce6fae1ee8b','贈高德順','楊萬里','宋','宋诗','song-poetry','','[]','兒時同客水中蟹，鴨脚林間索詩債。',64,'全唐诗/poet.song.142000.json','["兒時同客水中蟹，鴨脚林間索詩債。", "只今白髮共青燈，一尊濁酒話平生。", "我才不及君才美，毛穎負君真差事。", "見說君家千里駒，看渠高大君門閭。"]'),
('c82ff7ea-9116-4f00-a7af-37b364b122c1','送安成羅茂忠','楊萬里','宋','宋诗','song-poetry','','[]','書臺佳士君章孫，句法來自西溪門。',112,'全唐诗/poet.song.142000.json','["書臺佳士君章孫，句法來自西溪門。", "向來家住金谷園，珊瑚四尺蠟作薪。", "床頭黄金已散盡，買書却鑄文章印。", "印成一字不療饑，仰天大笑還哦詩。", "諸老先生總參徧，只欠一瞻晦翁面。", "晦翁今已作貴人，君從何許去問津。", "勸君努力戰今舉，來年拜渠爲座主。"]'),
('1b51476d-44b7-419e-a678-1dbf740b9762','曾伯貢主簿挽詩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','練練蘭溪秀，家家玉樹榮。',48,'全唐诗/poet.song.142000.json','["練練蘭溪秀，家家玉樹榮。", "興安有才子，艮老是先生。", "師與三冬學，詩專五字城。", "一官纔祭灶，作麽便銘旌。"]'),
('8fe1a5f6-5dac-4250-af5c-82dceb93b88e','曾伯貢主簿挽詩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','我壯君初冠，相逢便定交。',48,'全唐诗/poet.song.142000.json','["我壯君初冠，相逢便定交。", "即今俱白首，赴告忽黄茅。", "人物王兼謝，詩聲島與郊。", "病來無氣力，不得奠蘭肴。"]'),
('d18fcf2e-af90-4040-afb9-3c2093a3cb35','黄司法妻歐陽氏孺人挽詩','楊萬里','宋','宋诗','song-poetry','','[]','法掾無雙裔，夫人六一孫。',48,'全唐诗/poet.song.142000.json','["法掾無雙裔，夫人六一孫。", "夙勤南澗藻，晚享北堂萱。", "蒲圃嚴新檟，潘輿閟舊軒。", "庭階森玉樹，駟馬看高門。"]'),
('fbeb71e6-ef8a-4ec7-a7c3-4858a358164a','題曾景山通判壽衍堂','楊萬里','宋','宋诗','song-poetry','','[]','人家具慶已燕喜，人家重慶更奇偉。',88,'全唐诗/poet.song.142000.json','["人家具慶已燕喜，人家重慶更奇偉。", "宜春臺上賢治中，妙齡斫桂廣寒宮。", "親年九十身六二，芝蘭玉樹森庭砌。", "上堂綵衣稱壽觴，下堂繡口喧雪窗。", "紫樞相公喜嘉祥，大書壽衍名其堂，五世其昌未渠央。"]'),
('67c4d973-228d-4de5-b163-15f8f85b1fcb','送劉茂材主簿之官理定','楊萬里','宋','宋诗','song-poetry','','[]','陸機二十作文賦，劉群二十詣太常。',100,'全唐诗/poet.song.142000.json','["陸機二十作文賦，劉群二十詣太常。", "桃花浪險阿香怒，點破龍額歸西江。", "平津六十策第一，劉君五十賜袍笏。", "一官初入八桂林，官無早晚在努力。", "大帥大漕兩德星，總是青原舊使君。", "若問公堂階下吏，便是三瑞堂前門生前進士。"]'),
('6d22563a-a6ee-4e83-bebf-b9831e61e4f8','蕭照鄰參政大資挽詩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','父子雙晁董，中興只一家。',48,'全唐诗/poet.song.142000.json','["父子雙晁董，中興只一家。", "裏剛金百鍊，表粹玉無瑕。", "死力扶忠善，生平嫉佞邪。", "古人少全傳，公傳即非夸。"]'),
('6a4c43af-a4db-43b2-836c-c7671d69ca3a','蕭照鄰參政大資挽詩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','東府辭金印，南園伴赤松。',48,'全唐诗/poet.song.142000.json','["東府辭金印，南園伴赤松。", "門闌無薏苡，泉石自從容。", "忽作丁威鶴，云亡老子龍。", "一哀緣殄瘁，不是涕無從。"]'),
('b9f180ef-080b-4212-bd85-de10aea70345','贈旴江謝正之','楊萬里','宋','宋诗','song-poetry','','[]','旴江天上銀河冰，麻姑人間白玉京。',112,'全唐诗/poet.song.142000.json','["旴江天上銀河冰，麻姑人間白玉京。", "不生金珠不生玉，只生命代千人英。", "前有泰伯後子固，後無來者前無古。", "九州四海何同年，濃墨大字薦惠連。", "君家春草池塘句，只今又見君著語。", "袖中繡出詩一編，清新不減春草篇。", "願君努力古人事，再光麻姑與旴水。"]'),
('cbb6e409-2a63-4935-984a-0a70c0826128','太守趙山父命劉秀才寫予老醜索贊','楊萬里','宋','宋诗','song-poetry','','[]','香山有箇狂客，恣游三十六峰。',28,'全唐诗/poet.song.142000.json','["香山有箇狂客，恣游三十六峰。", "不是河南賢尹，誰贈明月清風。"]'),
('c2de3fce-9947-4f21-bb9c-1fceb281256e','寄題舒州宿松知縣戴在伯重新紫霄亭二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','一代名臣張右丞，玉山頭作紫霄亭。',32,'全唐诗/poet.song.142000.json','["一代名臣張右丞，玉山頭作紫霄亭。", "如今再得戴安道，拈出舊時山色青。"]'),
('1206fa0a-94b9-46e0-8c51-c31ffff861d6','寄題舒州宿松知縣戴在伯重新紫霄亭二首  其二','楊萬里','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u957f\u6c5f"]','萬里長江一線橫，好風時送晚潮聲。',32,'全唐诗/poet.song.142000.json','["萬里長江一線橫，好風時送晚潮聲。", "江州司馬叫不醒，叫得廬山分一觥。"]'),
('26e7d3e4-c588-412b-8306-42b4edc872da','寄題荆南撫幹胡仲方公廨信美樓  其一','楊萬里','宋','宋诗','song-poetry','','[]','大資孫子大參甥，磊磈胸中萬卷橫。',32,'全唐诗/poet.song.142000.json','["大資孫子大參甥，磊磈胸中萬卷橫。", "樓上已堆千古恨，晚潮更作斷腸聲。"]'),
('add8d387-ecf7-40d7-87ef-05ab1a9399c7','寄題荆南撫幹胡仲方公廨信美樓  其二','楊萬里','宋','宋诗','song-poetry','','[]','古有仲宣今仲方，二樓分貯一秋江。',32,'全唐诗/poet.song.142000.json','["古有仲宣今仲方，二樓分貯一秋江。", "散愁幸有杯中月，莫下南窗下北窗。"]'),
('b3938bc3-a1b6-4b17-8b13-a7092442665b','題劉子遠春風堂','楊萬里','宋','宋诗','song-poetry','','[]','艮齋先生門下士，寒星向曉今餘幾。',64,'全唐诗/poet.song.142000.json','["艮齋先生門下士，寒星向曉今餘幾。", "春風堂上劉更生，十年桂山問奇字。", "艮齋正派誰真傳，更生得髓仍得肝。", "春風卷著兩袖裏，放出摶扶天地間。"]'),
('10c290e9-5769-46af-b340-a91d9655d4e4','題劉子遠宴坐畫圖樓','楊萬里','宋','宋诗','song-poetry','','[]','大年小景真兒戲，郭熙遠山閑故紙。',64,'全唐诗/poet.song.142000.json','["大年小景真兒戲，郭熙遠山閑故紙。", "東山一塔作毛錐，試點盧溪一溪水。", "灑出樓前千萬峰，一一奔騰入樓裏。", "金華仙翁强解事，攘我樓中新句子。"]'),
('c49ac274-1ecf-44fa-9e24-174c12399b94','題太和宰卓士直寄新刻山谷快閣詩真蹟二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','快閣江鷗遠避人，西昌山月暗吹塵。',32,'全唐诗/poet.song.142000.json','["快閣江鷗遠避人，西昌山月暗吹塵。", "百年卓茂傳詩印，印出風光色色新。"]'),
('14c87068-4fbf-4d68-8ce4-57d6f31a6159','題太和宰卓士直寄新刻山谷快閣詩真蹟二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','太史留題快閣詩，舊碑未必是真題。',32,'全唐诗/poet.song.142000.json','["太史留題快閣詩，舊碑未必是真題。", "六丁搜出嚴家墨，白日青天橫紫蜺。"]'),
('ee444784-80cf-4133-bcca-786199196d16','同次公觀細陂小坐行店','楊萬里','宋','宋诗','song-poetry','','[]','店歇疑爲旅，溪行當出郊。',24,'全唐诗/poet.song.142000.json','["店歇疑爲旅，溪行當出郊。", "莓苔依斷蓼，翡翠上寒梢。"]'),
('1e1c2bdd-7629-47ab-86b7-6960aee789c1','南溪細陂','楊萬里','宋','宋诗','song-poetry','','[]','仙家有藥世無比，能乾水銀作銀子。',80,'全唐诗/poet.song.142000.json','["仙家有藥世無比，能乾水銀作銀子。", "老夫却把水晶環，鎔作南溪一溪水。", "閑隨穉子作兒嬉，金沙玉礫磊細陂。", "水從陂上瀉澗底，椎碎水晶聲滿耳。", "忽然流下片蒼苔，一朶碧雲影千里。"]'),
('63fbefc4-e13d-4f87-849b-a106649f74cb','訪蓬萊老人','楊萬里','宋','宋诗','song-poetry','','[]','不到蓬萊又幾時，涼花漸盛暑花稀。',32,'全唐诗/poet.song.142000.json','["不到蓬萊又幾時，涼花漸盛暑花稀。", "我來不是忘歸去，忘却來時況道歸。"]'),
('13c3da23-03c1-4cc8-80f2-a421c04879c5','觀棋感興','楊萬里','宋','宋诗','song-poetry','','[]','本是輸棋强作贏，看來終與好棋爭。',32,'全唐诗/poet.song.142000.json','["本是輸棋强作贏，看來終與好棋爭。", "君看國手無雙底，何用旁人捄敗兵。"]'),
('1fb9cfb2-cacf-44fd-8f3f-a54268586518','寄謝蜀帥袁起巖尚書閣學寄贈藥物二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','卧雪先生冰雪胸，小迂星履領元戎。',64,'全唐诗/poet.song.142000.json','["卧雪先生冰雪胸，小迂星履領元戎。", "草堂衣鉢風騷將，花屋笙簫造化工。", "杜宇催歸波正綠，海棠不睡燭斜紅。", "遨頭未了詞頭下，四世重新六五公。"]'),
('a21d9652-a29a-4328-bb13-5c582625a595','寄謝蜀帥袁起巖尚書閣學寄贈藥物二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','拋官歸隠七經年，睡殺山雲笑殺天。',64,'全唐诗/poet.song.142000.json','["拋官歸隠七經年，睡殺山雲笑殺天。", "剩雨殘風黄帽底，顛詩中酒白鷗前。", "少年行路今已矣，厚祿故人書寂然。", "只有錦城袁閣學，寄詩贈藥意悁悁。"]'),
('7baac361-ebd4-4947-8953-fccf4d11a7ee','謝淮東漕虞壽老寶文察院寄詩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','詩吸三江捲五湖，彫瓊爲句字爲珠。',64,'全唐诗/poet.song.142000.json','["詩吸三江捲五湖，彫瓊爲句字爲珠。", "前身謝守吟澄練，今代世南行祕書。", "獬豸峨冠久塵醭，星辰聽履即須臾。", "夜來飛入東園去，夢裏分明覺後虛。"]'),
('2836e8ef-a157-499f-8bf0-b2538cbeb6fa','謝淮東漕虞壽老寶文察院寄詩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','鵷行接翼復分襟，酒病詩愁老不禁。',64,'全唐诗/poet.song.142000.json','["鵷行接翼復分襟，酒病詩愁老不禁。", "十載江湖千里月，一生金石兩知心。", "悼亡君有安仁戚，歸隠儂爲梁父吟。", "早晚故人天上去，未應廊廟忘山林。"]'),
('8f05bbe7-3502-4c06-9a2c-6dc6d1ec98e2','寄題安福劉道協涌翠樓','楊萬里','宋','宋诗','song-poetry','','[]','讀書臺南山繞屋，恰如萬簪削青玉。',120,'全唐诗/poet.song.142000.json','["讀書臺南山繞屋，恰如萬簪削青玉。", "讀書臺北山更多，又似碧海躍萬波。", "臺邊高人子劉子，架樓南北山圍裏。", "醉中領客上上頭，忽驚平地翠浪浮。", "一浪拋雲入天半，衆浪翻空濕銀漢。", "砰轟打到欄干前，天跳地踔乾坤顛。", "主賓拍手呼釣船，定眼看來還不然，只是南北幾點山。"]'),
('c24b23a4-f014-423f-b18d-afd2bc042ace','送胡聖聞入太學','楊萬里','宋','宋诗','song-poetry','','[]','春風吹開孝廉船，撞星犯斗上九天。',64,'全唐诗/poet.song.142000.json','["春風吹開孝廉船，撞星犯斗上九天。", "夜書細字燈前月，朝茹寒虀甕中雪。", "何蕃省親間一歸，陸暢擢第各一時。", "此行歸來上親壽，桂枝滿把香滿袖。"]'),
('9778569f-eb93-4d7f-be6f-7ed90ebb96af','程泰之尚書龍學挽詞二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','廟器圭璋骨，儒林虎豹章。',48,'全唐诗/poet.song.142000.json','["廟器圭璋骨，儒林虎豹章。", "韋編雙輔嗣，禹跡再平當。", "月冷談經幄，塵昏弄筆床。", "西州何處路，谿水咽梅鄉。"]'),
('ccb0306d-c370-4cd5-8d25-d3eee1e981c6','程泰之尚書龍學挽詞二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','公弭江西節，儂橫南浦舟。',48,'全唐诗/poet.song.142000.json','["公弭江西節，儂橫南浦舟。", "相逢便金石，一別幾春秋。", "問訊頻黄耳，歸休各白頭。", "豐碑那忍讀，未讀涕先流。"]'),
('2081864b-921c-468a-9c91-c92bf768af3c','讀白氏長慶集','楊萬里','宋','宋诗','song-poetry','','[]','每讀樂天詩，一讀一回好。',96,'全唐诗/poet.song.142000.json','["每讀樂天詩，一讀一回好。", "少時不知愛，知愛今已老。", "初哦殊驩欣，熟味忽煩惱。", "多方遣外累，半已動中抱。", "事去何必追，心浄不須掃。", "追歎欲掃愁，自遣還自擾。", "不如卷此詩，喚酒一醉倒。", "狂歌謫仙詞，三杯通大道。"]'),
('920ee5b1-0df8-4fd9-880a-259fd789dde3','送幼輿子之官澧浦慈利監稅二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','估人耕貨不耕田，也合供輸餉萬屯。',32,'全唐诗/poet.song.142000.json','["估人耕貨不耕田，也合供輸餉萬屯。", "若道厚征爲報國，厚民却是負君恩。"]'),
('dd2d02a5-d959-4c5c-937d-a74edcaa208c','送幼輿子之官澧浦慈利監稅二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','素王開國道無臣，一榜春風放十人。',32,'全唐诗/poet.song.142000.json','["素王開國道無臣，一榜春風放十人。", "莫羨榜頭年十八，舊春過了有新春。"]'),
('9775be03-baad-446d-8b37-ad0e9c8c9337','題贛州重建思賢閣','楊萬里','宋','宋诗','song-poetry','','[]','趙公遺愛虎頭城，直到張公續此聲。',32,'全唐诗/poet.song.142000.json','["趙公遺愛虎頭城，直到張公續此聲。", "前趙後張俱可閣，贛民不用羨西京。"]'),
('aaf25960-248e-4263-976c-54e105d17bda','題章貢道院','楊萬里','宋','宋诗','song-poetry','','[]','江西道院賦金華，近日當塗共兩家。',32,'全唐诗/poet.song.142000.json','["江西道院賦金華，近日當塗共兩家。", "更著崆峒三道院，只銷卧治醉鶑花。"]'),
('958041a1-3a82-41a9-8f77-b91ef6481eb7','與子上野步','楊萬里','宋','宋诗','song-poetry','','[]','籬落深深巷，茅茨小小家。',24,'全唐诗/poet.song.142000.json','["籬落深深巷，茅茨小小家。", "冬晴好行脚，何處不梅花。"]'),
('6b6c590e-613b-419d-afcb-523b34011414','送贛守張子智左史進直敷文閣移帥八桂二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','龍尾名臣進寶奎，虎頭移鎮赴榕溪。',64,'全唐诗/poet.song.142000.json','["龍尾名臣進寶奎，虎頭移鎮赴榕溪。", "握刀將帥迎牙纛，解辮戎蠻貢象犀。", "翠浪玉虹餘昨夢，碧篸羅带入新題。", "鳳池雞樹公栖處，早箇雲飛不要梯。"]'),
('301b8740-180e-4806-87ae-149a0a8053ce','送贛守張子智左史進直敷文閣移帥八桂二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','拋官九載卧柴荆，有底生涯底友生。',64,'全唐诗/poet.song.142000.json','["拋官九載卧柴荆，有底生涯底友生。", "白鷺鸕鷀雙屬玉，青鞋布韈一笭箵。", "贛江府主憐逋客，尊酒綈袍篤故情。", "天上故人今又去，碧雲西望暮天橫。"]'),
('2fedc716-d881-4ee9-9ee7-b808d729087e','至後與履常探梅東園三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雨後霜前梅欲開，欲開猶懶雪風催。',32,'全唐诗/poet.song.142000.json','["雨後霜前梅欲開，欲開猶懶雪風催。", "一秋不到東園裏，從此朝朝暮暮來。"]'),
('e91b15ee-5dfc-4d11-aa4d-a5a472909635','至後與履常探梅東園三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','兩朶三枝梅正新，不疎不密最忺人。',32,'全唐诗/poet.song.142000.json','["兩朶三枝梅正新，不疎不密最忺人。", "花枝夾徑嗔人過，絓脫老夫頭上巾。"]'),
('115eecad-355e-461f-aa77-19bd157da486','至後與履常探梅東園三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','雨澀風酸悶却春，日光初暖倍精神。',32,'全唐诗/poet.song.142000.json','["雨澀風酸悶却春，日光初暖倍精神。", "天如一面青羅扇，仰看橫枝自寫真。"]'),
('8bf9d840-91dd-459d-b4d6-5bf75f13f48c','題永豐劉伯英雙清亭','楊萬里','宋','宋诗','song-poetry','','[]','銀河一派天上來，霜松萬本水際栽。',72,'全唐诗/poet.song.142000.json','["銀河一派天上來，霜松萬本水際栽。", "公幹作亭占佳處，攔住清風入窗戶。", "醉餘綠綺膝上橫，學得松聲與水聲。", "更待九秋月亭午，白玉壺中有新句，煩君赤手雙拾取。"]'),
('e8c8c944-3c26-4965-84ad-e7e502785cdf','寄題彭澤王尉名自適廨舍二境 讀書巖','楊萬里','宋','宋诗','song-poetry','','[]','不遇黄山谷，那傳石橘林。',48,'全唐诗/poet.song.142000.json','["不遇黄山谷，那傳石橘林。", "巖欺小孤頂，影落大江心。", "試聽秋蟲語，如聞夜誦音。", "梅仙癖嗜古，此外更幽尋。"]'),
('4d12e1da-5407-484e-b01c-e164381d278e','寄題彭澤王尉名自適廨舍二境 潜玉洞','楊萬里','宋','宋诗','song-poetry','','[]','人道書巖好，誰知石洞奇。',48,'全唐诗/poet.song.142000.json','["人道書巖好，誰知石洞奇。", "外纔一徑盡，中忽萬峰欹。", "竅石天成屋，泓泉鬼斸池。", "弘中遠孫子，宴喜又添詩。"]'),
('784ee537-9d70-49f9-bcc8-74112d7ed6f1','題湖北唐憲桂林義學','楊萬里','宋','宋诗','song-poetry','','[]','梅花五嶺八桂林，青羅带繞碧玉簪。',99,'全唐诗/poet.song.142000.json','["梅花五嶺八桂林，青羅带繞碧玉簪。", "祥刑使者兩唐裔，親領諸生到洙泗。", "七星巖畔築齋房，獨秀峰尖作筆床。", "買書堆上天中央，海表學子來奔忙。", "中州淑氣無間斷，南斗文星方炳煥。", "君不見日南姜相曲江張，萬古清風裂雲漢。"]'),
('e1129b34-20b8-4256-b9b2-34ec99516587','除夜小飲歎都下酥乳不至','楊萬里','宋','宋诗','song-poetry','','[]','雪韭霜菘酌歲除，也無牛乳也無酥。',32,'全唐诗/poet.song.142000.json','["雪韭霜菘酌歲除，也無牛乳也無酥。", "貧中却富何人會，自有村醪不用沽。"]'),
('29d218c5-08d2-4b57-9b67-145ac466013c','辛酉正月十一日東園桃李盛開','楊萬里','宋','宋诗','song-poetry','','[]','千萬重山見復遮，兩三點雨直還斜。',32,'全唐诗/poet.song.142000.json','["千萬重山見復遮，兩三點雨直還斜。", "行穿錦巷入雪巷，看盡桃花到李花。"]'),
('c6ec7dc9-efde-4e35-98c3-a18a81aa4726','溪邊回望東園桃李','楊萬里','宋','宋诗','song-poetry','','[]','看花不合在花間，外面看來錦一般。',32,'全唐诗/poet.song.142000.json','["看花不合在花間，外面看來錦一般。", "每一團花三丈許，紅花團繞白花團。"]'),
('5158c486-4280-4d8e-a320-db539203ade7','上元後一日往山莊訪子仁中塗望見莊裏李花二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','莊裏李花何似生，山頭轉處最分明。',32,'全唐诗/poet.song.142000.json','["莊裏李花何似生，山頭轉處最分明。", "轎中舉首聊東望，不見花枝見雪城。"]'),
('a10f7ec0-911e-44c5-8267-81acb8e9757f','上元後一日往山莊訪子仁中塗望見莊裏李花二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','李花十里縱長圍，漏出桃花片子兒。',32,'全唐诗/poet.song.142000.json','["李花十里縱長圍，漏出桃花片子兒。", "千丈越羅初水凍，中間一點涴燕脂。"]'),
('a0f6ac8a-72f1-4f5d-b936-53a43d3c9d5c','新栽德安牡丹透根生孫枝皆千葉種也即非接頭二月二日瑞雲紅初開清曉起看喜而賦之','楊萬里','宋','宋诗','song-poetry','','[]','日上渾遲在，花乘絕早看。',48,'全唐诗/poet.song.142000.json','["日上渾遲在，花乘絕早看。", "精神百倍好，風露七分寒。", "夜宴醒猶醉，晨粧濕未乾。", "子孫更千億，紫笋繞團欒。"]'),
('928829e6-34e5-48a0-87ab-17b705d42837','送俞漕子清大卿赴召二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','帝求耆舊憶吾公，紫詔斜行下碧穹。',64,'全唐诗/poet.song.142000.json','["帝求耆舊憶吾公，紫詔斜行下碧穹。", "勵操蘭薰仍雪瑩，作民冬日與春風。", "便登鳳閣鸞臺上，小試雞翹豹尾中。", "十載江湖訪民瘼，一時傾倒沃天聰。"]'),
('eee69fb7-9b63-4844-9f2a-ea6c6e3f3ba5','送俞漕子清大卿赴召二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','自笑孤蹤霜葉輕，宦游何幸並耆英。',64,'全唐诗/poet.song.142000.json','["自笑孤蹤霜葉輕，宦游何幸並耆英。", "合符先後分江郡，接武差池綴月卿。", "愛我從來兩膠漆，與公別是一親情。", "老身無用難提挈，尚有兒曹累使令。"]'),
('032fa963-5959-4f66-9581-b1dd2ab11acf','謝江東耿漕曼老寄書并與沈侍郎唱和詩二首 謝詒書勞苦','楊萬里','宋','宋诗','song-poetry','','[]','朱雀橋邊舊使星，五年再照大江明。',32,'全唐诗/poet.song.142000.json','["朱雀橋邊舊使星，五年再照大江明。", "端能記憶誠齋叟，千里書來訪死生。"]'),
('5f213092-4e21-4b48-b9ba-653d82c6f170','謝江東耿漕曼老寄書并與沈侍郎唱和詩二首 謝唱和佳句','楊萬里','宋','宋诗','song-poetry','','[]','碧落侍郎金作句，瀛洲學士玉爲章。',32,'全唐诗/poet.song.142000.json','["碧落侍郎金作句，瀛洲學士玉爲章。", "兩公唱和君知麽，箇是安期却老方。"]'),
('c0c5c8ae-4238-4b31-b7c0-f3e505a47488','題王子宣主簿青山讀書堂','楊萬里','宋','宋诗','song-poetry','','[]','謝家青山李家據，王家青山當家住。',64,'全唐诗/poet.song.142000.json','["謝家青山李家據，王家青山當家住。", "上頭新作讀書堂，牙籤玉軸古錦囊。", "萬夫攘臂儂掉臂，萬事無味書有味。", "時挑野菜煮一字，兒輩不須來染指。"]'),
('38af6b0c-29c1-4ead-be07-e27c4a5dc73c','夏至雨霽與陳履常暮行溪上二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','西山已暗隔金鉦，猶照東山一抹明。',32,'全唐诗/poet.song.142000.json','["西山已暗隔金鉦，猶照東山一抹明。", "片子時間弄山色，乍黄乍紫忽全青。"]'),
('cd919c3b-cda6-4fdd-b3ac-88a6f2ce37e6','夏至雨霽與陳履常暮行溪上二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','夕涼恰恰好溪行，暮色催人底急生。',32,'全唐诗/poet.song.142000.json','["夕涼恰恰好溪行，暮色催人底急生。", "半路蛙聲迎步止，一熒松火隔籬明。"]'),
('fe3871af-c56b-4d13-b989-3a9a14040f5b','送子上弟赴郴州史君羅達甫寺正之招','楊萬里','宋','宋诗','song-poetry','','[]','郴山奇變水清寫，郴江幸繞郴山下。',80,'全唐诗/poet.song.142000.json','["郴山奇變水清寫，郴江幸繞郴山下。", "韓秦妙語久絕弦，誰煎鳳觜續此篇。", "君章詞客山水主，雲錦聘君君好赴。", "爲尋兩公舊游處，得句寄儂儂不妬。", "休道郴陽和雁無，也曾避雪羅浮去。"]'),
('811a652f-c134-4085-9ba7-a694191bed5b','走筆謝吉守趙判院分餉三山生荔子','楊萬里','宋','宋诗','song-poetry','','[]','吾州五馬住閩山，分我三山荔子丹。',64,'全唐诗/poet.song.142000.json','["吾州五馬住閩山，分我三山荔子丹。", "甘露落來雞子大，曉風凍作水晶團。", "西川紅錦無此色，南海綠羅猶带酸。", "不是今年天不暑，玉膚照得野人寒。"]'),
('a52763e7-bb7e-4cd3-8bcb-005f95bcb97c','夏夜翫月','楊萬里','宋','宋诗','song-poetry','','[]','仰頭月在天，照我影在地。',84,'全唐诗/poet.song.142000.json','["仰頭月在天，照我影在地。", "我行影亦行，我止影亦止。", "不知我與影，爲一定爲二。", "月能寫我影，自寫却何似。", "偶然步溪旁，月却在溪裏。", "上下兩輪月，若箇是真底。", "唯復水是天，唯復天是水。"]'),
('eb438218-a9e2-4645-add7-cacee121efbe','夏夜月下獨酌二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','誰道今年熱，今宵分外清。',48,'全唐诗/poet.song.142000.json','["誰道今年熱，今宵分外清。", "竹風秋九夏，溪月晝三更。", "此景天慳與，無人酒自傾。", "明朝火繖上，別作一經營。"]'),
('dad67f04-9cab-4094-a6ff-5960b14adac9','夏夜月下獨酌二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','月忿雲遮却，雲遭月輥翻。',48,'全唐诗/poet.song.142000.json','["月忿雲遮却，雲遭月輥翻。", "斬新燈世界，特地玉乾坤。", "兔舞催詩句，蟾醒笑醉魂。", "姮家且莫睡，照管失金盆。"]'),
('197deb60-3fb1-4ff0-93c1-100b81882731','謝蜀帥劉仲洪尚書龍學遣騎詒書之惠','楊萬里','宋','宋诗','song-poetry','','[]','紫衣軍將打門來，雲錦書從錦水回。',64,'全唐诗/poet.song.142000.json','["紫衣軍將打門來，雲錦書從錦水回。", "箇是國西天一柱，早歸斗下位三能。", "致身將相黑頭在，憐我漁樵青眼開。", "舊日雪山寒刮骨，祇今移取上春臺。"]'),
('5a9779b5-bb9b-4505-bac2-aed5aad9aeca','足痛無聊塊坐讀江西詩','楊萬里','宋','宋诗','song-poetry','','[]','兩脚徧雲水，群書久網絲。',48,'全唐诗/poet.song.142000.json','["兩脚徧雲水，群書久網絲。", "却因三日痛，理得數編詩。", "不借雙高挂，毋追一任欹。", "老來非愛病，不病亦何爲。"]'),
('b2235c45-ad94-4575-961c-1a4867f53f47','夏夜露坐二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','火老殊未熱，雨多還自晴。',48,'全唐诗/poet.song.142000.json','["火老殊未熱，雨多還自晴。", "暮天無定色，過鳥有歸聲。", "坐久人將睡，更深月始明。", "素娥欺我老，偏照雪千莖。"]'),
('641d6870-c6a5-48bf-8297-623c6a9b5c63','夏夜露坐二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','山翠都成黑，天黄忽復青。',48,'全唐诗/poet.song.142000.json','["山翠都成黑，天黄忽復青。", "月肥過半璧，雲瘦不遮星。", "瓦鼓三四隻，村酤一兩瓶。", "人皆笑我醉，我獨笑渠醒。"]'),
('833a482f-3494-4d77-a890-3db90f9d6b03','讀貞觀政要','楊萬里','宋','宋诗','song-poetry','','[]','拔士新豐逆旅中，懷賢鴨綠水波東。',32,'全唐诗/poet.song.142000.json','["拔士新豐逆旅中，懷賢鴨綠水波東。", "酒傾一斗鳶肩客，醋設三杯羊鼻公。"]'),
('4f7ca0ae-5140-4b45-86f4-6fb5fd10a28c','七月十一夜月下獨酌','楊萬里','宋','宋诗','song-poetry','','[]','今歲秋陽曬人死，今宵秋月呼人起。',104,'全唐诗/poet.song.142000.json','["今歲秋陽曬人死，今宵秋月呼人起。", "月光如水澡吾體，月色如霜凍吾髓。", "老夫畏熱如於菟，平生愛月如冰壺。", "望舒可客不可孤，麴生可親不可疎。", "更招玉兔金蟾蜍，同酌山杯煮澗蔬。", "來朝秋陽再作惡，今夕秋光且行樂。", "遮莫參橫并月落。"]'),
('5be6722b-0dfd-4782-ab49-0fbf7308e1bc','月下聞笛','楊萬里','宋','宋诗','song-poetry','','[]','天色鎔成水，蟾光鍊出銀。',48,'全唐诗/poet.song.142000.json','["天色鎔成水，蟾光鍊出銀。", "碧香三酌半，玉笛一聲新。", "小婉還清壯，多歡忽苦辛。", "何人傳此曲，此曲怨何人。"]'),
('aeb7e022-0e07-4c39-b03c-7405586fa442','中元日早起','楊萬里','宋','宋诗','song-poetry','','[]','欲借微涼問萬松，萬松自熱訴無風。',32,'全唐诗/poet.song.142000.json','["欲借微涼問萬松，萬松自熱訴無風。", "清晨秋暑已如許，那更斜陽與日中。"]'),
('9b79d240-5d92-4008-b04a-10dba9c904f1','露坐戲嘲星月','楊萬里','宋','宋诗','song-poetry','','[]','東生定西歸，月豈不識路。',72,'全唐诗/poet.song.142000.json','["東生定西歸，月豈不識路。", "何須倩長庚，夜夜引行步。", "星住月不行，星行月不住。", "無人問阿姊，此事竟誰主。", "不知聽金蟇，無乃由玉兔。", "來夜偷此星，看月歸何處。"]'),
('f9885855-1dcd-4dfa-bf67-a7320687dfa9','蓮子','楊萬里','宋','宋诗','song-poetry','','[]','蜂兒來自宛溪中，兩翅雖無已是蟲。',32,'全唐诗/poet.song.142000.json','["蜂兒來自宛溪中，兩翅雖無已是蟲。", "不似荷花窠底蜜，方成玉蛹未成蜂。"]'),
('8be411fd-2bdf-4d1f-8a60-d9bf03b8eaed','秋暑午睡起汲泉洗面','楊萬里','宋','宋诗','song-poetry','','[]','大桶雙擔新井花，松盆滿瀉莫留些。',32,'全唐诗/poet.song.142000.json','["大桶雙擔新井花，松盆滿瀉莫留些。", "刺頭蘸入松盆底，不是清涼第二家。"]'),
('3501616f-eded-4b45-9018-b51cc2bf3232','久旱禱雨不應晴天忽落數點','楊萬里','宋','宋诗','song-poetry','','[]','烈日秋來曬殺人，青天半點更無雲。',32,'全唐诗/poet.song.142000.json','["烈日秋來曬殺人，青天半點更無雲。", "忽傳天上真珠落，未到半空成水銀。"]'),
('601b329c-963a-4da8-8f7f-5f908a21fc0f','秋日早起','楊萬里','宋','宋诗','song-poetry','','[]','雞鳴鐘未鳴，不知鄉晨否。',48,'全唐诗/poet.song.142000.json','["雞鳴鐘未鳴，不知鄉晨否。", "起來恐驚衆，未敢啟戶牖。", "殘燈吐芒角，上下兩銀帚。", "定眼試諦觀，散作飛電走。"]'),
('82f07b76-ab08-4744-be1f-7a233188a2e8','晚飲','楊萬里','宋','宋诗','song-poetry','','[]','大醉或傷生，不醉又傷情。',48,'全唐诗/poet.song.142000.json','["大醉或傷生，不醉又傷情。", "此事兩難處，後先有重輕。", "醉後失天地，餘生底浮萍。", "愁城不須攻，醉鄉無此城。"]'),
('45eadb5c-3912-4567-8efb-c2022d19e7b2','送陳婿履常縣丞之官泰寧','楊萬里','宋','宋诗','song-poetry','','[]','玉潤非冠玉，東床忽易東。',48,'全唐诗/poet.song.142000.json','["玉潤非冠玉，東床忽易東。", "一官斯立樣，五字後山風。", "明月來宵共，清尊何日同。", "看君即飛兔，老我自冥鴻。"]'),
('eae76c53-2c65-40d1-96bd-6de2b89e98c5','送羅仲仁試藝南宮','楊萬里','宋','宋诗','song-poetry','','[]','紹興廉吏誰第一，君家郎罷真無匹。',99,'全唐诗/poet.song.142000.json','["紹興廉吏誰第一，君家郎罷真無匹。", "腰纏墨綬不請錢，妻啼兒號窮刮骨。", "清無人知有天知，四囝三箇攀桂枝。", "不應一箇獨見遺，今秋君與一鶚飛。", "君不見吾州狀元晚得意，董公五十有三歲。", "君今加渠更三年，春風射策君勉旃。"]'),
('bad7f077-23fa-4eae-abe1-028bd08c857d','古風送劉季游試藝南宮','楊萬里','宋','宋诗','song-poetry','','[]','西溪先生劉夫子，個是國士天下士。',128,'全唐诗/poet.song.142000.json','["西溪先生劉夫子，個是國士天下士。", "家庭孝友春裏風，義氣高寒秋後水。", "艮齋薦書叫九關，重華表閭上半天。", "人冤有德却無位，天報芝蘭滿階砌。", "諸孫箇箇九鳳雛，此郎軒軒千里駒。", "槐花再登鄉老書，桃花一跳化龍魚。", "堂上雙親黑頭在，日喚子孫倚門待。", "綠衣歸上千歲觴，還我西溪讀書債。"]'),
('da6dd376-2028-470d-ab7a-0693ac208d1a','送廬陵宰黄伯庸赴召','楊萬里','宋','宋诗','song-poetry','','[]','君寄梅花道別腸，我攀官柳送歸艎。',64,'全唐诗/poet.song.142000.json','["君寄梅花道別腸，我攀官柳送歸艎。", "東都循吏似名茂，南浦詩人更姓黄。", "白鷺青原留惠愛，蒼苔紅藥入篇章。", "故人若問誠齋叟，化作沙鷗弄夕陽。"]'),
('7fa3a016-5193-4d01-a36b-ab5c2e045776','同劉季游登天柱岡四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','兩隻胡床小憩些，一枝筇杖拄傾斜。',64,'全唐诗/poet.song.142000.json','["兩隻胡床小憩些，一枝筇杖拄傾斜。", "煙雲慘淡天將雪，風日荒寒梅未花。", "人去客來酤酒市，雞鳴犬吠野人家。", "清游不用忙歸去，强管行程是暮鴉。"]'),
('c3861c12-4409-4366-a5a8-86b135c0df79','同劉季游登天柱岡四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','我行誰與報江楓，旋擺旌旗一路紅。',64,'全唐诗/poet.song.142000.json','["我行誰與報江楓，旋擺旌旗一路紅。", "朔吹崩騰危兩耳，東山踴躍獻諸峰。", "松陰好處皆亭子，瑶草香邊即坐狨。", "漸陟漸高元不覺，忽然身在半天中。"]'),
('5df08259-fee2-4fde-bb2c-8c12ca6d85b2','同劉季游登天柱岡四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','穿青度碧白雲中，山正奇時路忽窮。',32,'全唐诗/poet.song.142000.json','["穿青度碧白雲中，山正奇時路忽窮。", "引道老農辭我去，與君更上最高峰。"]'),
('261ff401-ec7d-42ee-8b79-9b5d63a8721a','同劉季游登天柱岡四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','偶然乘興上孱顔，若待偷閑何日閑。',32,'全唐诗/poet.song.142000.json','["偶然乘興上孱顔，若待偷閑何日閑。", "脚力到時皆我有，不須更問是誰山。"]'),
('bdb409e3-8788-4268-b8ba-5206d6b2080c','夜飲二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','夜飲空齋冷，移歸近竹爐。',48,'全唐诗/poet.song.142000.json','["夜飲空齋冷，移歸近竹爐。", "酒新今晚醡，燭短昨宵餘。", "紫蔗椽來大，黄柑蜜不如。", "醉中得五字，索筆不能書。"]'),
('6cc2918d-de6f-482e-ab6b-33ee781dc4cf','夜飲二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','飲酒無奇訣，且斟三四分。',48,'全唐诗/poet.song.142000.json','["飲酒無奇訣，且斟三四分。", "初頭只嫌淺，忽地有餘春。", "身外多少事，燈前子細論。", "絕憐青女老，忍冷撒瓊塵。"]'),
('1681faf9-3d7d-4ce0-bc85-0ffd7d862ba6','不睡四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','夜永無眠非爲茶，無風燈影自橫斜。',32,'全唐诗/poet.song.142000.json','["夜永無眠非爲茶，無風燈影自橫斜。", "擁裯仰面書帷薄，數盡承塵一簟花。"]'),
('fb530496-a024-4d3d-944c-e101d36de700','不睡四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','望後更深月未明，暗蛩凍得總無聲。',32,'全唐诗/poet.song.142000.json','["望後更深月未明，暗蛩凍得總無聲。", "閑心幸自清如水，萬感還從不睡生。"]'),
('fac7a48e-10a4-4c9a-9c60-ab87c773e61f','不睡四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','清愁無數暗相隨，酒是渠讎也是媒。',32,'全唐诗/poet.song.142000.json','["清愁無數暗相隨，酒是渠讎也是媒。", "醉裏不知何處嚲，等人醒後一時來。"]'),
('604c20a7-4cc9-40bb-b4f5-26c8d7733b56','不睡四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','眊矂渾如病起初，冬烘又似酒醒餘。',32,'全唐诗/poet.song.142000.json','["眊矂渾如病起初，冬烘又似酒醒餘。", "睡鄉幸有閑田地，不放詩人僦一居。"]'),
('d041342e-9d4c-4856-af84-322083a24ba0','醉吟二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','十載人間樂與憂，幾曾半點到心頭。',64,'全唐诗/poet.song.142000.json','["十載人間樂與憂，幾曾半點到心頭。", "梧桐葉上秋無價，蟋蟀聲中月亦愁。", "暮角曉鐘何日了，蒼顔華髮此生休。", "吟顛醉蹶知無益，利走名奔有命不。"]'),
('6fe6bb4e-c294-4ab1-aa1b-0ea8b016d06b','醉吟二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','三春草草眼中過，未抵三冬樂事多。',64,'全唐诗/poet.song.142000.json','["三春草草眼中過，未抵三冬樂事多。", "燭焰雙丫紅再合，酒花半蕾碧千波。", "孤寒霜月儂相似，跌宕雪風誰奈何。", "道是閑人沒勳績，一枝樵斧一漁蓑。"]'),
('3800309d-38e4-4413-bc39-c15fd181bbb1','烏臼燭','楊萬里','宋','宋诗','song-poetry','','[]','焰白光寒淚亦收，臼燈十倍蜜燈休。',32,'全唐诗/poet.song.142000.json','["焰白光寒淚亦收，臼燈十倍蜜燈休。", "忘情也似誠齋叟，燒盡心時不淚流。"]'),
('8f067475-ed40-489c-bd79-40bb2beb920d','送王文伯上舍歸豐城兼簡何侍郎','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','碧落先生少可人，銀鈎繭紙苦稱君。',64,'全唐诗/poet.song.142000.json','["碧落先生少可人，銀鈎繭紙苦稱君。", "談間口吸西江水，句裏家傳南浦雲。", "千里端能來命駕，一尊得與細論文。", "還家剩草三千牘，看策平津第一勳。"]'),
('4325bac6-e0ee-4646-8b12-eb05b26981b5','題曾良臣思堂','楊萬里','宋','宋诗','song-poetry','','[]','謝墅新成了，潘輿竟不歸。',48,'全唐诗/poet.song.142000.json','["謝墅新成了，潘輿竟不歸。", "升堂仰遺像，下拜泣沾衣。", "反哺烏何在，卧冰魚自肥。", "夢中環佩響，驚喜覺來非。"]'),
('f3180d3d-eff7-4eeb-b4af-859a5c5f9267','送彭子山提刑郎中赴召二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','帝想丹青憶老成，公兼竹潤更蘭馨。',64,'全唐诗/poet.song.142000.json','["帝想丹青憶老成，公兼竹潤更蘭馨。", "獨追洙泗人無訟，再使成康世措刑。", "召節自天回使節，郎星朝斗作台星。", "花邊獨坐黄昏句，剩寄江西白鷺汀。"]'),
('5dda3e7e-949f-424c-9994-60f9abfc7e11','送彭子山提刑郎中赴召二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','瓊樹初瞻二紀中，玉京再別一星終。',64,'全唐诗/poet.song.142000.json','["瓊樹初瞻二紀中，玉京再別一星終。", "我隨病鶴欹黄帽，公駕雲鴻上碧穹。", "寄徑絲綸紫薇閣，押班冠劍大明宮。", "錦園尚欠桃栽否，兒輩河陽待曉風。"]'),
('574c4f6c-d3dd-4d0c-b40e-5fdb23b922f6','送族弟子西赴省','楊萬里','宋','宋诗','song-poetry','','[]','吾家詞伯達齋翁，阿季文名有父風。',64,'全唐诗/poet.song.142000.json','["吾家詞伯達齋翁，阿季文名有父風。", "筆陣千軍能獨掃，馬羣萬古洗來空。", "嗟予還笏歸林下，看子乘船入月中。", "淡墨榜頭先快睹，泥金帖子不須封。"]'),
('72645e1a-8926-433d-b74c-961fd18ce042','寄題福帥張子儀尚書禊遊堂','楊萬里','宋','宋诗','song-poetry','','[]','祖孫接武禊堂前，風物重新六十年。',64,'全唐诗/poet.song.142000.json','["祖孫接武禊堂前，風物重新六十年。", "無恙鈞衡舊棠蔭，有光台斗繼蒲鞭。", "手提西郭三山月，下照南湖萬頃天。", "不要外人來作記，當家自有筆如椽。"]'),
('4b39941b-2bf2-4ace-8df2-51ec90617eea','南溪弄水回望山園梅花','楊萬里','宋','宋诗','song-poetry','','[]','梅從山上過溪來，近愛清溪遠愛梅。',32,'全唐诗/poet.song.142000.json','["梅從山上過溪來，近愛清溪遠愛梅。", "溪水聲聲留我住，梅花朶朶喚人回。"]'),
('a44d3073-6097-4a2d-bf55-7021a44bdbd0','火閣午睡起負暄二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','火閣紅銷雪尚香，睡魔引我入渠鄉。',32,'全唐诗/poet.song.142000.json','["火閣紅銷雪尚香，睡魔引我入渠鄉。", "覺來一陣寒無柰，自掇胡床負太陽。"]'),
('f70773e0-6a9e-4dc0-8c88-ff4a2314be73','火閣午睡起負暄二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','黄菊霜枝已懶殘，瑞香紫笋政團欒。',32,'全唐诗/poet.song.142000.json','["黄菊霜枝已懶殘，瑞香紫笋政團欒。", "盆池影裏看題壁，上字還成下字看。"]'),
('73775649-cc85-45e8-96ad-89818f3518e6','曬衣','楊萬里','宋','宋诗','song-poetry','','[]','亭午曬衣晡褶衣，柳箱布襆自携歸。',32,'全唐诗/poet.song.142000.json','["亭午曬衣晡褶衣，柳箱布襆自携歸。", "妻孥相笑還相問，赤脚蒼頭更阿誰。"]'),
('93f44d8a-1bd1-4d0f-bf5e-7a9b73cedade','讀張文潜詩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','晚愛肥仙詩自然，何曾繡繪更琱鎸。',32,'全唐诗/poet.song.142000.json','["晚愛肥仙詩自然，何曾繡繪更琱鎸。", "春花秋月冬冰雪，不聽陳玄只聽天。"]'),
('1964a279-d186-4b12-9cde-41d421ac94fc','讀張文潜詩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','山谷前頭敢說詩，絕稱潄井掃花詞。',32,'全唐诗/poet.song.142000.json','["山谷前頭敢說詩，絕稱潄井掃花詞。", "後來全集教渠見，別有天珍渠得知。"]'),
('8be3a890-a875-4bf3-9b8c-f8416e786991','壬戌人日南溪暮景三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','坐看青天起白雲，化成龍子鈒銀鱗。',32,'全唐诗/poet.song.142000.json','["坐看青天起白雲，化成龍子鈒銀鱗。", "霎時塞得青天滿，只見龍鱗不見身。"]'),
('f05ee8ef-1cd7-4803-b6c4-466a62f72d03','壬戌人日南溪暮景三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','春暖溪暄出小魚，沉浮上下巧相娛。',32,'全唐诗/poet.song.142000.json','["春暖溪暄出小魚，沉浮上下巧相娛。", "一跳一浪錢來大，開作瑶環忽丈餘。"]'),
('8d546b72-adba-4a4f-9a74-f0c38f6db183','壬戌人日南溪暮景三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','翡翠驚飛不作行，沙鷗亂下自成雙。',32,'全唐诗/poet.song.142000.json','["翡翠驚飛不作行，沙鷗亂下自成雙。", "一天霞綺沉波底，便是西川濯錦江。"]'),
('7c5e0140-46ad-4da1-80b6-2db5edea42e1','雨後至溪上','楊萬里','宋','宋诗','song-poetry','','[]','夜雨無端忽曉晴，南溪便長半篙清。',64,'全唐诗/poet.song.142000.json','["夜雨無端忽曉晴，南溪便長半篙清。", "斜衝亂石雪霜碎，快瀉深陂金玉聲。", "慢處回頭縈作漩，急邊眨眼不留行。", "李成覷著如何畫，却是詩中畫得成。"]'),
('66a4b75e-ecb2-4fd3-a2b1-b6c5fecb9f17','寄題太和宰趙嘉言勤民二圖 題通濟渡船圖','楊萬里','宋','宋诗','song-poetry','','[]','歲歲桃花水到時，野航客子命如絲。',32,'全唐诗/poet.song.142000.json','["歲歲桃花水到時，野航客子命如絲。", "趙侯小試濟川手，雪浪翻天不濺伊。"]'),
('ee0d43fc-3714-46d1-a1f0-6f8fbbb8f972','寄題太和宰趙嘉言勤民二圖 題停罷坊場圖','楊萬里','宋','宋诗','song-poetry','','[]','半山辱國賣叢祠，鍾步諸坊卷酒旗。',32,'全唐诗/poet.song.142000.json','["半山辱國賣叢祠，鍾步諸坊卷酒旗。", "村裏山農語音好，孔方兄已赦鵝兒。"]'),
('d118b758-3cc3-4d56-ac3b-42791d6f4fc1','上元前一日遊東園看紅梅三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','欲折紅梅朶，看來不忍攀。',24,'全唐诗/poet.song.142000.json','["欲折紅梅朶，看來不忍攀。", "週迴尋四處，恰得一枝繁。"]'),
('2ea74cfb-4070-49fc-b5cc-b4d2e73d52cf','上元前一日遊東園看紅梅三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','偶看紅梅到小園，憑欄送眼過前村。',32,'全唐诗/poet.song.142000.json','["偶看紅梅到小園，憑欄送眼過前村。", "山頭茅屋隔孤樹，籬外行人出半身。"]'),
('67681b6a-1551-4004-96eb-704254c6518d','上元前一日遊東園看紅梅三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','兒牽黄犢父擔犁，社鼓迎神簇紙旗。',32,'全唐诗/poet.song.142000.json','["兒牽黄犢父擔犁，社鼓迎神簇紙旗。", "不是豐年那得此，今春大勝去春時。"]'),
('a6556f56-8677-4cac-a8b5-33c6b5a3b417','南溪薄晚觀水','楊萬里','宋','宋诗','song-poetry','','[]','誰將沙礫壅隄斜，水怒衝隄自決沙。',32,'全唐诗/poet.song.142000.json','["誰將沙礫壅隄斜，水怒衝隄自決沙。", "無數小魚齊亂跳，瑠璃盤底簸銀花。"]'),
('3582be22-707e-4df2-9439-789bddb2f96c','溪邊月上二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','正月十四夜，如何月便團。',24,'全唐诗/poet.song.142000.json','["正月十四夜，如何月便團。", "似知吾輩出，預借上元看。"]'),
('5c84c887-d6fc-458a-a1dc-1d87f5006f25','溪邊月上二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','片子黄金餠，看來只管高。',24,'全唐诗/poet.song.142000.json','["片子黄金餠，看來只管高。", "忽然落溪水，雜碎作銀濤。"]'),
('a07ee169-13bd-4a53-be5f-58dcff94e169','同才翁弟遊東園','楊萬里','宋','宋诗','song-poetry','','[]','東園花徑半莓苔，老子多時不到來。',32,'全唐诗/poet.song.142000.json','["東園花徑半莓苔，老子多時不到來。", "一巷江梅都落盡，祇今開底是紅梅。"]'),
('6622d4d2-b231-4256-8692-4f0671cdcf7c','近故太師左丞相魏國文忠京公挽歌辭三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','孝廟深知己，今皇正宰官。',48,'全唐诗/poet.song.142000.json','["孝廟深知己，今皇正宰官。", "一言能定國，二聖得重懽。", "立節山相似，容人海未寬。", "至今死諸葛，虜使膽猶寒。"]'),
('19eac0db-e896-423d-a5ed-1b48e43c490f','近故太師左丞相魏國文忠京公挽歌辭三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','鎮蜀雙清獻，回天再子明。',48,'全唐诗/poet.song.142000.json','["鎮蜀雙清獻，回天再子明。", "何曾動聲色，一笑付權衡。", "臨絕緣憂國，平生不近名。", "中興賢相傳，日月奪光精。"]'),
('ebf034dd-a9e4-4630-b0a3-38b47c5c073c','近故太師左丞相魏國文忠京公挽歌辭三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','柏府公峨豸，荆溪我把麾。',48,'全唐诗/poet.song.142000.json','["柏府公峨豸，荆溪我把麾。", "聞風無半面，折簡兩相知。", "偕掾膠投漆，分襟雲與泥。", "樓成扁山浦，灑淚欠題詩。"]'),
('f63303b7-7e37-4ece-8692-3f33c7c9e371','近故魏國夫人盧氏挽歌辭三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','胄出開元相，賢稱魏國嬪。',48,'全唐诗/poet.song.142000.json','["胄出開元相，賢稱魏國嬪。", "祇教紀彤管，不見轉鴻鈞。", "瓜葛春風裏，蘋蘩南澗濱。", "古今書列女，仁孝幾何人。"]'),
('5aa18500-b44f-447b-bb86-c4cf96c03c02','近故魏國夫人盧氏挽歌辭三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','唐代崔家母，升堂乳阿姑。',48,'全唐诗/poet.song.142000.json','["唐代崔家母，升堂乳阿姑。", "姑言吾報婦，孫孝婦如吾。", "此段前無古，夫人獨與俱。", "祇看秦國語，更恐李唐無。"]'),
('e50a6f6f-7889-4196-b9fc-cca7d8af129d','近故魏國夫人盧氏挽歌辭三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','素節勤仍儉，清風冷似冰。',48,'全唐诗/poet.song.142000.json','["素節勤仍儉，清風冷似冰。", "秋衣孟光布，夜績敬姜燈。", "拱木霜何早，同塋雪政凝。", "郎君一夔足，再看九霄鵬。"]'),
('da2fa9e6-005b-4244-bc3d-a9cb7d3110ac','東園探桃李二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','偶逢李徑一花開，從此東園日日來。',32,'全唐诗/poet.song.142000.json','["偶逢李徑一花開，從此東園日日來。", "更約桃花同坼好，紅紅白白兩相催。"]'),
('025dc5a8-dd3a-450e-be30-f4e4fb0cdcf5','東園探桃李二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','有花無葉也孤寒，有葉無花草一般。',32,'全唐诗/poet.song.142000.json','["有花無葉也孤寒，有葉無花草一般。", "最是桃花饒態度，醉紅嬌綠惱人看。"]'),
('88101df0-1955-4019-9c96-c7b646f52701','李花','楊萬里','宋','宋诗','song-poetry','','[]','李花宜遠更宜繁，惟遠惟繁始足看。',32,'全唐诗/poet.song.142000.json','["李花宜遠更宜繁，惟遠惟繁始足看。", "莫學江梅作疎影，家風各自一般般。"]'),
('70981911-be1a-4722-8bad-6ab9a3ab8c40','春晴','楊萬里','宋','宋诗','song-poetry','','[]','日透微風暖，風揉嫩日佳。',24,'全唐诗/poet.song.142000.json','["日透微風暖，風揉嫩日佳。", "祇知趲桃李，不道落梅花。"]'),
('0f6d7964-69bd-4be8-888c-9cd123a7c2b8','寄題太和丞公沈君公館亭臺四詠 真清亭','楊萬里','宋','宋诗','song-poetry','','[]','蒼髯秦大夫，瘦骨孤竹君。',24,'全唐诗/poet.song.142000.json','["蒼髯秦大夫，瘦骨孤竹君。", "主人似二子，二子似主人。"]'),
('53077929-c000-412f-b019-40912d4f9763','寄題太和丞公沈君公館亭臺四詠 特秀亭','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','秋月弄長江，平地點遠岫。',24,'全唐诗/poet.song.142000.json','["秋月弄長江，平地點遠岫。", "贊府詩句中，字字江山秀。"]'),
('f643a2fb-b05c-46a5-b622-360fdd755932','寄題太和丞公沈君公館亭臺四詠 成蹊亭','楊萬里','宋','宋诗','song-poetry','','[]','紅雨未隨風，白雪忽滿枝。',24,'全唐诗/poet.song.142000.json','["紅雨未隨風，白雪忽滿枝。", "祇今正月尾，政是斷腸時。"]'),
('eea4bbe8-114f-4908-a194-d49d6164b4d5','寄題太和丞公沈君公館亭臺四詠 讀書臺','楊萬里','宋','宋诗','song-poetry','','[]','庭散紙尾鶩，窗聚案頭螢。',24,'全唐诗/poet.song.142000.json','["庭散紙尾鶩，窗聚案頭螢。", "無端循除水，也學夜誦聲。"]'),
('7c729bc0-48ea-4395-ac25-dda9255141b4','寄題分宜李克明上舍高居二詠 不礙雲山樓','楊萬里','宋','宋诗','song-poetry','','[]','想見謫仙裔，卷簾雙眼寒。',24,'全唐诗/poet.song.142000.json','["想見謫仙裔，卷簾雙眼寒。", "雲山千疊碧，飛舞入欄干。"]'),
('6c3ab725-0a18-4e95-b2c4-7a49725b583c','寄題分宜李克明上舍高居二詠 東塾','楊萬里','宋','宋诗','song-poetry','','[]','一鳳領四雛，夜作吾伊聲。',24,'全唐诗/poet.song.142000.json','["一鳳領四雛，夜作吾伊聲。", "梧桐高拂日，好去瑞堯庭。"]'),
('f7eb76cb-31d4-4fe2-9576-b96efaf887a7','春寒','楊萬里','宋','宋诗','song-poetry','','[]','風日晴暄一併來，桃花告報李花開。',32,'全唐诗/poet.song.142000.json','["風日晴暄一併來，桃花告報李花開。", "待君減盡衣裘了，夜半春寒特地回。"]'),
('6b462bef-37e5-4f20-bc08-8304e6f5f625','和張寺丞功父八絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','約齋太瘦古僊真，寄我詩篇字字新。',32,'全唐诗/poet.song.142000.json','["約齋太瘦古僊真，寄我詩篇字字新。", "受業陳三能幾日，無端參換謫仙人。"]'),
('f8683943-9c25-4315-a07d-ce685a4037ca','和張寺丞功父八絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','古來官職妬詩篇，二物雙違不肯全。',32,'全唐诗/poet.song.142000.json','["古來官職妬詩篇，二物雙違不肯全。", "君被詩篇折官職，如何又寄一新編。"]'),
('fae4a923-274c-4a61-8d15-bf8eadcab8d0','和張寺丞功父八絕句  其三','楊萬里','宋','宋诗','song-poetry','','[]','與子相望天一方，有書無使倩誰將。',32,'全唐诗/poet.song.142000.json','["與子相望天一方，有書無使倩誰將。", "歸鴻欲下還飛去，不作書郵有底忙。"]'),
('f6f909fd-3408-4f0c-9787-77b60d25abc5','和張寺丞功父八絕句  其四','楊萬里','宋','宋诗','song-poetry','','[]','金華不敢比東坡，此後東坡爾許多。',32,'全唐诗/poet.song.142000.json','["金華不敢比東坡，此後東坡爾許多。", "擾擾胸中百周孔，不愁柳柳笑人何。"]'),
('11b5b0df-6623-482f-92e9-2cb2900f7606','和張寺丞功父八絕句  其五','楊萬里','宋','宋诗','song-poetry','','[]','問訊南湖作麽生，日撞金玉奏英莖。',32,'全唐诗/poet.song.142000.json','["問訊南湖作麽生，日撞金玉奏英莖。", "無人打殺浄飯子，放出渠頭七步行。"]'),
('62ab1785-7155-4cc8-afdd-6c0bfe68ffc8','和張寺丞功父八絕句  其六','楊萬里','宋','宋诗','song-poetry','','[]','新歲南湖春又濃，海棠舊入我詩中。',32,'全唐诗/poet.song.142000.json','["新歲南湖春又濃，海棠舊入我詩中。", "別來若有相思字，寄與江西花信風。"]'),
('4f40e2b3-7eda-48aa-bb43-1d62a9516c1f','和張寺丞功父八絕句  其七','楊萬里','宋','宋诗','song-poetry','','[]','湖邊花底舊論詩，再要尋盟今若爲。',32,'全唐诗/poet.song.142000.json','["湖邊花底舊論詩，再要尋盟今若爲。", "道是鶑啼無點淚，教鶑聞此也垂洟。"]'),
('5af57cd9-d1af-402a-98ae-3cab68a85a82','和張寺丞功父八絕句  其八','楊萬里','宋','宋诗','song-poetry','','[]','斷當湖山我與公，問公別後却誰同。',32,'全唐诗/poet.song.142000.json','["斷當湖山我與公，問公別後却誰同。", "一生海內金石友，萬事人間牛馬風。"]'),
('6e1377b3-fbeb-41ac-88b6-fa2aa83a15e9','謝襄陽帥楊侍郎用轆轤體','楊萬里','宋','宋诗','song-poetry','','[]','合志同宗憶嗣清，尋盟繼好感難兄。',64,'全唐诗/poet.song.142000.json','["合志同宗憶嗣清，尋盟繼好感難兄。", "關西伯起今夫子，後世子雲重易經。", "金薤銀鈎詒妙墨，貂裘玉札寄交情。", "本朝未有楊家相，留待公歸兩兩星。"]'),
('7faef381-dbd0-47ab-9b04-aad9c9679d6a','王式之直閣不遠千里來訪野人贈以佳句次韻奉謝','楊萬里','宋','宋诗','song-poetry','','[]','君才陸海與潘江，句裏芒寒萬丈長。',64,'全唐诗/poet.song.142000.json','["君才陸海與潘江，句裏芒寒萬丈長。", "雪椀冰甌翻筆墨，錦機綉段出肝腸。", "王家龍鳳重英特，謝砌芝蘭讓耿光。", "相國登庸衣鉢在，郎君努力續前芳。"]'),
('3e3554d8-9d03-47cb-9774-dbfd4e228a53','寄題張縣尉敬之南昌官寺重新子真祠堂','楊萬里','宋','宋诗','song-poetry','','[]','梅郎絳節朝玉臺，朝游五城暮九垓。',96,'全唐诗/poet.song.142000.json','["梅郎絳節朝玉臺，朝游五城暮九垓。", "遺民香火答遺愛，何年祠屋荒蒼苔。", "劍津詩客子張子，住持仙壇判山水。", "上書台斗大居士，作緣水漕皇華使。", "二臺併檄孔家兄，經始新祠不日成。", "西山南浦作賀賓，野梅官柳俱驩聲。"]'),
('17b45ff3-b122-4f7d-be96-7a728e6e7b0e','送趙吉州判院器之移利路提刑','楊萬里','宋','宋诗','song-poetry','','[]','趙侯邁往隆準孫，未年五十專三城。',128,'全唐诗/poet.song.142000.json','["趙侯邁往隆準孫，未年五十專三城。", "千里秋豪無遁情，兩眼洞照如秋鷹。", "何須奮髯走百吏，棠陰晝寂清如水。", "年年州人喫賤米，侲子踏歌凍黎喜。", "去冬苦暖未有梅，使君一笑梅花開。", "夜吹平地一尺雪，留下豐年今歲回。", "使星移照天西去，白鷺青原遮不住。", "即隨丹詔歸握蘭，遂持紫橐甘泉班。"]'),
('16c05771-3c94-4645-ad36-537cc05553e5','雨中入城送趙吉州器之二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','拂溪楊柳縷生金，欄路山礬香殺人。',32,'全唐诗/poet.song.142000.json','["拂溪楊柳縷生金，欄路山礬香殺人。", "不是衝泥送行客，外頭放過若干春。"]'),
('781f4dfd-3d5f-4dbc-8c86-48c756daa224','雨中入城送趙吉州器之二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','村店農忙半不開，入城客子去還來。',32,'全唐诗/poet.song.142000.json','["村店農忙半不開，入城客子去還來。", "阿耶烏傘兒青笠，賣却松柴買菜回。"]'),
('744fdeec-94aa-4fef-92a6-d49f22d5de0f','宿城外張氏莊早起入城三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','燈火頻挑只管殘，雨聲終夜惱空山。',32,'全唐诗/poet.song.142000.json','["燈火頻挑只管殘，雨聲終夜惱空山。", "幸蒙曉月多情白，又遣東風抵死寒。"]'),
('f14baa2e-78a0-4ba9-b2e4-d2ef066f6c38','宿城外張氏莊早起入城三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','破店無雞報五更，只將夢覺當雞鳴。',32,'全唐诗/poet.song.142000.json','["破店無雞報五更，只將夢覺當雞鳴。", "匆匆上却籃輿了，隔壁人家政睡聲。"]'),
('0bb675f8-11e2-4d3e-8b36-f975828aac61','宿城外張氏莊早起入城三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','眠雲跂石十餘年，回首拋官一瞬間。',32,'全唐诗/poet.song.142000.json','["眠雲跂石十餘年，回首拋官一瞬間。", "送舊迎新也辛苦，一番辛苦兩年閑。"]'),
('61aa4fb4-79b5-41a8-a177-e9d849004d8c','次公滿秩來歸偶上巳寒食同日父子小酌','楊萬里','宋','宋诗','song-poetry','','[]','又是一年脩禊時，何須曲水泛金巵。',64,'全唐诗/poet.song.142000.json','["又是一年脩禊時，何須曲水泛金巵。", "遍嘗衆酒少亦醉，坐到三更眠未遲。", "上巳巧當寒食日，春風慳放牡丹枝。", "白頭父子燈前語，忘却江湖久別離。"]'),
('71b806fd-203f-4353-9db1-c31d2f491039','送金元度教授辭滿赴部改秩','楊萬里','宋','宋诗','song-poetry','','[]','金華唐呂兩儒先，夜半黄梅君併傳。',64,'全唐诗/poet.song.142000.json','["金華唐呂兩儒先，夜半黄梅君併傳。", "不日經筵重坐席，蹔時黌舍冷無氈。", "引班曉漏槐楓裏，出宰春風桃李邊。", "莫遣垂楊知別恨，一篙新漲解歸船。"]'),
('9e8920a2-763e-42c6-92f1-07446eca0dcf','嘗荼𧃲酒','楊萬里','宋','宋诗','song-poetry','','[]','月中露下摘荼糜，瀉酒銀缾花倒垂。',64,'全唐诗/poet.song.142000.json','["月中露下摘荼糜，瀉酒銀缾花倒垂。", "若要花香薰酒骨，莫教玉醴濕瓊肌。", "一杯墮我無何有，百罰知君亦不辭。", "敕賜深之能幾許，野人時復一中之。"]'),
('ad8079a2-803e-4e8a-b20b-01184c53ea16','劉季澄投贈新詩次韻爲謝','楊萬里','宋','宋诗','song-poetry','','[]','君操筆耒啟新畬，耕徧西溪萬卷餘。',64,'全唐诗/poet.song.142000.json','["君操筆耒啟新畬，耕徧西溪萬卷餘。", "藜杖芒鞋來得得，柳風花雨政疎疎。", "是家人物孫如祖，驚代詩文我愛渠。", "努力收科無早晚，不須燈下獨長噓。"]'),
('d339e7e4-7c8d-4554-8fe2-5cef3e18b8b9','餞洪帥張伯子華學尚書移鎮京口','楊萬里','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','周家天球祇一隻，張家今有雙白璧。',230,'全唐诗/poet.song.142000.json','["周家天球祇一隻，張家今有雙白璧。", "前稱紫薇後文昌，衙官二陸僕兩唐。", "金章玉句迭清鏘，天孫雲機織錦裳。", "松心竹節爭老蒼，冰壺水鏡明秋霜。", "君不見于湖先生掌綸綍，二典三謨纔一筆。", "君不見篤素先生立朝端，五臣十亂半武間。", "聽履星辰踐台斗，翻身鳳池屈伸肘。", "夢入飛雲卷雨簾，袖却築巖作霖手。", "滕王閣上唐阿舒，春生秋殺震江湖。", "吏部未見張尚書，春生儘有秋殺無。", "江西十州百萬戶，父非姓召母非杜。", "也祇周人兩句詩，豈弟君子民父母。", "又去南徐作好春，落霞秋水亦眉顰。", "南徐父老錯欣欣，玉皇催渠轉鴻鈞。"]'),
('642cca38-651e-4a75-a149-2cd9fe032121','春雨不止二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','無計奈何春日長，宰予介紹謁羲皇。',32,'全唐诗/poet.song.142000.json','["無計奈何春日長，宰予介紹謁羲皇。", "蟻纔問陣天又雨，蜂欲舂糧花政香。"]'),
('fce36cf6-d245-454a-b836-c268b8b089af','春雨不止二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','春雨如毛又似埃，雲開還合合還開。',32,'全唐诗/poet.song.142000.json','["春雨如毛又似埃，雲開還合合還開。", "怪來春晚寒如許，無頼桐花領取來。"]'),
('67967e84-51ea-4abd-8ad3-f4f7ff5c7588','踏青','楊萬里','宋','宋诗','song-poetry','','[]','雨換溪溪玉，花呈嶺嶺春。',24,'全唐诗/poet.song.142000.json','["雨換溪溪玉，花呈嶺嶺春。", "秧田暄處早，茅屋補痕新。"]'),
('8224478b-3bf8-44a8-a3e4-7aab9fa02352','寒燈','楊萬里','宋','宋诗','song-poetry','','[]','老穉都眠我獨醒，寒燈半點伴三更。',32,'全唐诗/poet.song.142000.json','["老穉都眠我獨醒，寒燈半點伴三更。", "雙花忽作蜻蜓眼，孤焰仍懸玉膽瓶。"]'),
('789d8a03-f9d7-4886-b020-8cd892a9bf70','雨夜獨酌','楊萬里','宋','宋诗','song-poetry','','[]','清明未到未和柔，過了清明春又休。',32,'全唐诗/poet.song.142000.json','["清明未到未和柔，過了清明春又休。", "燭下看花徧有思，醉中聽雨也無愁。"]'),
('94eecba2-9838-4368-b2ef-62625af94a80','瓶中淮陽紅牡丹落盡有歎三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','只愁風雨妬花枝，翦入瓷瓶養却伊。',32,'全唐诗/poet.song.142000.json','["只愁風雨妬花枝，翦入瓷瓶養却伊。", "更下重簾深閉閣，忽然花落又關誰。"]'),
('6b0c240e-3f55-405c-9afe-c7f984699b9f','瓶中淮陽紅牡丹落盡有歎三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','眼中姚魏過匆匆，只有淮陽打底紅。',32,'全唐诗/poet.song.142000.json','["眼中姚魏過匆匆，只有淮陽打底紅。", "杜宇一聲花睡醒，却教老子怨東風。"]'),
('42b234f7-a584-4f9f-a7a7-bf1c88368304','瓶中淮陽紅牡丹落盡有歎三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','又是明年看牡丹，未開芍藥怯春寒。',32,'全唐诗/poet.song.142000.json','["又是明年看牡丹，未開芍藥怯春寒。", "落英滿地不須掃，一片蔫紅也足觀。"]'),
('952c63f4-9339-497e-9c1a-181fe1412260','寄題龍泉李宗儒師儒槐陰書院','楊萬里','宋','宋诗','song-poetry','','[]','龍泉二李繼謫仙，朝議朝散相後先。',80,'全唐诗/poet.song.142000.json','["龍泉二李繼謫仙，朝議朝散相後先。", "鳳雛二妙繼乃祖，宗儒師儒賢弟昆。", "手種兔目今幾年，日茹葉淘呻斷編。", "陰似王家三樹綠，異時官職追前躅。", "花作唐人八月黄，來歲能書催趣裝。"]'),
('480bb198-d194-4329-8b31-b1514cb28092','李師儒上舍稽古堂','楊萬里','宋','宋诗','song-poetry','','[]','青楓金剎依然在，黄石圯橋元不改。',112,'全唐诗/poet.song.142000.json','["青楓金剎依然在，黄石圯橋元不改。", "只有謫仙稽古堂，兵燒水毀草樹荒。", "二大夫家有孫子，去珠復還堂再起。", "朱甍碧瓦拂金波，牙籤玉軸拄銀河。", "山鬼吹燈聽夜誦，秋兔獻穎供晨哦。", "向來二李名父子，今來二李佳兄弟。", "鶺鴒雙去集上林，李家大夫看二二。"]'),
('b43b41af-3518-4372-a107-b6714f7db9c9','初夏即事十二解  其一','楊萬里','宋','宋诗','song-poetry','','[]','蓮葉頭巾道樣裁，仙桃扇子午時回。',32,'全唐诗/poet.song.142000.json','["蓮葉頭巾道樣裁，仙桃扇子午時回。", "撲蠅墮地猶能旋，閉閣生塵底處來。"]'),
('b45e09c4-a08c-4f65-aadc-d1d9f6428ecc','初夏即事十二解  其二','楊萬里','宋','宋诗','song-poetry','','[]','瑞香端合譜離騷，有子傳芳韻亦高。',32,'全唐诗/poet.song.142000.json','["瑞香端合譜離騷，有子傳芳韻亦高。", "失却薰籠紅錦被，化爲矮樹紫櫻桃。"]'),
('8e375db4-a337-4fa3-a937-29ac80e8d378','初夏即事十二解  其三','楊萬里','宋','宋诗','song-poetry','','[]','百日田乾田父愁，只銷一雨百無憂。',32,'全唐诗/poet.song.142000.json','["百日田乾田父愁，只銷一雨百無憂。", "更無人惜田中水，放下清溪恣意流。"]'),
('1b75bcf8-e27b-4e19-b2db-445a0878706e','初夏即事十二解  其四','楊萬里','宋','宋诗','song-poetry','','[]','從教節序暗相催，曆日塵生懶看來。',32,'全唐诗/poet.song.142000.json','["從教節序暗相催，曆日塵生懶看來。", "却是石榴知立夏，年年此日一花開。"]'),
('f38551c1-7ee6-4800-bd9e-294f406b0edd','初夏即事十二解  其五','楊萬里','宋','宋诗','song-poetry','','[]','檻中紅藥趁春歸，瓶裏苛留三兩枝。',32,'全唐诗/poet.song.142000.json','["檻中紅藥趁春歸，瓶裏苛留三兩枝。", "一片落來能戀我，葉梢閣住不教飛。"]'),
('8fa5784d-ef9e-48b1-86fe-822d8e8108da','初夏即事十二解  其六','楊萬里','宋','宋诗','song-poetry','','[]','密有花紅綠刺長，似來作伴石榴芳。',32,'全唐诗/poet.song.142000.json','["密有花紅綠刺長，似來作伴石榴芳。", "金櫻身子玫瑰臉，更喫餳枝蜜果香。"]'),
('cf770343-1a13-4044-bd73-74de0ece30cd','初夏即事十二解  其七','楊萬里','宋','宋诗','song-poetry','','[]','玉磬金鐘天半鳴，夢中驚我起來聽。',32,'全唐诗/poet.song.142000.json','["玉磬金鐘天半鳴，夢中驚我起來聽。", "萬松花上三更雨，政事堂中有此聲。"]'),
('b67593a6-ce47-40a6-8971-4c6415da670f','初夏即事十二解  其八','楊萬里','宋','宋诗','song-poetry','','[]','東渚西陂萬馬奔，浪花吞盡舊波痕。',32,'全唐诗/poet.song.142000.json','["東渚西陂萬馬奔，浪花吞盡舊波痕。", "山童莫掃中庭水，要寫錢錢雨點紋。"]'),
('e3cbeb45-c8fb-4de3-887f-1f812ad67318','初夏即事十二解  其九','楊萬里','宋','宋诗','song-poetry','','[]','更無一箇子規啼，寂寂空山花自飛。',32,'全唐诗/poet.song.142000.json','["更無一箇子規啼，寂寂空山花自飛。", "啼得春歸它便去，元來不是勸人歸。"]'),
('08dabf32-7f1e-4145-b23e-8dc5766a2757','初夏即事十二解  其一○','楊萬里','宋','宋诗','song-poetry','','[]','柳外花梢啼亂鶑，行人過盡不曾聽。',32,'全唐诗/poet.song.142000.json','["柳外花梢啼亂鶑，行人過盡不曾聽。", "得人聽處君知麽，天欲明時第一聲。"]'),
('105e5e22-3a33-4d93-be5c-a9845d96eb2d','初夏即事十二解  其一一','楊萬里','宋','宋诗','song-poetry','','[]','狹斜只解賞春紅，秋菊冬梅不負公。',32,'全唐诗/poet.song.142000.json','["狹斜只解賞春紅，秋菊冬梅不負公。", "我道四時俱富貴，一杯催喚藕花風。"]'),
('1515f825-c0cf-45ce-baa0-79c5b3eb11a5','初夏即事十二解  其一二','楊萬里','宋','宋诗','song-poetry','','[]','王家麈柄綠瓊香，萱草偷來柄更長。',32,'全唐诗/poet.song.142000.json','["王家麈柄綠瓊香，萱草偷來柄更長。", "藏却柿紅纓拂子，菖蒲節裏放風光。"]'),
('640d42cf-dff9-4a8f-b97f-ba0b9f6e737b','詩酒懷趙德莊','楊萬里','宋','宋诗','song-poetry','','[]','舊日張三影，今時趙半杯。',48,'全唐诗/poet.song.142000.json','["舊日張三影，今時趙半杯。", "誰將牌印子，牒過草廬來。", "一代風流盡，餘年鬢髮催。", "愁邊對詩酒，懷抱向誰開。"]'),
('1edfc255-e4fe-49c9-b0c8-ef2674784811','紀聞悼舊','楊萬里','宋','宋诗','song-poetry','','[]','莫說湘南寺，令人絕痛渠。',48,'全唐诗/poet.song.142000.json','["莫說湘南寺，令人絕痛渠。", "中間緣國論，偶似絕交書。", "衫短枯荷葉，牆高過筍輿。", "人生須富貴，富貴竟何如。"]'),
('6bff28c6-dcb6-4a69-89a1-49a2ca2fb572','郭母孺人李氏挽歌辭','楊萬里','宋','宋诗','song-poetry','','[]','李郭俱名族，華婣合兩家。',48,'全唐诗/poet.song.142000.json','["李郭俱名族，華婣合兩家。", "藁砧巾角雨，郎罷筆頭花。", "樹秀庭雙玉，蓀榮砌百芽。", "半生冰雪節，再賦白山茶。"]'),
('ba48ec16-566a-48da-b814-a560e3b222dc','七字敬餞周彥敷府判直閣之官虎城','楊萬里','宋','宋诗','song-poetry','','[]','碧落仙人出作州，青原詩伯佐承流。',64,'全唐诗/poet.song.142000.json','["碧落仙人出作州，青原詩伯佐承流。", "江山得助催新句，風月平分入勝遊。", "清獻濂溪兩賓主，崆峒章貢再賡酬。", "舊時綠水紅蓮客，南望旗幢鬢已秋。"]'),
('8e7ee0b8-c06b-4edb-adb9-d8f161704bf2','端午前一日含笑初拆','楊萬里','宋','宋诗','song-poetry','','[]','一點瓜香破醉眠，誤它酒客枉流涎。',64,'全唐诗/poet.song.142000.json','["一點瓜香破醉眠，誤它酒客枉流涎。", "如何滴露牛心李，化作垂頭玉井蓮。", "初喜曉光將莞爾，竟羞午影不嫣然。", "忽看吐下金櫻核，蔌蔌聲乾暮葉邊。"]'),
('6cc4f489-bf3c-4a90-9c35-23219cca329e','端午獨酌','楊萬里','宋','宋诗','song-poetry','','[]','招得榴花共一觴，艾人笑殺老夫狂。',64,'全唐诗/poet.song.142000.json','["招得榴花共一觴，艾人笑殺老夫狂。", "子蘭赤口禳何益，正則紅船看不妨。", "團粽明朝便無味，菖蒲今日麽生香。", "一生幸免春端帖，可遣漁歌譜大章。"]'),
('62c5de03-0419-4de9-8a79-8d7b2c31a57d','送吉州通判趙德輝上印赴闕','楊萬里','宋','宋诗','song-poetry','','[]','太守九秋霜，通守三春風。',88,'全唐诗/poet.song.142000.json','["太守九秋霜，通守三春風。", "太守鏡照膽，通守淵涵空。", "古來人才在寒士，皇家人才在宗子。", "君看二趙作廬陵，寬猛晦明兩相濟。", "太守已乘八使車，通守合分五馬符。", "行看二趙俱法從，老夫別獻中和頌。"]'),
('52b00c9a-44c3-4854-9f1e-4b371836ae2c','暑中待月小酌','楊萬里','宋','宋诗','song-poetry','','[]','火傘朝張復暮張，若教無月底禁當。',64,'全唐诗/poet.song.142000.json','["火傘朝張復暮張，若教無月底禁當。", "隔林欲上光先漏，窺戶無多氣已涼。", "萬里無雲天似水，一奩新鏡色如霜。", "廣寒宮裏應無酒，挽住姮娥勸一觴。"]'),
('3c248628-7e95-4286-8940-744ffa8c8e1e','夏日小飲分題得菱用轆轤體','楊萬里','宋','宋诗','song-poetry','','[]','不是齊堂觳觫生，如何雙觝獨崢嶸。',64,'全唐诗/poet.song.142000.json','["不是齊堂觳觫生，如何雙觝獨崢嶸。", "犀中忽有紅尖角，天上也無甜底冰。", "只愛衣裳桃杏淺，誰知肌骨雪霜明。", "酒徒苦問渠名姓，無姓無名字子陵。"]'),
('3c37f6c3-834e-4f94-9e53-678a010b5a67','移床','楊萬里','宋','宋诗','song-poetry','','[]','清晨暑氣已愁予，何況晹蟲午及晡。',32,'全唐诗/poet.song.142000.json','["清晨暑氣已愁予，何況晹蟲午及晡。", "尋得松風小涼處，移床來坐又還無。"]'),
('fad4b240-d2e4-41d9-8622-ca3ae5cdad54','午睡起','楊萬里','宋','宋诗','song-poetry','','[]','永晝能不倦，亭午思小睡。',96,'全唐诗/poet.song.142000.json','["永晝能不倦，亭午思小睡。", "竹床熱如曬，展轉竟無寐。", "起來搔白首，百匝繞簷際。", "政當眊矂中，忽有一奇事。", "一風北戶來，穿度南窗外。", "窗外蕙初花，披拂動香氣。", "老夫得一涼，灑然有生意。", "來日當此時，未知復何似。"]'),
('935ffa6f-17c8-4d2b-aaed-94a3cf23f8ab','送章漢卿歸宣城','楊萬里','宋','宋诗','song-poetry','','[]','竹葉孤斟久，梅花遠信疎。',48,'全唐诗/poet.song.142000.json','["竹葉孤斟久，梅花遠信疎。", "如何窮巷轍，忽枉故人車。", "伯仲俱佳士，雲霄政望渠。", "相從又相別，欲別重躊躇。"]'),
('cf0e7bad-8e19-4eaf-81a9-89dbe1c82fcc','夏夜喜雨','楊萬里','宋','宋诗','song-poetry','','[]','聽雨初假寐，還成睡著休。',48,'全唐诗/poet.song.142000.json','["聽雨初假寐，還成睡著休。", "夢中簷奏樂，夜半簟知秋。", "今歲應須熟，餘生有底愁。", "無人知喜事，課僕織新篘。"]'),
('615eec10-2106-4dde-a6e5-a243469c437a','題長沙鍾仲山判院岫雲舒卷樓二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','天柱峰尖半點雲，散爲嶽麓橘洲春。',32,'全唐诗/poet.song.142000.json','["天柱峰尖半點雲，散爲嶽麓橘洲春。", "盡供詩客揮毫裏，怪底春空態度新。"]'),
('d0ec19d8-d08e-4a58-9385-8ae6a926bfeb','題長沙鍾仲山判院岫雲舒卷樓二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','入夜雲來宿兩窗，明朝雲去照三湘。',32,'全唐诗/poet.song.142000.json','["入夜雲來宿兩窗，明朝雲去照三湘。", "也知遠岫無心出，解后爲霖亦不妨。"]'),
('e959ba59-31a8-4041-8512-b9e749867b6c','立秋日聞蟬','楊萬里','宋','宋诗','song-poetry','','[]','老火薰人欲破頭，喚秋不到得人愁。',32,'全唐诗/poet.song.142000.json','["老火薰人欲破頭，喚秋不到得人愁。", "夜來一雨將秋至，今晚蟬聲始報秋。"]'),
('6bcd1809-6bd0-4783-8994-1b0dabfff734','二含笑俱作秋花','楊萬里','宋','宋诗','song-poetry','','[]','秋來二笑再芬芳，紫笑何如白笑强。',32,'全唐诗/poet.song.142000.json','["秋來二笑再芬芳，紫笑何如白笑强。", "只有此花偷不得，無人知處忽然香。"]'),
('90547d85-060d-438c-8508-20dd7c068d6b','秋夜極熱三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','只怨西風不早歸，早歸何似且歸遲。',32,'全唐诗/poet.song.142000.json','["只怨西風不早歸，早歸何似且歸遲。", "姮娥一夜摇團扇，更說明朝日午時。"]'),
('58cfff15-ab50-4731-98db-30786a5176f8','秋夜極熱三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','秋神今歲也癡獃，行李如何草草回。',32,'全唐诗/poet.song.142000.json','["秋神今歲也癡獃，行李如何草草回。", "白帝羽衣渾不带，炎官火傘却將來。"]'),
('0b7d957b-fbc9-414d-a73f-039d432fc161','秋夜極熱三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','葵扇頻揮手已麻，竹床偏熱冷無些。',32,'全唐诗/poet.song.142000.json','["葵扇頻揮手已麻，竹床偏熱冷無些。", "面涼却感鬚根汗，省得開門汲井花。"]'),
('1a46faf3-f142-48be-8b3a-2844a946cce1','題安福劉虞卿敏齋','楊萬里','宋','宋诗','song-poetry','','[]','君不見杜家阿宜開雪窗，日讀十紙月一箱。',102,'全唐诗/poet.song.142000.json','["君不見杜家阿宜開雪窗，日讀十紙月一箱。", "君不見崔家阿立染霜兔，暮作千詩朝百賦。", "讀書臺北卯金刀，齋前不種李與桃。", "滿階只種書带草，黄金非寶書爲寶。", "郎君玉樹臨風前，咀嚼青竹夜不眠。", "何須多羨崔與杜，諸郎努力青雲路。"]'),
('3a8e480e-356e-4c84-b265-9c569166fcf1','九月三日喜雨蓋不雨四十日矣','楊萬里','宋','宋诗','song-poetry','','[]','玉帝愁聞旱，雷公怒見鬚。',48,'全唐诗/poet.song.142000.json','["玉帝愁聞旱，雷公怒見鬚。", "搜龍無嚲處，倒海不遺餘。", "稻裏雲初活，蕎梢雪再鋪。", "老農啼又笑，欲去且安居。"]'),
('c4665df9-f8af-4241-8a2b-3bd6b24824af','謝蘇州史君張子儀尚書贈衣服送酒錢','楊萬里','宋','宋诗','song-poetry','','[]','香山老益窶，欲賣宅與田。',192,'全唐诗/poet.song.142000.json','["香山老益窶，欲賣宅與田。", "荆南贈春服，侍中送酒錢。", "何如韋蘇州，一日兼兩賢。", "酒錢隨春服，併至南溪邊。", "寄物已不輕，意更在物先。", "僕也拙生理，巧亦營不前。", "病廢非爲高，拋官餘十年。", "紙田蝸牛廬，縱賣誰作緣。", "故人豈云少，衮衮青雲端。", "王弘不可作，范叔空自寒。", "忽攬蘇州書，冷窗回春暄。", "急褫九月絺，徑追八酒仙。", "竹煙爲我喜，波月爲我妍。", "籬菊凍不花，一笑亦粲然。", "醉中化爲蝶，飛墮虎丘山。", "齊雲已在眼，忽然遠於天。"]'),
('bbb3c8b5-a61d-4a24-9b3e-b72ad3b5a7ed','九日招子上子西嘗新酒進退格','楊萬里','宋','宋诗','song-poetry','','[]','但令有酒對籬東，管得山名不是龍。',64,'全唐诗/poet.song.142000.json','["但令有酒對籬東，管得山名不是龍。", "榨裏潑醅迎節裏，雨中移菊自城中。", "多時不飲今辭醉，一笑相懽古罕逢。", "我輩明年當更健，不須子細看萸紅。"]'),
('f0b46198-9df7-47d9-a45b-3b41124a479f','九日菊未花','楊萬里','宋','宋诗','song-poetry','','[]','舊說黄楊厄閏年，今年併厄菊花天。',64,'全唐诗/poet.song.142000.json','["舊說黄楊厄閏年，今年併厄菊花天。", "但挼青蕊浮新酒，何必黄金鑄小錢。", "半醉嚼香霜月底，一枝却老鬢絲邊。", "阿誰會得開遲意，暗展重陽十月前。"]'),
('a5289338-352e-4be4-bb10-c5d20952bbfd','寒雞','楊萬里','宋','宋诗','song-poetry','','[]','寒雞睡著不知晨，多謝鐘聲喚起人。',32,'全唐诗/poet.song.142000.json','["寒雞睡著不知晨，多謝鐘聲喚起人。", "明曉莫教鐘睡著，被它雞笑不須嗔。"]'),
('e4fa8c45-2896-4cc8-b259-39e95aed12ff','南溪上種芙蓉','楊萬里','宋','宋诗','song-poetry','','[]','夾水芙容密密栽，緣溪斜立照溪開。',32,'全唐诗/poet.song.142000.json','["夾水芙容密密栽，緣溪斜立照溪開。", "放教十里紅將去，不盡溪流不要回。"]'),
('b5cc535f-4bbe-4031-8684-437d20ec0f27','曉看芙蓉','楊萬里','宋','宋诗','song-poetry','','[]','兩歲芙蓉無一枝，今年萬朶壓枝低。',64,'全唐诗/poet.song.142000.json','["兩歲芙蓉無一枝，今年萬朶壓枝低。", "半紅半白花都閙，非短非長樹斬齊。", "臨水釅粧新雨後，出牆背面曉風西。", "春英笑殺秋英淡，祗恐穠於桃李蹊。"]'),
('1a26be8c-a437-4342-a756-28d4fa6ea695','瑞慶節日同王式之詣雲際寺滿散','楊萬里','宋','宋诗','song-poetry','','[]','金剎深藏翠巘間，鐘聲吹下白雲端。',64,'全唐诗/poet.song.142000.json','["金剎深藏翠巘間，鐘聲吹下白雲端。", "誰知東浙能詩客，也到南溪祝聖山。", "重碧清池染衣溼，軟紅香霧襲人寒。", "祝君來歲千秋節，著脚含元鵷鷺班。"]'),
('d17f4799-ff1e-4d37-8eec-de63f1b4312c','寄王用之判府監簿','楊萬里','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','寅清堂上初相識，君如玉樹逢春碧。',131,'全唐诗/poet.song.142000.json','["寅清堂上初相識，君如玉樹逢春碧。", "滕王閣下重相從，君如天驥追秋風。", "九州四海王魯公，有子不減漢八龍。", "君才況是廊廟具，登庸衣鉢親分付。", "笋班小試雲霄步，州麾妙琢湖山句。", "君不見西京韋家父子間，阿成官職似阿賢。", "皇朝呂家也不惡，大申小申相後先。", "看君一武超韋呂，奄有龜蒙再封魯。"]'),
('b530509e-6352-48ec-b2e5-28cd2eea1031','王式之命劉秀才寫予真因署其上','楊萬里','宋','宋诗','song-poetry','','[]','浙水東兼浙水西，千巖萬壑總遨嬉。',32,'全唐诗/poet.song.142000.json','["浙水東兼浙水西，千巖萬壑總遨嬉。", "游山祗欠金華債，乘興今隨王式之。"]'),
('80946ee0-6424-4fc0-9a3d-1cc2f1944449','久雨妨於農收因訪子上有歎','楊萬里','宋','宋诗','song-poetry','','[]','君能過我意殊傾，我每看君脚便輕。',64,'全唐诗/poet.song.142000.json','["君能過我意殊傾，我每看君脚便輕。", "若爲泥塗斷還往，端令老病底心情。", "未霜楊柳秋猶碧，既雨芙蓉晚更明。", "旱歲嫌晴不嫌熟，今年教熟不教晴。"]'),
('03f0ef17-3f83-4d37-9088-1ea3c7fce521','題三老圖二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','旦奭行間著季真，黄冠不合附青雲。',32,'全唐诗/poet.song.142000.json','["旦奭行間著季真，黄冠不合附青雲。", "二南風裏君知麽，添箇委蛇退食人。"]'),
('2e406bf0-ad0f-4362-897d-bbc275444b41','題三老圖二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','劉郎寫照妙通神，三老圖成又一新。',32,'全唐诗/poet.song.142000.json','["劉郎寫照妙通神，三老圖成又一新。", "只道老韓同傳好，被人指點也愁人。"]'),
('93612eb9-bf8b-4c42-8c35-531d46974f64','南溪堰灘','楊萬里','宋','宋诗','song-poetry','','[]','爲愛溪流箭樣湍，戲拋亂石障清瀾。',64,'全唐诗/poet.song.142000.json','["爲愛溪流箭樣湍，戲拋亂石障清瀾。", "忽如亞父撞玉斗，又似仲尼鳴象環。", "整北移南教儘怒，從朝至午不知還。", "便饒灧澦三巴峽，也當龍門八節灘。"]'),
('87648293-5abe-4d1d-bd47-b476f8c970ba','至後入城道中雜興十首  其一','楊萬里','宋','宋诗','song-poetry','','[]','至後寒梅未苦繁，臘前暖蝶已偷還。',32,'全唐诗/poet.song.142000.json','["至後寒梅未苦繁，臘前暖蝶已偷還。", "隔林日射池光動，碎却池中倒影山。"]'),
('7868f178-e4b9-4e6d-a216-a23f6cc1e7b1','至後入城道中雜興十首  其二','楊萬里','宋','宋诗','song-poetry','','[]','大熟仍教得大晴，今年又是一昇平。',32,'全唐诗/poet.song.142000.json','["大熟仍教得大晴，今年又是一昇平。", "昇平不在簫韶裏，只在諸村打稻聲。"]'),
('ae3e0b52-e1ea-465f-8c1e-2d5ea24a96be','至後入城道中雜興十首  其三','楊萬里','宋','宋诗','song-poetry','','[]','問渠田父定無饑，却道官人那得知。',32,'全唐诗/poet.song.142000.json','["問渠田父定無饑，却道官人那得知。", "未送太倉新玉粒，敢先雲子滑流匙。"]'),
('a3921919-1d86-4c0c-8660-6e36ada3f54b','至後入城道中雜興十首  其四','楊萬里','宋','宋诗','song-poetry','','[]','畦蔬甘似卧沙羊，正爲新經幾夜霜。',32,'全唐诗/poet.song.142000.json','["畦蔬甘似卧沙羊，正爲新經幾夜霜。", "蘆菔過拳菘過膝，北風一路菜羹香。"]'),
('b74b4555-f2ba-4070-8d2a-290e962e6ee4','至後入城道中雜興十首  其五','楊萬里','宋','宋诗','song-poetry','','[]','長亭阿姥短亭翁，探借桃花作面紅。',32,'全唐诗/poet.song.142000.json','["長亭阿姥短亭翁，探借桃花作面紅。", "酒熟自嘗仍自賣，一生割據醉鄉中。"]'),
('415b3d96-e4d9-4e9b-8fc5-b0fa8d79263d','至後入城道中雜興十首  其六','楊萬里','宋','宋诗','song-poetry','','[]','豐年物物總欣驩，不但人和畜亦蕃。',32,'全唐诗/poet.song.142000.json','["豐年物物總欣驩，不但人和畜亦蕃。", "簸處金膚肥彘母，舂餘珠屑飽雞孫。"]'),
('a40a56af-1b62-4392-9759-16e8df646feb','至後入城道中雜興十首  其七','楊萬里','宋','宋诗','song-poetry','','[]','山路肩輿倦僕夫，家兄爲我酒頻沽。',32,'全唐诗/poet.song.142000.json','["山路肩輿倦僕夫，家兄爲我酒頻沽。", "賣薪人散知城近，啼柳烏忙覺日晡。"]'),
('7c8fbed2-30da-4be9-b6d7-b94f1cfc0667','至後入城道中雜興十首  其八','楊萬里','宋','宋诗','song-poetry','','[]','誰練苕花作雪茸，更將楓葉染猩紅。',32,'全唐诗/poet.song.142000.json','["誰練苕花作雪茸，更將楓葉染猩紅。", "姮娥不認推青女，青女又還推化工。"]'),
('b10f2dd6-6aa1-4994-819a-991fbd3f75cb','至後入城道中雜興十首  其九','楊萬里','宋','宋诗','song-poetry','','[]','忽見輕綃三兩重，橫遮萬丈翠屏風。',32,'全唐诗/poet.song.142000.json','["忽見輕綃三兩重，橫遮萬丈翠屏風。", "老夫細熨䰒鬆眼，却是青原隠霧中。"]'),
('2e85eb4a-7f24-4c67-88a5-31b0899016b1','至後入城道中雜興十首  其一○','楊萬里','宋','宋诗','song-poetry','','[]','春時宿處雨浪浪，至後重投張氏莊。',32,'全唐诗/poet.song.142000.json','["春時宿處雨浪浪，至後重投張氏莊。", "際晚烏銀何許買，夕陽特地戀寒窗。"]'),
('672ef402-5d12-4482-a140-d69ad11bd857','歐陽伯威挽詞','楊萬里','宋','宋诗','song-poetry','','[]','酒魄飛穿月，詩星流入脾。',48,'全唐诗/poet.song.142000.json','["酒魄飛穿月，詩星流入脾。", "豪來無一世，貧不上雙眉。", "瀘水奇唐律，香城賞楚辭。", "前身定東野，又得退之碑。"]'),
('78b43e20-9b7f-4fb0-baea-1582f155e120','題東江劉長元勤有齋','楊萬里','宋','宋诗','song-poetry','','[]','蠹簡三更寂，寒燈半點慳。',48,'全唐诗/poet.song.142000.json','["蠹簡三更寂，寒燈半點慳。", "不知門外雪，已失月中山。", "白璧非愁禹，黄金只鑄顔。", "時來漫拈出，掇取桂枝還。"]'),
('04b40e12-214f-47e0-a7ff-3bc85562cf51','謝永新大夫楊叔裕惠詩','楊萬里','宋','宋诗','song-poetry','','[]','今代吾家後子雲，新詩也解乞陳人。',64,'全唐诗/poet.song.142000.json','["今代吾家後子雲，新詩也解乞陳人。", "銀河波浪痕痕玉，花縣風光字字春。", "大勝十年燈火讀，更無半點簿書塵。", "鶚章塞得公車破，便合留渠立紫宸。"]'),
('5124c288-7d63-4301-a5ff-aa49e6afb818','寄袁起巖樞密賀新除仍謝送四縑并詩集兼懇求陳婿薦書二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','樞相身通貴，恩書意轉親。',48,'全唐诗/poet.song.142000.json','["樞相身通貴，恩書意轉親。", "四端香雪縠，一卷錦江春。", "公即專堂印，儂方理釣緡。", "五公今果六，詩讖也如神。"]'),
('bba77073-aca5-46d7-9802-1f563fca2934','寄袁起巖樞密賀新除仍謝送四縑并詩集兼懇求陳婿薦書二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','知己熙鴻化，陽和被九臯。',48,'全唐诗/poet.song.142000.json','["知己熙鴻化，陽和被九臯。", "自憐今老病，無分惱鈞陶。", "獨念東床客，猶沉左選曹。", "春風半張紙，立地作宜敖。"]'),
('15bf7d8a-3160-48d4-9774-fc83fbf9f9e5','再入城宿張氏莊早起進退格','楊萬里','宋','宋诗','song-poetry','','[]','夢覺月如晝，誤驚天欲明。',48,'全唐诗/poet.song.142000.json','["夢覺月如晝，誤驚天欲明。", "起吹松葉燼，自點臼花燈。", "山轎已十里，譙門才四更。", "脚根豈無火，鬚上也成冰。"]'),
('5621dc5a-4250-417b-b146-e123fb115ff2','與次公夜酌','楊萬里','宋','宋诗','song-poetry','','[]','湯盂深淺任橫斜，酒力微醺略減些。',32,'全唐诗/poet.song.142000.json','["湯盂深淺任橫斜，酒力微醺略減些。", "翦燭小童殊解事，不留燭燼却留花。"]'),
('c1197d90-b482-4a26-92b5-9671bb38d32d','不寐','楊萬里','宋','宋诗','song-poetry','','[]','脚底神通也自强，三更報我有飛霜。',32,'全唐诗/poet.song.142000.json','["脚底神通也自强，三更報我有飛霜。", "人言冬夜長如歲，不寐方知歲未長。"]'),
('e73d90dd-793a-4823-836a-7f3688151041','野望二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','也知口業欠消磨，造物嗔人奈口何。',32,'全唐诗/poet.song.142000.json','["也知口業欠消磨，造物嗔人奈口何。", "莫管詩人例寒餓，且容老子小婆娑。"]'),
('9e37c9a3-4d59-43d4-af9e-dd81c4294511','野望二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','野童擷菜疎移步，客子追程有底忙。',32,'全唐诗/poet.song.142000.json','["野童擷菜疎移步，客子追程有底忙。", "茅屋破時偏入畫，布衫洗了曬枯桑。"]'),
('50865c5b-4f6f-41f5-a3df-65e9372d21be','瑞香盛開呈益國公二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','近看丁香萬粒攢，遠看却與紫毬般。',64,'全唐诗/poet.song.142000.json','["近看丁香萬粒攢，遠看却與紫毬般。", "誰將玉膽薔薇水，新濯瓊膚錦綉襌。", "浄界薰脩爾芬馥，無人翦剔自團欒。", "下元前至上元後，省得龍沉與麝蘭。"]'),
('7d36fea1-d01c-48f0-8cf6-0d00de82c9d4','瑞香盛開呈益國公二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','針來大笋束仍攢，作麽開時色兩般。',64,'全唐诗/poet.song.142000.json','["針來大笋束仍攢，作麽開時色兩般。", "荀令金爐炷沉水，昭容紫袖襯中襌。", "同花異葉株株異，一種欒枝節節欒。", "雪裏寒香得三友，溪邊梅與畹邊蘭。"]'),
('b5869f97-8543-42c6-a9a8-6d583423f843','余處恭少師左相郇公挽辭三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','上聖臨三極，維師正百工。',48,'全唐诗/poet.song.142000.json','["上聖臨三極，維師正百工。", "忠清兩楊綰，誠一再溫公。", "衡嶽摧天柱，明堂失棟隆。", "初元得名相，不待卦非熊。"]'),
('0aef055f-3ea9-4f51-bb4c-9e69668dee4a','余處恭少師左相郇公挽辭三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','孝廟乘乾日，光宗宅震宮。',48,'全唐诗/poet.song.142000.json','["孝廟乘乾日，光宗宅震宮。", "夔龍池集鳳，黄綺翼高鴻。", "初政扶皇極，三朝抗大忠。", "朞年坐黄閣，萬古一清風。"]'),
('2620b612-3607-40d3-9ce1-986601977597','余處恭少師左相郇公挽辭三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','天下非無士，胸中自有人。',48,'全唐诗/poet.song.142000.json','["天下非無士，胸中自有人。", "如何初拜相，首薦一遺民。", "恩我丘山小，懷公骨肉親。", "白頭哭知己，東望獨傷神。"]'),
('094318ae-b0c0-4ce9-a131-8f37cb80d7f5','寄題龍泉項聖與盧溪書院','楊萬里','宋','宋诗','song-poetry','','[]','三顧先生得麟筆，付囑遺經誰第一。',96,'全唐诗/poet.song.142000.json','["三顧先生得麟筆，付囑遺經誰第一。", "獨將麟髓飯澹翁，項家阿英亦其乙。", "澹翁孤忠貫兩儀，阿英卓行徹九扉。", "旌門一日插天半，却把此筆傳阿宜。", "阿宜阿囝續弓冶，盧溪書院聲無價。", "不論當家與外人，不日天池看渾化。"]'),
('8e439f57-c3ef-436b-bfd5-cfd726f789fe','送西昌大夫趙嘉言上印赴闕','楊萬里','宋','宋诗','song-poetry','','[]','西昌難作自古傳，卓令趙令不作難。',66,'全唐诗/poet.song.142000.json','["西昌難作自古傳，卓令趙令不作難。", "二令來時民頓寬，二令去日官餘錢。", "從來美政人難繼，二君雙美今誰似。", "卓令已作中都官，趙令也合即綴卓令班。"]'),
('a0657190-ac47-4b3d-a1a1-b48ce2139515','山茶','楊萬里','宋','宋诗','song-poetry','','[]','樹子團團映碧岑，初看喚作木犀林。',64,'全唐诗/poet.song.142000.json','["樹子團團映碧岑，初看喚作木犀林。", "誰將金粟銀絲膾，簇飣朱紅菜椀心。", "春早橫招桃李妬，歲寒不受雪霜侵。", "題詩畢竟輸坡老，葉厚有稜花色深。"]'),
('79d6c023-d564-417b-8d88-ca7e239f2c83','夙興待旦二絕  其一','楊萬里','宋','宋诗','song-poetry','','[]','覺後難重睡，醉餘還獨醒。',24,'全唐诗/poet.song.142000.json','["覺後難重睡，醉餘還獨醒。", "東窗不肯白，挑盡一燈青。"]'),
('f2903c17-e20d-4527-bbdc-e6a726b92ee9','夙興待旦二絕  其二','楊萬里','宋','宋诗','song-poetry','','[]','村裏無銅漏，金鷄管殺更。',24,'全唐诗/poet.song.142000.json','["村裏無銅漏，金鷄管殺更。", "百聲猶未曉，却等第三聲。"]'),
('9e9e8962-72f4-4f67-905d-549d86e71357','癸亥上巳即事','楊萬里','宋','宋诗','song-poetry','','[]','怪底風光好，還當上巳辰。',48,'全唐诗/poet.song.142000.json','["怪底風光好，還當上巳辰。", "柳鶑樊子口，梁燕趙家身。", "花落春容瘦，陰濃夏意新。", "曬書仍焙藥，幽事也勞神。"]'),
('731bda85-6f69-4a4a-83db-a0329b8ca71a','登度雪臺觀金沙荼𧃲','楊萬里','宋','宋诗','song-poetry','','[]','金沙瓶子荼糜粟，一一尖紅映圜綠。',64,'全唐诗/poet.song.142000.json','["金沙瓶子荼糜粟，一一尖紅映圜綠。", "只銷三日雨和風，化作真珠堆錦褥。", "饒渠飛度雪前開，開了却吹香雪來。", "紅紅白白照天半，醉倚琱欄眼凌亂。"]'),
('5ea4429a-3ac4-4685-ae7e-b0636db6ee3c','古風敬餞吉州梁史君','楊萬里','宋','宋诗','song-poetry','','[]','南方儒先囿三山，山中豹蔚推伯鸞。',168,'全唐诗/poet.song.142000.json','["南方儒先囿三山，山中豹蔚推伯鸞。", "手拏枝桂下廣寒，身作德星南斗間。", "治行第一聞九關，再分魚書朱兩幡。", "豐湖夜敲坡老門，螺浦曉酌六一泉，露冕朞月惠化傳。", "青原改色白鷺妍，白叟鼓腹黄童顛。", "麴生打開禁酒國，雲子湊集移粟船。", "向來醉人號一瑞，如今醉人橫路眠。", "滿城米賤酒更賤，盡道人皆有一天。", "如何癖愛香火緣，三章叫閽覓散仙。", "定知不晚當賜環，金貂玉佩香案前。"]'),
('627ee82a-6c71-4b61-8b12-ca1f510ad29e','古風敬餞都運煥章雷吏部祗召入覲','楊萬里','宋','宋诗','song-poetry','','[]','高皇中興社稷臣，紫巖先生第一人。',176,'全唐诗/poet.song.142000.json','["高皇中興社稷臣，紫巖先生第一人。", "來從紫巖住紫蓋，鴻鈞轉作湘中春。", "風流人物被草木，香滿橘洲連嶽麓。", "一時賓客盛鄒枚，明月夜光和結綠。", "雷家夫子龍鳳章，優入其室升其堂。", "朱幡玉節徧南紀，錦帳綾衾推望郎。", "使星下照翼軫旁，西山南浦回風光。", "渠儂別有經世具，袖却兩手惟深藏。", "玉皇喚渠登廟廊，小却猶在持橐行。", "野人亦忝同門者，久挂衣冠卧林下。", "病身只合釣煙波，兒輩猶堪累甄冶。"]'),
('9d4bfb73-3aa8-4608-9652-de9416a7a275','子年劉郎寫余老貌求贊','楊萬里','宋','宋诗','song-poetry','','[]','鬢少梳欲無，髭短鑷更少。',24,'全唐诗/poet.song.142000.json','["鬢少梳欲無，髭短鑷更少。", "搔鬢祗撚髭，覓句何日了。"]'),
('b1a3338d-ecf1-48e6-b602-44420f76c793','暮行田間二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','布穀聲中日脚收，瘦藤叫我看西疇。',32,'全唐诗/poet.song.142000.json','["布穀聲中日脚收，瘦藤叫我看西疇。", "露珠走上青秧葉，不到梢頭便肯休。"]'),
('85828f93-307e-4981-aec8-01669f435bb6','暮行田間二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','水滿平田無處無，一張雪紙眼中鋪。',32,'全唐诗/poet.song.142000.json','["水滿平田無處無，一張雪紙眼中鋪。", "新秧亂插成井字，却道山農不解書。"]'),
('948c9382-8c8d-4302-b1f0-2f971e40390e','清曉趨郡早炊幽居延福寺','楊萬里','宋','宋诗','song-poetry','','[]','小轎欹還正，荒蹊細又紆。',48,'全唐诗/poet.song.142000.json','["小轎欹還正，荒蹊細又紆。", "危峰上金鏡，遠草亂瓊珠。", "霧外鐘聲近，花梢殿脊孤。", "老僧知我冷，展席傍紅爐。"]'),
('aa5f6b6d-f446-4402-8280-82f3d80c8636','午過烏東','楊萬里','宋','宋诗','song-poetry','','[]','險盡塗初坦，寒輕日向中。',48,'全唐诗/poet.song.142000.json','["險盡塗初坦，寒輕日向中。", "稻雲遲雨碧，蕎雪早霜紅。", "五日再行役，二年三鞠躬。", "只言棄官久，却與在官同。"]'),
('275a8f5b-df87-40e2-8498-7f9530ede963','晚宿小羅田四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','青林化作萬黄金，落日光寒色却深。',32,'全唐诗/poet.song.142000.json','["青林化作萬黄金，落日光寒色却深。", "仰看松梢數松子，不妨更與數松針。"]'),
('90b421a6-ab20-488a-b95f-9d539076ea87','晚宿小羅田四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','倒盡菰蒲折盡荷，芙蓉臨水恨無多。',32,'全唐诗/poet.song.142000.json','["倒盡菰蒲折盡荷，芙蓉臨水恨無多。", "一花却有兩花影，東卧斜陽西卧波。"]'),
('fb0fe98a-89ab-436f-9879-599a1f5ca104','晚宿小羅田四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','蕭灑低低屋，虛明小小窗。',24,'全唐诗/poet.song.142000.json','["蕭灑低低屋，虛明小小窗。", "客間那得許，窗外更寒江。"]'),
('e1e9fa8d-6c05-4b89-824a-6988b61ba336','晚宿小羅田四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','白酒聊三盞，青燈欲二更。',24,'全唐诗/poet.song.142000.json','["白酒聊三盞，青燈欲二更。", "倦來乘急睡，過了睡難成。"]'),
('01b7e262-98e5-40cd-aba9-55ceb2b64160','後一月再宿城外野店夙興入城謁益公二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','吹燈覽鏡又匆匆，烏帽新時白鬢空。',64,'全唐诗/poet.song.142000.json','["吹燈覽鏡又匆匆，烏帽新時白鬢空。", "殘月忙追曉星上，飛霜先到轎窗中。", "如何五鼓寒十倍，不肯半分饒一翁。", "到得火輪相暖熱，山霏特地碧曚曨。"]'),
('c2f0d550-0d5b-4cf8-9191-699408cb54d4','後一月再宿城外野店夙興入城謁益公二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','歸途未信欲斜陽，只怪行人影轉長。',64,'全唐诗/poet.song.142000.json','["歸途未信欲斜陽，只怪行人影轉長。", "松壽已高猶綠髮，楓年方少更紅裳。", "秋光便是天金谷，畫本偷歸我錦囊。", "只怨衝寒歎行役，青鞋布襪却芬香。"]'),
('8308c0e9-24d7-47ba-9f2e-ec0ad48f8be6','題胡季亨觀生亭二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','誰信秋霜臘雪中，雪中霜裏有春風。',32,'全唐诗/poet.song.142000.json','["誰信秋霜臘雪中，雪中霜裏有春風。", "菊花未了梅花發，休說桃花入嫩紅。"]'),
('8917222e-7c64-415b-b653-872bd847e645','題胡季亨觀生亭二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','漏泄春光有阿亨，一雙詩眼太乖生。',32,'全唐诗/poet.song.142000.json','["漏泄春光有阿亨，一雙詩眼太乖生。", "草根未響渠先覺，不待黄鸝第一聲。"]'),
('ca15ea8a-e94a-4c21-94f4-c9e28a937bd2','胡季亨贈集句古風效其體奉酬','楊萬里','宋','宋诗','song-poetry','','[]','秋氣集南磵，清風來故人。',108,'全唐诗/poet.song.142000.json','["秋氣集南磵，清風來故人。", "遺我一端綺，桃李不成春。", "大句斡元造，高詞媲皇墳。", "百衲收寸錦，一字買堪貧。", "苦恨鄰里間，良覿渺無因。", "今日是何朝，始聞扣柴荆。", "黄菊有佳色，寒水各依痕。", "且共歡此飲，重與細論文。", "何以報佳惠，山中有白雲。"]'),
('b5fc7c0d-a6b5-4fc3-8e0a-4a1340784b3d','十月久雨妨農收二十八日得霜遂晴喜而賦之','楊萬里','宋','宋诗','song-poetry','','[]','雨脚麻相似，禾頭耳欲生。',48,'全唐诗/poet.song.142000.json','["雨脚麻相似，禾頭耳欲生。", "風收白癡霧，霜作上牢晴。", "逗曉雙栖鵲，巡簷數喜聲。", "呼兒洗塵甑，忍餓待新秔。"]'),
('f4813548-d3e5-452e-9d09-1c6176447e22','早起','楊萬里','宋','宋诗','song-poetry','','[]','黄菊花繁依舊臞，牡丹葉落恰如枯。',32,'全唐诗/poet.song.142000.json','["黄菊花繁依舊臞，牡丹葉落恰如枯。", "霜中蚱蜢凍欲死，緊抱寒梢不放渠。"]'),
('6b34a775-9eb4-4cfc-91f2-b2a7aa66622e','蠅虎六言','楊萬里','宋','宋诗','song-poetry','','[]','長有青蠅入夢，初無白額負嵎。',28,'全唐诗/poet.song.142000.json','["長有青蠅入夢，初無白額負嵎。", "傳業羲皇網罟，齊名鬭穀於菟。"]'),
('02bf055a-9e9d-4cae-9c14-e0bad940b33c','進退格寄張功父姜堯章','楊萬里','宋','宋诗','song-poetry','','[]','尤蕭范陸四詩翁，此後誰當第一功。',64,'全唐诗/poet.song.142000.json','["尤蕭范陸四詩翁，此後誰當第一功。", "新拜南湖爲上將，更差白石作先鋒。", "可憐公等俱癡絕，不見詞人到老窮。", "謝遣管城儂已晚，酒泉端欲乞移封。"]'),
('29856ea8-46fc-4a20-baf7-52883cd2958a','寄題八桂張松卿義莊','楊萬里','宋','宋诗','song-poetry','','[]','張氏避氈裘，邢遷來桂州。',48,'全唐诗/poet.song.142000.json','["張氏避氈裘，邢遷來桂州。", "買田同族食，作計豈孫謀。", "公藝君今是，希文古罕儔。", "荆花再連理，萱草更千秋。"]'),
('69fd8601-9ef7-4670-9638-20d371f8d1ad','陳商卿挽辭','楊萬里','宋','宋诗','song-poetry','','[]','遠緒傳媯水，高風似太丘。',48,'全唐诗/poet.song.142000.json','["遠緒傳媯水，高風似太丘。", "萱堂魚躍雪，蘭砌鶚橫秋。", "杖屨疎金谷，鶑花冷玉舟。", "行看紫鸞紙，告第賁松楸。"]'),
('47f0cf80-3558-40f6-8764-95c64dbf2c0f','題曾世夫頤齋','楊萬里','宋','宋诗','song-poetry','','[]','吾友子曾子，滋蘭澗溪幽。',96,'全唐诗/poet.song.142000.json','["吾友子曾子，滋蘭澗溪幽。", "藥房動波底，韋編著床頭。", "夢吞六畫香，身從三聖游。", "上瞻岐山開，下聆雷聲收。", "告于閟靈龜，潜淵騎玉虯。", "食菲足自養，朶頤非所求。", "一朝浮洛書，綠字獻禹疇。", "分半啖虞翻，相視一笑休。"]'),
('780627e8-66a7-4b5d-a967-b1e3e38f4283','曉起','楊萬里','宋','宋诗','song-poetry','','[]','霜挾清寒凍殺人，袖中十指怯頭巾。',32,'全唐诗/poet.song.142000.json','["霜挾清寒凍殺人，袖中十指怯頭巾。", "金篦落地拾不得，却是穿窗曉日痕。"]'),
('c5595991-32cc-48fe-8ced-9a3bdbc6873c','日午','楊萬里','宋','宋诗','song-poetry','','[]','揭竿借日自烘衣，背立晴暄片子時。',32,'全唐诗/poet.song.142000.json','["揭竿借日自烘衣，背立晴暄片子時。", "雪後春生人未覺，弄絲蟢子獨先知。"]'),
('77bc5a2f-1385-4ea2-9fd1-4998f15b204e','賀胡守寺正禱雪響應','楊萬里','宋','宋诗','song-poetry','','[]','廬陵新事一奇絕，老農七年不識雪。',144,'全唐诗/poet.song.142000.json','["廬陵新事一奇絕，老農七年不識雪。", "史君領取六花來，一夜九天開玉闕。", "萬家鑄作銀樓臺，千峰琢出瓊崔嵬。", "頻歲魃兒祟䆉䅉，來秋雲子如芋魁。", "老夫與雪亦久別，滕六參儂求普說。", "爲渠拈此一瓣香，今身胡姓前身黄。", "只愁潁川歸廟堂，不愁寰宇無豐穰。", "東閣官梅應解語，綠毛么鳳仍能舞。", "合詞再拜壽史君，滿爲天花中玉醑。"]'),
('c8b4a780-0d31-4d9a-b0a3-b86cf767b826','十二月二十七日立春夜不寐','楊萬里','宋','宋诗','song-poetry','','[]','冬夜嫌長只望春，春宵又永更何言。',64,'全唐诗/poet.song.142000.json','["冬夜嫌長只望春，春宵又永更何言。", "睫梢强合終無睡，脚底相摩也不溫。", "竟夕松風聽到曉，忽明燈火看來昏。", "擁裯却起蒙頭坐，顧影真成一病猿。"]'),
('e780c0f9-9e7d-499e-9b3e-85a8de627906','送黄幾先司戶','楊萬里','宋','宋诗','song-poetry','','[]','吾友黄編修，用不究其挾。',96,'全唐诗/poet.song.142000.json','["吾友黄編修，用不究其挾。", "有子傳父書，潜心泣麟業。", "胸中石渠剩，筆底秋鷹捷。", "蟾兔贈一枝，衣鉢續四葉。", "不應千里來，乃欲一揖別。", "恰當新酒熟，幸與故人接。", "細酌且短檠，軟語更長鋏。", "去去謁九扉，天路看高躡。"]'),
('c5d13436-a742-4002-b841-c07b5479ea6d','寄題南昌尉廳思賢亭','楊萬里','宋','宋诗','song-poetry','','[]','有客栖霞外，無名涴黨中。',48,'全唐诗/poet.song.142000.json','["有客栖霞外，無名涴黨中。", "南州一高士，東漢獨清風。", "舊國已禾女，荒阡猶石翁。", "更煩吹笛魄，端爲洗榛叢。"]'),
('e7be6f79-0f94-4844-b562-0c35906e8f56','甲子初春即事六首  其一','楊萬里','宋','宋诗','song-poetry','','[]','老子燒香罷，蜂兒作隊來。',24,'全唐诗/poet.song.142000.json','["老子燒香罷，蜂兒作隊來。", "徘徊繞襟袖，將謂是花開。"]'),
('88dd8127-34cf-4572-8eac-5c6451170820','甲子初春即事六首  其二','楊萬里','宋','宋诗','song-poetry','','[]','臘去寒猶在，春來花未開。',24,'全唐诗/poet.song.142000.json','["臘去寒猶在，春來花未開。", "東風忽然到，放盡一園梅。"]'),
('12628421-4ffd-443b-bb12-9e8d6ccf19fb','甲子初春即事六首  其三','楊萬里','宋','宋诗','song-poetry','','[]','徑李渾穠白，山桃半淡紅。',24,'全唐诗/poet.song.142000.json','["徑李渾穠白，山桃半淡紅。", "杏花紅又白，非淡亦非穠。"]'),
('f960759e-db79-4991-ab36-7cc47694b349','甲子初春即事六首  其四','楊萬里','宋','宋诗','song-poetry','','[]','只有觀書樂，其如病眼何。',24,'全唐诗/poet.song.142000.json','["只有觀書樂，其如病眼何。", "但令吾意適，不必卷頭多。"]'),
('e648c691-d644-4bb5-a399-36abe9e6fd44','甲子初春即事六首  其五','楊萬里','宋','宋诗','song-poetry','','[]','驟暖如初夏，通身退裌衣。',24,'全唐诗/poet.song.142000.json','["驟暖如初夏，通身退裌衣。", "只言寒已去，却等五更歸。"]'),
('5a9e56e9-e20d-4ee2-9921-0183840a68c7','甲子初春即事六首  其六','楊萬里','宋','宋诗','song-poetry','','[]','人怨花遲發，天教暖早催。',24,'全唐诗/poet.song.142000.json','["人怨花遲發，天教暖早催。", "不知要催落，却道是催開。"]'),
('5bf81770-712c-4fe2-9f62-9dda7de3b3d9','二月十四日曉起看海棠八首  其一','楊萬里','宋','宋诗','song-poetry','','[]','過雨天猶濕，新晴日尚寒。',24,'全唐诗/poet.song.142000.json','["過雨天猶濕，新晴日尚寒。", "懸知曉粧好，破霧急來看。"]'),
('235b10ff-eb5a-4264-a25f-4f85571fe087','二月十四日曉起看海棠八首  其二','楊萬里','宋','宋诗','song-poetry','','[]','初日光殊薄，晴梢露正濃。',24,'全唐诗/poet.song.142000.json','["初日光殊薄，晴梢露正濃。", "真珠粧未穩，更著柳邊風。"]'),
('e847e9a5-4774-4a09-a0e3-2abb9a4f6e38','二月十四日曉起看海棠八首  其三','楊萬里','宋','宋诗','song-poetry','','[]','晚得看花訣，丁寧趁絕晨。',24,'全唐诗/poet.song.142000.json','["晚得看花訣，丁寧趁絕晨。", "乘他醉眠起，別是一精神。"]'),
('43f29288-5acb-4c5e-a6b2-c07b3e1c3cac','二月十四日曉起看海棠八首  其四','楊萬里','宋','宋诗','song-poetry','','[]','四面花光合，一身香霧紅。',24,'全唐诗/poet.song.142000.json','["四面花光合，一身香霧紅。", "忽從霞綺上，跳下錦城中。"]'),
('0beb5390-41f2-4671-a15f-98b4007dd318','二月十四日曉起看海棠八首  其五','楊萬里','宋','宋诗','song-poetry','','[]','花密無重數，看來眼轉迷。',24,'全唐诗/poet.song.142000.json','["花密無重數，看來眼轉迷。", "化爲花世界，忘却日東西。"]'),
('4c0b7cd1-05b6-45e2-8268-9a0903405a4a','二月十四日曉起看海棠八首  其六','楊萬里','宋','宋诗','song-poetry','','[]','外種百來樹，中安一小亭。',24,'全唐诗/poet.song.142000.json','["外種百來樹，中安一小亭。", "放眸紅未了，紅了是天青。"]'),
('4e5fc91f-3836-448c-b669-1f3808704501','二月十四日曉起看海棠八首  其七','楊萬里','宋','宋诗','song-poetry','','[]','老子侵星起，蜂兒先我忙。',24,'全唐诗/poet.song.142000.json','["老子侵星起，蜂兒先我忙。", "淵才無鼻孔，信口道無香。"]'),
('eba1edf8-1edc-4f55-aac8-f968d5f23055','二月十四日曉起看海棠八首  其八','楊萬里','宋','宋诗','song-poetry','','[]','除却牡丹了，海棠當亞元。',24,'全唐诗/poet.song.142000.json','["除却牡丹了，海棠當亞元。", "豔超紅白外，香在有無間。"]'),
('b9cf3da6-a691-434e-b9be-b0b3257ca13f','寄題袁機仲侍郎殿撰建溪北山四景 妙浄庵','楊萬里','宋','宋诗','song-poetry','','[]','韓子不肯佛，饒操苦出家。',24,'全唐诗/poet.song.142000.json','["韓子不肯佛，饒操苦出家。", "何如妙浄老，紫橐碧蓮花。"]'),
('b25ffef0-627c-42e7-b3e2-ff35813171fe','寄題袁機仲侍郎殿撰建溪北山四景 冰壺閣','楊萬里','宋','宋诗','song-poetry','','[]','竹國風世界，梅兄雪友朋。',24,'全唐诗/poet.song.142000.json','["竹國風世界，梅兄雪友朋。", "地清無可比，且道玉壺冰。"]'),
('dadb9ef6-95ac-4769-93ff-e76485453a8e','寄題袁機仲侍郎殿撰建溪北山四景 玉虹橋','楊萬里','宋','宋诗','song-poetry','','[]','銀河月外來，玉虹天上落。',24,'全唐诗/poet.song.142000.json','["銀河月外來，玉虹天上落。", "騎虹弄銀河，人間無箇樂。"]'),
('dec25535-3600-4e2d-9167-30a575de579d','寄題袁機仲侍郎殿撰建溪北山四景 抗雲亭','楊萬里','宋','宋诗','song-poetry','','[]','脚底一朶雲，乘之繞空碧。',24,'全唐诗/poet.song.142000.json','["脚底一朶雲，乘之繞空碧。", "前身王子喬，今代李太白。"]'),
('fc3d4424-c3d7-4d50-ab09-d5d382089252','題張季長少卿飾庵庵名取告詞云學足以自飾','楊萬里','宋','宋诗','song-poetry','','[]','吾友張飾庵，學到賁上白。',144,'全唐诗/poet.song.142000.json','["吾友張飾庵，學到賁上白。", "真賁初非文，至飾亦無色。", "君看瑄玉姿，豈借青黄飾。", "寶氣不自中，白虹貫空碧。", "飾庵隠岷嶺，英名震京國。", "魯論感鳳歎，春秋辯麟獲。", "孝廟聘丘園，有來校墳籍。", "光皇訪忠賢，再起貳卿棘。", "未應兩朝舊，不侍九重側。", "訓詞揭昭回，聖意深記憶。", "盍歸贊人文，小却猶講席。", "未要從子真，带月耕巖石。"]'),
('272fd673-9b85-40d5-9383-340e40c8d7aa','十山歌呈太守胡平一  其一','楊萬里','宋','宋诗','song-poetry','','[]','豺虎深交雁鶩行，到官管取汝無妨。',32,'全唐诗/poet.song.142000.json','["豺虎深交雁鶩行，到官管取汝無妨。", "只將剽劫爲喧閙，喝放歸來儘陸梁。"]'),
('13a34581-6dea-4ef9-9d52-12d10cab8489','十山歌呈太守胡平一  其二','楊萬里','宋','宋诗','song-poetry','','[]','羣盜常山蛇勢如，一偷捕獲十偷扶。',32,'全唐诗/poet.song.142000.json','["羣盜常山蛇勢如，一偷捕獲十偷扶。", "十偷行賂一偷免，百姓如何奈得渠。"]'),
('7c25ddbb-4290-4443-8dcc-10f1a6cfeeef','十山歌呈太守胡平一  其三','楊萬里','宋','宋诗','song-poetry','','[]','淦客前春荷一豬，城門賣得兩千餘。',32,'全唐诗/poet.song.142000.json','["淦客前春荷一豬，城門賣得兩千餘。", "明朝回到石斧嶺，連喫數刀今在無。"]'),
('15b520ef-1ae1-457b-bfd5-47434abf9786','十山歌呈太守胡平一  其四','楊萬里','宋','宋诗','song-poetry','','[]','說似行人且細聽，螺岡門外莫宵征。',32,'全唐诗/poet.song.142000.json','["說似行人且細聽，螺岡門外莫宵征。", "前頭石斧韓婆嶺，第一單身不要行。"]'),
('986dbab1-9899-4581-8499-af2d3594caf0','十山歌呈太守胡平一  其五','楊萬里','宋','宋诗','song-poetry','','[]','後趙前丁兩使君，羣偷望見總星奔。',32,'全唐诗/poet.song.142000.json','["後趙前丁兩使君，羣偷望見總星奔。", "後人却笑渠儂猛，仁及偷兒不及民。"]'),
('a3ae7b71-b9b4-4cd9-af6c-55b4d520d16c','十山歌呈太守胡平一  其六','楊萬里','宋','宋诗','song-poetry','','[]','王黄二盜久馳聲，手棒腰刀白晝行。',32,'全唐诗/poet.song.142000.json','["王黄二盜久馳聲，手棒腰刀白晝行。", "逢著村人持一物，喝令放下敢誰爭。"]'),
('295798a3-d95b-49d1-af16-c621eebf0267','十山歌呈太守胡平一  其七','楊萬里','宋','宋诗','song-poetry','','[]','近有村人带血論，使君親與驗傷痕。',32,'全唐诗/poet.song.142000.json','["近有村人带血論，使君親與驗傷痕。", "鶩行剛道非行劫，只是行人兩作喧。"]'),
('2202dcaf-dcfa-4ab9-b728-f33e5d30ff16','十山歌呈太守胡平一  其八','楊萬里','宋','宋诗','song-poetry','','[]','賢尹如何受吏謾，青天白日萬人看。',32,'全唐诗/poet.song.142000.json','["賢尹如何受吏謾，青天白日萬人看。", "忽然一展霹靂手，盡杖偷魁竄遠蠻。"]'),
('0f217e49-8cfe-4e85-9c05-81617dae9770','十山歌呈太守胡平一  其九','楊萬里','宋','宋诗','song-poetry','','[]','北門今早頓然清，懷璧操金儘夜行。',32,'全唐诗/poet.song.142000.json','["北門今早頓然清，懷璧操金儘夜行。", "却有一般可憐底，羣偷枉却費家兄。"]'),
('276ff180-eb1a-4547-bdd5-bc885c4e0721','十山歌呈太守胡平一  其一○','楊萬里','宋','宋诗','song-poetry','','[]','行人滿路喜歌呼，小盜何須辱廟謨。',32,'全唐诗/poet.song.142000.json','["行人滿路喜歌呼，小盜何須辱廟謨。", "早箇使君歸鼎軸，爲禽頡利繫單于。"]'),
('02fa6c87-1e21-424b-babe-69f860279cce','五月十六夜病中無聊起來步月五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','拋官放浪十三年，底事今年病嬾殘。',32,'全唐诗/poet.song.142000.json','["拋官放浪十三年，底事今年病嬾殘。", "舊健肯饒梅摘索，新羸翻羨竹平安。"]'),
('673b3602-2907-4065-b85f-b32ae6f45138','五月十六夜病中無聊起來步月五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','無求不必位三公，一飽何須祿萬鍾。',32,'全唐诗/poet.song.142000.json','["無求不必位三公，一飽何須祿萬鍾。", "只有人生安樂好，享它明月與清風。"]'),
('3f296102-5f5b-403f-a60b-685ea8835588','五月十六夜病中無聊起來步月五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','人睡方酣雞未知，起來叫轉月華西。',32,'全唐诗/poet.song.142000.json','["人睡方酣雞未知，起來叫轉月華西。", "南風吹落北斗柄，細數月中丹桂枝。"]'),
('747c7174-479a-4d98-8afd-2d313092df09','五月十六夜病中無聊起來步月五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','夏日雖炎夜却清，四更還更勝三更。',32,'全唐诗/poet.song.142000.json','["夏日雖炎夜却清，四更還更勝三更。", "露從玉兔鬚根落，風在銀河浪底生。"]'),
('6af12ef4-8324-4246-a6bd-01e4d2867d4f','五月十六夜病中無聊起來步月五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','道是月明星便稀，阿瞞此句未爲奇。',32,'全唐诗/poet.song.142000.json','["道是月明星便稀，阿瞞此句未爲奇。", "今宵斗柄也不見，一鏡孤光天四垂。"]'),
('5bb0f714-01a4-4df7-8c5e-40c11eaa9ee5','題李季章中書舍人石林堂','楊萬里','宋','宋诗','song-poetry','','[]','紫微仙人今太白，不愛好官愛奇石。',112,'全唐诗/poet.song.142000.json','["紫微仙人今太白，不愛好官愛奇石。", "頃從道山歸雪山，一葉漁船一橫笛。", "船過宣池月滿空，乘雲飛上九華峰。", "十指一掇九芙蓉，和月擎取歸船中。", "歸到雁湖秋水碧，萬斛酒船觴九客。", "蟇頤諸峰作不速，不待折簡登几席。", "儂與石兄殊不疎，問訊別來安穩無。"]'),
('64276d51-0ee0-48f9-92bd-5aef02923cea','與長孺共讀杜詩','楊萬里','宋','宋诗','song-poetry','','[]','病身兀兀腦岑岑，偶到兒曹文字林。',64,'全唐诗/poet.song.142000.json','["病身兀兀腦岑岑，偶到兒曹文字林。", "一卷杜詩揉欲爛，兩人齊讀味初深。", "斲肝枉却期千載，漏眼誰曾更再尋。", "筆底姦雄死猶毒，莫將饒舌泄渠心。"]'),
('7d14ea0b-ee61-4f21-87cb-29df0a67eeac','食蓮子三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','白玉蜂兒綠玉房，蜂房未綻已聞香。',32,'全唐诗/poet.song.142000.json','["白玉蜂兒綠玉房，蜂房未綻已聞香。", "蜂兒解醒詩人醉，一嚼清冰一嚥霜。"]'),
('8ffa4cc4-91c1-4937-b776-60d624d0a225','食蓮子三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','城中蓮子買將歸，未問嘗新早與遲。',32,'全唐诗/poet.song.142000.json','["城中蓮子買將歸，未問嘗新早與遲。", "偶憶湧金門外曉，畫船带露摘來時。"]'),
('ea02e345-e502-4c6e-9a18-07281ddfbc81','食蓮子三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','戢戢蜂兒出露房，未生翅股及鋒芒。',32,'全唐诗/poet.song.142000.json','["戢戢蜂兒出露房，未生翅股及鋒芒。", "丁寧莫遣它人剝，要染儂家十指香。"]'),
('9ac27dbf-42a2-4aa5-af6b-c55071d8d771','族人同諸友問疾二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','老無星事可營爲，政是長閑好病時。',64,'全唐诗/poet.song.142000.json','["老無星事可營爲，政是長閑好病時。", "兩脚倦行贏得坐，一生欠睡頓還伊。", "夢聞有客欣然起，兒道勤翁乃爾癡。", "抵掌縱談天亦笑，此身安否更曾知。"]'),
('49091173-248a-47dd-a6de-4831e086c062','族人同諸友問疾二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','摩詰沉痾未易排，文殊一問失妖災。',64,'全唐诗/poet.song.142000.json','["摩詰沉痾未易排，文殊一問失妖災。", "老夫何幸羣賢集，倒屣出迎雙眼開。", "語造極時全愈了，病知客去即重來。", "呼兒細揀新書策，體不佳時看一回。"]'),
('8356d74f-7d9b-4d9b-bfc5-fb401f7e31a5','病中復脚痛終日倦坐遣悶','楊萬里','宋','宋诗','song-poetry','','[]','滿眼生花雪滿顛，者稀又過四雙年。',64,'全唐诗/poet.song.142000.json','["滿眼生花雪滿顛，者稀又過四雙年。", "誰知病脚妨行步，只見端居道坐禪。", "墮扇几旁猶嬾拾，檢書窗下更能前。", "世人總羨飛仙侶，我羨行人便是仙。"]'),
('48f197c8-b023-4f7a-aa31-c2e1c242f541','六月二十四日病起喜雨聞鶑與大兒議秋凉一出游山三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','末伏將催中伏休，匆匆送夏又迎秋。',64,'全唐诗/poet.song.142000.json','["末伏將催中伏休，匆匆送夏又迎秋。", "暑中竹色風仍雨，病裏鶑聲喜破愁。", "大熟十年無此作，微生一飽更何求。", "急須剩踏蓮花麴，藥玉新船待拍浮。"]'),
('351808d2-6cb0-4e0e-94af-6afd86a99cb7','六月二十四日病起喜雨聞鶑與大兒議秋凉一出游山三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','病勢初來敵頗强，排山倒海也難當。',64,'全唐诗/poet.song.142000.json','["病勢初來敵頗强，排山倒海也難當。", "老夫笑把東西玉，豎子難藏上下肓。", "酒陣時聞報三捷，詩壇元不費單槍。", "夜來夢入清涼國，風月冰人別是鄉。"]'),
('1bf528b0-4b5c-4e57-a504-ff071f76c8b4','六月二十四日病起喜雨聞鶑與大兒議秋凉一出游山三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','暑氣朝來掃地空，南風畢竟讓西風。',64,'全唐诗/poet.song.142000.json','["暑氣朝來掃地空，南風畢竟讓西風。", "秋生楚尾吳頭外，涼殺天涯地角中。", "萬疊山連千澗水，雙行纏伴一郫筒。", "初程道是窮忙著，且宿東山東復東。"]'),
('1d6df288-23e8-4fd0-958d-684c01300d17','雨後曉起看山','楊萬里','宋','宋诗','song-poetry','','[]','晨起出蓬戶，換却隔水峰。',108,'全唐诗/poet.song.142000.json','["晨起出蓬戶，換却隔水峰。", "細看只舊山，色與昨不同。", "雖經夜來雨，末必有許功。", "雲師挈衆巉，置在藍水中。", "沙土俱綠浄，草樹添青葱。", "不然近秋衰，那得還春容。", "此意殊不淺，要將調詩翁。", "判斷索一語，可惜語不工。", "正使語工著，不如山色濃。"]'),
('33731989-a4ed-4e1f-9f29-25268fb4f008','病中七夕','楊萬里','宋','宋诗','song-poetry','','[]','良辰美景底須來，苦惱如山正滿懷。',64,'全唐诗/poet.song.142000.json','["良辰美景底須來，苦惱如山正滿懷。", "蟬度清歌侑溪柳，花吹黄雪灑官槐。", "新秋風物俱堪賞，久病心情自不佳。", "說與兒童休乞巧，老夫守拙尚多乖。"]'),
('7115fbe0-4db2-42dc-bafa-f61ee8cb86d0','秋熱','楊萬里','宋','宋诗','song-poetry','','[]','今年秋熱倍常年，更住西峰落照村。',32,'全唐诗/poet.song.142000.json','["今年秋熱倍常年，更住西峰落照村。", "最是櫻桃梢上日，裴回不落等黄昏。"]'),
('4db9a77f-d413-4537-bb96-410ea3beab1d','食菱','楊萬里','宋','宋诗','song-poetry','','[]','雞頭吾弟藕吾兄，頭角嶄然也不爭。',64,'全唐诗/poet.song.142000.json','["雞頭吾弟藕吾兄，頭角嶄然也不爭。", "白璧中藏煙水晦，紅裳左袒雪花明。", "一生子木非知己，千載靈均是主盟。", "每到炎官張火傘，西山未當聖之清。"]'),
('a3890d08-db01-4921-82d8-2da29023c472','晚酌','楊萬里','宋','宋诗','song-poetry','','[]','暑天寒果飣來餿，水果清於木果休。',64,'全唐诗/poet.song.142000.json','["暑天寒果飣來餿，水果清於木果休。", "蓮入新秋何便瘦，菱沉到底竟能浮。", "山泉釀酒香仍冽，野蔌堆盤爽更幽。", "方丈食前非不愛，風蟬一腹飽詩愁。"]'),
('c93a02be-5ad1-4283-a39c-6dc11b14b774','七夕後一夜月中露坐二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','火雲散作鬰金雲，簷際移床偃病身。',64,'全唐诗/poet.song.142000.json','["火雲散作鬰金雲，簷際移床偃病身。", "古井石崖新汲水，花洲苔砌蕩晴塵。", "風纔小動即停吹，竹自不涼那及人。", "獨感今宵上弦月，桂梢分露滴紗巾。"]'),
('7d85af4e-5d38-497f-989e-f29877e7166b','七夕後一夜月中露坐二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','今古詩人愛月圓，未堪商略玉嬋娟。',64,'全唐诗/poet.song.142000.json','["今古詩人愛月圓，未堪商略玉嬋娟。", "脩眉半璧各自好，團鏡磨鎌俱可憐。", "一夜一般新樣出，幾回幾換爲人妍。", "教渠也學金鴉扇，未必清光直一錢。"]'),
('427a7bac-5141-4129-ab7e-a603d423c6be','夜熱不寐曉起步溪上','楊萬里','宋','宋诗','song-poetry','','[]','夜氣積到曉，微涼方滿川。',48,'全唐诗/poet.song.142000.json','["夜氣積到曉，微涼方滿川。", "老夫乘早起，落月正娟然。", "拄杖丫疲檐，行人憩痛肩。", "勞生誰獨免，客路最堪憐。"]'),
('45084ba8-c68a-4086-aa68-69a4819f3231','寄題趙漕祕閣東山堂','楊萬里','宋','宋诗','song-poetry','','[]','阿旦東山著乾坤，十雨世界三登村。',144,'全唐诗/poet.song.142000.json','["阿旦東山著乾坤，十雨世界三登村。", "阿安東山著一身，白雲保社明月鄰。", "此山祗合館此客，千載阿誰敢爭席。", "趙侯玉立隆準孫，洗空凡馬追古人。", "千山萬水略行徧，一錐卓住東洋岸。", "東洋山麓東復東，築堂折簡招兩公。", "倒提北斗酌銀漢，靈山作樽江作鍾。", "浩歌小袖經綸手，笑與兩公舉天酒。", "東山今屬趙家莊，敬請兩公遷別鄉。"]'),
('dc2a647f-2670-414a-9425-eac092707428','送吉州解魁左人傑詣太常','楊萬里','宋','宋诗','song-poetry','','[]','高皇一馬化龍日，臨軒策士誰第一。',96,'全唐诗/poet.song.142000.json','["高皇一馬化龍日，臨軒策士誰第一。", "玉山山下汪端明，年財十八第一人。", "聖上來年集英殿，黄繖中央橫玉案。", "何人再續老尚書，禾水左家千里駒。", "春秋三傳貯胸臆，買紙待傳晁董策。", "君才盍與汪相先，君年更少汪兩年。"]'),
('0d37eb6e-7650-4d15-bb10-b364fb73a166','送左元規三詣太常','楊萬里','宋','宋诗','song-poetry','','[]','晉侯三駕楚莫爭，薛侯三箭天山平。',64,'全唐诗/poet.song.142000.json','["晉侯三駕楚莫爭，薛侯三箭天山平。", "江西今代再丘明，親到杏壇授麟經。", "筆陣獨掃萬人軍，兩魁槐花再薦名。", "來年蘭省與集英，三元不數馮家京。"]'),
('dca02435-c957-49c1-89e8-d33673b894b0','送廬陵宰趙材老','楊萬里','宋','宋诗','song-poetry','','[]','趙侯龍種秀天潢，金玉肝脾錦繡腸。',64,'全唐诗/poet.song.142000.json','["趙侯龍種秀天潢，金玉肝脾錦繡腸。", "未復九人黄閣相，猶堪三字紫微郎。", "饑餐蘭菊枝枝月，醉灑雲煙句句霜。", "誰與邦民頌遺愛，老夫端欲續甘棠。"]'),
('45af37d5-dc06-41cc-8dc2-2322a8f2d8c2','送項聖與詣太常','楊萬里','宋','宋诗','song-poetry','','[]','盧溪書院一番新，千里學子來如雲。',96,'全唐诗/poet.song.142000.json','["盧溪書院一番新，千里學子來如雲。", "天教書院名日起，速化先從主人始。", "主人主盟爲阿誰，楚漢名家今項斯。", "胸中五車載書卷，筆端三峽傾冰硯。", "魯秉周禮說一經，有司把燭題秋薦。", "鵠袍詣闕柳袍歸，來年書院更光輝。"]'),
('85b986b1-473f-4017-9c26-5f60a5f2df12','淋疾復作醫云忌文字勞心曉起自警二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','半似枯禪半似癡，也無何慮與何思。',32,'全唐诗/poet.song.142000.json','["半似枯禪半似癡，也無何慮與何思。", "偶看清曉雙雙蝶，飛徧黄花一一枝。"]'),
('69bb364f-8da9-41af-a330-f941f78b8841','淋疾復作醫云忌文字勞心曉起自警二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','荒耽詩句枉勞心，懺悔鶑花罷苦吟。',32,'全唐诗/poet.song.142000.json','["荒耽詩句枉勞心，懺悔鶑花罷苦吟。", "也不欠渠陶謝債，夜來夢裏又相尋。"]'),
('a25045a1-5878-4464-97fb-523eca583130','題朱伯勤千峰紫翠樓二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','秀嶺西頭鳳嶺東，周遭略數一千峰。',32,'全唐诗/poet.song.142000.json','["秀嶺西頭鳳嶺東，周遭略數一千峰。", "商量沒頓新樓處，頓著穠藍釅紫中。"]'),
('614e0711-b690-4324-bc21-834bd67645bd','題朱伯勤千峰紫翠樓二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一色千峰翠作圍，忽然齊換紫綃衣。',32,'全唐诗/poet.song.142000.json','["一色千峰翠作圍，忽然齊換紫綃衣。", "客來欲識樓中景，祇等金鴉浴海時。"]'),
('cdf0573c-681b-4b40-abc4-f5f19d2b679e','易允升畫像贊','楊萬里','宋','宋诗','song-poetry','','[]','疎髯撚欲無，短鬢搔已秃。',24,'全唐诗/poet.song.142000.json','["疎髯撚欲無，短鬢搔已秃。", "定知得句來，暗喜見眉目。"]'),
('e9be1d89-4934-46ee-84f7-b28d8d0093a4','嚴陵决曹易允升自官下遣騎歸寫予老醜因題其額','楊萬里','宋','宋诗','song-poetry','','[]','玉泉半潭冰，釣臺萬壑雪。',24,'全唐诗/poet.song.142000.json','["玉泉半潭冰，釣臺萬壑雪。", "汝往訪客星，剩挾一磨衲。"]'),
('ced27010-4597-4211-8aba-72940610c880','又自贊','楊萬里','宋','宋诗','song-poetry','','[]','清風索我吟，明月勸我飲。',24,'全唐诗/poet.song.142000.json','["清風索我吟，明月勸我飲。", "醉倒落花前，天地即衾枕。"]'),
('a1c0bd9f-2083-4221-abf8-c023251d595e','寄題永新昊天觀賀知宮方外軒','楊萬里','宋','宋诗','song-poetry','','[]','君家祕監唐詩客，飲中八仙渠第一。',96,'全唐诗/poet.song.142000.json','["君家祕監唐詩客，飲中八仙渠第一。", "君家水部晉仙真，曾拜東封玉路塵。", "祗今孫子方外士，羽衣霞佩雲爲袂。", "月下緱山吹鳳笙，霧裏華陽割龍耳。", "何當踞龜食蛤蜊，大嚼碧藕嬉瑶池。", "若見君家兩仙伯，爲儂寄聲好將息。"]'),
('5bcc14f1-2715-4429-b27f-2882353d4fd6','寄題萬安蕭和卿雲岡書院','楊萬里','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','君不見南軒先生以道鳴，嶽麓書院陶諸生。',86,'全唐诗/poet.song.142000.json','["君不見南軒先生以道鳴，嶽麓書院陶諸生。", "君不見晦庵先生妙經學，廬山書院榜白鹿。", "吾鄉蕭君八葉孫，雲岡築齋高入雲。", "芝蘭玉樹爭績文，江湖鵠袍爭駿奔。", "願師朱張兩先生，駟馬高蓋塞里門。"]'),
('cc2ccb6b-c032-46f2-ae23-bb32f0f6411e','題王晉輔專春亭','楊萬里','宋','宋诗','song-poetry','','[]','向來王家癖於馬，今來王家癖於花。',96,'全唐诗/poet.song.142000.json','["向來王家癖於馬，今來王家癖於花。", "洛陽城裏花如海，一半移取來君家。", "此花就中最穠麗，姚家黄兼魏家紫。", "花王更有王中王，看却姚魏千花降。", "一春好處君知否，上巳前頭寒食後。", "千花不用妬渠伊，此外春光更屬誰。"]'),
('12cdefc4-c1cf-4395-b759-d1a0117b6c3c','題王晉輔桂堂','楊萬里','宋','宋诗','song-poetry','','[]','諸天別有金色界，金粟如來更奇怪。',80,'全唐诗/poet.song.142000.json','["諸天別有金色界，金粟如來更奇怪。", "玉露洗面晞金風，黄雲迎下月姊宮。", "未與羣芳較顔色，寒香世界誰較得。", "一箇世界一粟中，萬粟世界香無窮。", "詩人夢入廣寒殿，香殺詩人天不管。"]'),
('20dbaaaa-08b0-4fd5-b49b-b1a8e27f2df7','贈臨川嚴泰伯秀才','楊萬里','宋','宋诗','song-poetry','','[]','臨汝嚴夫子，搘筇扣敝廬。',48,'全唐诗/poet.song.142000.json','["臨汝嚴夫子，搘筇扣敝廬。", "文如漆園壯，人似客星孤。", "善相遺驎瘦，深參得腹腴。", "行看最先進，辨論詘諸儒。"]'),
('7092fa40-1bda-46e7-be62-a576b3cb1674','送羅季周主簿之官八桂','楊萬里','宋','宋诗','song-poetry','','[]','憶昔相從夜誦時，子垂兩髧我初髭。',64,'全唐诗/poet.song.142000.json','["憶昔相從夜誦時，子垂兩髧我初髭。", "梧桐葉落猶無睡，桃李春歸總不知。", "我已懸車老巖壑，子方斂板走階墀。", "莫嫌衰病人皆棄，桂嶺梅花寄一枝。"]'),
('87466380-488e-47ec-9b7f-0dd2d35904c0','乙丑改元開禧元日','楊萬里','宋','宋诗','song-poetry','','[]','開禧元祀更元正，宿雨新收放曉晴。',64,'全唐诗/poet.song.142000.json','["開禧元祀更元正，宿雨新收放曉晴。", "夜半梅花添一歲，夢中爆竹報殘更。", "方知人喜天亦喜，作麽鐘鳴雞未鳴。", "老子年齡君莫問，屠蘇飲了更無兄。"]'),
('b67bbc54-1c21-4cb1-b251-0029d81a0c58','立春日','楊萬里','宋','宋诗','song-poetry','','[]','何處新春好，深山處士家。',24,'全唐诗/poet.song.142000.json','["何處新春好，深山處士家。", "風光先著柳，日色款催花。"]'),
('aac13835-1a9d-4880-a614-6b40f4985310','寄題鄒有常愛蓮亭','楊萬里','宋','宋诗','song-poetry','','[]','道鄉先生有族子，卜築富川弄江水。',64,'全唐诗/poet.song.142000.json','["道鄉先生有族子，卜築富川弄江水。", "更穿兩沼磨碧銅，分種芙蕖了秋事。", "一沼花白一沼紅，新亭恰當紅白中。", "此花不與千花同，吹香別是濂溪風。"]'),
('daf3e926-c3f9-4756-a4bd-45470e6caef7','題分宜李少度燕谷','楊萬里','宋','宋诗','song-poetry','','[]','君不見向來吹律談天衍，能令寒谷回春暖。',102,'全唐诗/poet.song.142000.json','["君不見向來吹律談天衍，能令寒谷回春暖。", "君不見祗今桂山謝艮齋，能回燕谷爲春臺。", "謫仙耳孫有仙骨，家傳謫仙好風月。", "斸開別墅一谷中，管領春光醉煙雪。", "艮齋作記印此山，山與主人千載傳。", "谷中花柳莫放過，乞取風月三千篇。"]'),
('98527472-aa0a-48ea-83a1-1f57082dd6d5','答胡伯圜贈詩','楊萬里','宋','宋诗','song-poetry','','[]','澹老郎君阿永賢，渥漥財駕折金鞭。',64,'全唐诗/poet.song.142000.json','["澹老郎君阿永賢，渥漥財駕折金鞭。", "只今兩子似連璧，一建雙旌開二天。", "白馬將軍震交阯，青錢學士即甘泉。", "弟兄蕙茂仍蘭發，頓有機雲在眼前。"]'),
('d1dff136-3edb-43ec-88a0-b95cdfaac462','答胡仲方贈詩','楊萬里','宋','宋诗','song-poetry','','[]','疇昔昭王渡楚江，得萍斗大嚼甘芳。',64,'全唐诗/poet.song.142000.json','["疇昔昭王渡楚江，得萍斗大嚼甘芳。", "因君黄綬作此縣，問古青蘋何處鄉。", "民樂弦歌愛言偃，天將桃李醉河陽。", "望郎舊說爲邑宰，邑宰今看爲望郎。"]'),
('28b2ac58-b58c-4b4d-91ac-74874194e8d5','病中春雨聞東園花盛','楊萬里','宋','宋诗','song-poetry','','[]','萬類欣欣一老悲，物華豈是不佳時。',64,'全唐诗/poet.song.142000.json','["萬類欣欣一老悲，物華豈是不佳時。", "病夫自與春無分，好景非於我獨遺。", "花底報來開已閙，雨中過了更曾知。", "風光九十今强半，又約芳菲隔歲期。"]'),
('aef905dc-c208-448a-98aa-f2019a31e4e2','雨霽看東園桃李行溪上進退格','楊萬里','宋','宋诗','song-poetry','','[]','藥裹關心正腹煩，强排孤悶到東園。',64,'全唐诗/poet.song.142000.json','["藥裹關心正腹煩，强排孤悶到東園。", "行穿一一三三徑，來往紅紅白白間。", "繞樹仰看渾不見，隔溪回望不勝繁。", "村村桃李家家柳，脚力酸時坐看山。"]'),
('0045a1e3-cef3-4bcd-bea1-d1441a8ffca7','春盡夜坐三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','春光草草病中休，病眼逢春道是秋。',32,'全唐诗/poet.song.142000.json','["春光草草病中休，病眼逢春道是秋。", "祗有青燈憐此老，伴人無睡照人愁。"]'),
('c1a5ffe0-523b-41f6-ab8f-d6a1bb691e4f','春盡夜坐三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','疾痛呼天天豈知，知而不管亦何爲。',32,'全唐诗/poet.song.142000.json','["疾痛呼天天豈知，知而不管亦何爲。", "偶拈白傅長慶集，又得驩欣片子時。"]'),
('9667ef01-2ac2-41a1-b8bb-8df343875fce','春盡夜坐三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','病夫說病訴旁人，它自開眉我自顰。',32,'全唐诗/poet.song.143000.json','["病夫說病訴旁人，它自開眉我自顰。", "後有病夫看病句，不須告訴亦沾巾。"]'),
('25f1dc4c-14d7-4a36-b9eb-f9111688f74b','去歲四月得淋疾今又四月病猶未愈','楊萬里','宋','宋诗','song-poetry','','[]','去歲四月病，如今一歲來。',48,'全唐诗/poet.song.143000.json','["去歲四月病，如今一歲來。", "越吟三百日，涼劑二千杯。", "極痛過於割，通身總是災。", "花時久斷酒，紅藥爲誰開。"]'),
('5bb1903d-fafc-4f2e-b550-0b798fc43515','自遣','楊萬里','宋','宋诗','song-poetry','','[]','莫將一病苦憂煎，山尚能游石可眠。',32,'全唐诗/poet.song.143000.json','["莫將一病苦憂煎，山尚能游石可眠。", "匹似病風兼病脚，老夫猶是地行仙。"]'),
('d2eddd2a-79ed-4da7-993c-e47e272e86c5','久病小愈雨中端午試筆四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','病較欣逢五五辰，宮衣忽憶拜天恩。',32,'全唐诗/poet.song.143000.json','["病較欣逢五五辰，宮衣忽憶拜天恩。", "舊時疊雪含風眼，今看空山雨點痕。"]'),
('9d68f2df-6e96-405c-b99d-59e2ef26138f','久病小愈雨中端午試筆四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','愛與陳玄酷作緣，餘波染指黑斕斑。',32,'全唐诗/poet.song.143000.json','["愛與陳玄酷作緣，餘波染指黑斕斑。", "呼童汲水無來底，自掬垂簷一滴慳。"]'),
('439131a4-a8de-4ab9-b80d-cebbd10d6d2a','久病小愈雨中端午試筆四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','春去無花可得攀，石榴不豔却明鮮。',32,'全唐诗/poet.song.143000.json','["春去無花可得攀，石榴不豔却明鮮。", "昨朝花發今朝落，留得梢頭一蔕看。"]'),
('f9f6839b-8326-4b40-865d-ca8da5a9b719','久病小愈雨中端午試筆四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','月季元來插得成，瓶中花落葉猶青。',32,'全唐诗/poet.song.143000.json','["月季元來插得成，瓶中花落葉猶青。", "試將插向蒼苔砌，小朶忽開雙眼明。"]'),
('07d5c245-c41e-4c47-a265-550e38f552ad','送吉州太守胡平一寺正赴召','楊萬里','宋','宋诗','song-poetry','','[]','憶昔乾道游璧水，君爲秀孝儂博士。',160,'全唐诗/poet.song.143000.json','["憶昔乾道游璧水，君爲秀孝儂博士。", "逮今嘉泰歸青原，儂爲州民君刺史。", "人生離合風中雲，白髮相逢有幾人。", "與君相逢又相別，不待折柳眉先顰。", "如君豈弟民父母，春風風人夏雨雨。", "忽然一夜飛秋霜，驚殺雁鶩兼豺狼。", "政聲無翼到天上，玉皇詔君登廟廊。", "郎星卿月小借路，金華玉堂即高步。", "中興賢關育鳳麟，向來未有秉鴻鈞。", "祗今丞相破荒了，第一衣鉢當傳君。"]'),
('17858df4-a071-4d92-94d0-f8125ec0ac2d','病起覽鏡二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','病起長新骨，居然非舊容。',48,'全唐诗/poet.song.143000.json','["病起長新骨，居然非舊容。", "眼添佩環带，腰減採花蜂。", "對面不相識，何人忽此逢。", "吾身無定在，更要問窮通。"]'),
('d4a3e969-675c-4c6e-8175-a33a1ca89f8a','病起覽鏡二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','覽鏡忽自問，何方一病翁。',48,'全唐诗/poet.song.143000.json','["覽鏡忽自問，何方一病翁。", "生涯管城外，本貫醉鄉中。", "筆硯今都廢，尊罍久屢空。", "又將數莖雪，顦顇見西風。"]'),
('deaeb15f-dc2a-459c-8940-009f04cce1f5','病中感秋','楊萬里','宋','宋诗','song-poetry','','[]','病中一刻抵三秋，況見西風再樹頭。',64,'全唐诗/poet.song.143000.json','["病中一刻抵三秋，況見西風再樹頭。", "老去能禁幾回病，秋來不爲別人愁。", "書帷夢覺疑僧榻，竹戶涼侵似客舟。", "壽外康寧方是福，不然徒壽不須休。"]'),
('faf7eb5b-fada-4ef9-b808-1b607eb4923d','秋衣','楊萬里','宋','宋诗','song-poetry','','[]','晨興換新衣，視身忽潜愕。',120,'全唐诗/poet.song.143000.json','["晨興換新衣，視身忽潜愕。", "腹皮皺百摺，髀肉寬一握。", "沈痾兩年餘，衰體半標落。", "且留宿塵垢，莫遣新澡濯。", "未澡體尚肥，既濯肌轉削。", "無髮已是僧，有骨不如鶴。", "明年方八十，似覺九十著。", "寡食幸自清，辟穀底須學。", "便可作飛仙，御風上雲幕。", "如何肥瘠想，猶有秋衣作。"]'),
('5ade74b0-3abe-4841-b43d-71b082f3bc67','夜讀詩卷','楊萬里','宋','宋诗','song-poetry','','[]','幽屏元無恨，清愁不自任。',48,'全唐诗/poet.song.143000.json','["幽屏元無恨，清愁不自任。", "兩窗兩橫卷，一讀一沾襟。", "祗有三更月，知予萬古心。", "病來謝杯杓，吟罷重長吟。"]'),
('6c403ec5-8878-4632-9e4e-b55a18833258','病中止酒','楊萬里','宋','宋诗','song-poetry','','[]','平生萬事輕，惟以酒自娛。',144,'全唐诗/poet.song.143000.json','["平生萬事輕，惟以酒自娛。", "當其愛酒時，一日不可無。", "老來因屬疾，不飲五月餘。", "客飲我不羨，而況逢麴車。", "見杯不思斟，見樽不思酤。", "終日但清坐，此心長泊如。", "只悟世人情，逐物非一途。", "仕者嫮貂蟬，貨者珍金珠。", "賜泰嗤原貧，由勇誚孔迂。", "何物真樂憂，何人定巧愚。", "病後得反身，曠然同太虛。", "其餘君莫問，麴生尚可疎。"]'),
('4a81b8b9-8bb6-4f4e-9a80-cd750380eaed','病中喜雨呈李吉州','楊萬里','宋','宋诗','song-poetry','','[]','兩日炎暉烈未收，連宵甘澍沛如流。',64,'全唐诗/poet.song.143000.json','["兩日炎暉烈未收，連宵甘澍沛如流。", "大田今日非昨日，多稼新秋賽舊秋。", "涼氣隔簾深亦透，香煙穿袖散難留。", "史君小試爲霖手，便作江西第一州。"]'),
('1426c1cd-dfd9-4efe-914e-3633d9fa5d45','送戴良輔藥者歸城郛  其一','楊萬里','宋','宋诗','song-poetry','','[]','君欲問淋疾，便是法外刑。',56,'全唐诗/poet.song.143000.json','["君欲問淋疾，便是法外刑。", "刲剔備百毒，更以虐焰烹。", "玉皇夜半敕六丁，押差戴君爲藥丞。", "倒囊刺手探玉札，一洗愁肺冰雪清。"]'),
('c8e4109f-f83f-43db-b3d3-995316814510','送戴良輔藥者歸城郛  其二','楊萬里','宋','宋诗','song-poetry','','[]','一生百病都好去，不但膏肓驅二豎。',32,'全唐诗/poet.song.143000.json','["一生百病都好去，不但膏肓驅二豎。", "寄言仲景與安常，古今何代無醫王。"]'),
('443c6fbb-4863-4244-9c82-d74c9d1b83c4','寄題張仲寅甘老堂','楊萬里','宋','宋诗','song-poetry','','[]','屏山十論抉聖心，甘老十論刮古今。',114,'全唐诗/poet.song.143000.json','["屏山十論抉聖心，甘老十論刮古今。", "古今刮得都見髓，持獻玉工逢刖趾。", "玉皇左相華陽封，上與阿旦雙周公。", "薦渠金門可登仕，金門送渠外臺試。", "渠儂掉頭不肯行，有雪可釣月可耕。", "恩山紫蕨椽來大，恩江白魚船樣箇。", "綠蓑青篛霞上卧，不知畢逋明眎東西過。"]'),
('575b7172-5ec3-48ca-8680-981dc91f4b6e','送藥者陳國器','楊萬里','宋','宋诗','song-poetry','','[]','竇憲一舉空朔野，曹霸一筆空凡馬。',251,'全唐诗/poet.song.143000.json','["竇憲一舉空朔野，曹霸一筆空凡馬。", "吾鄉藥者有陳生，一丸洗空萬藥者。", "庸醫皆笑道旁莎，陳生拈出便是玉山禾。", "庸醫皆笑澗下水，陳生酌來便是上池底。", "也只不離神農書，書外別得一亡珠。", "也只不出歧伯論，論外別得舌一寸。", "舊遭痔疾惱殺儂，新遭淋疾與合縱。", "恰如住在圃田國，晉楚腹背來夾攻。", "陳生贈我玉菌子，乃是華陽洞中乖龍耳。", "陳生贈我紺葉紗，乃是金鴉脚底扶桑花。", "汲泉親手煮蟹眼，一浣枯腸如浣沙。", "平生舊疾蟬殻退，秋風吹落青天外。", "更傳枕中鴻寶方，戒勿浪傳泄天藏。", "君不見回巖仙客逢貧子，指石成金吾濟爾。", "貧子再拜不要金，祇覓指頭吾自指。"]'),
('8c7b961a-3a9c-4eff-932e-a418c0a63098','送王長文赴上庠','楊萬里','宋','宋诗','song-poetry','','[]','吾鄉前輩王南賓，讀書萬卷筆有神。',96,'全唐诗/poet.song.143000.json','["吾鄉前輩王南賓，讀書萬卷筆有神。", "屢登天府獻和璞，玉工過眼珉奪真。", "祇今有孫又奇絕，踏雪携書詣金闕。", "玉皇書院璧水中，賜子半窗桃玉蟲。", "端能健筆追乃祖，斗藪寸心寫千古。", "廣寒掇取第一枝，早爲雙親開兩眉。"]'),
('86c72fee-8f37-4034-995f-625edca43b81','賀吉州李守臘雪','楊萬里','宋','宋诗','song-poetry','','[]','仁侯妙手作廬陵，民歌敏惠如神明。',130,'全唐诗/poet.song.143000.json','["仁侯妙手作廬陵，民歌敏惠如神明。", "歌聲動天天降瑞，一夜幻出瓊瑶城。", "麗譙一新玉樓觀，郡治別起銀設廳。", "曉上青原臺上望，千門萬戶皆水晶。", "八邑山川一千里，盡種琪樹璣爲英。", "幕僚秉燭爭入賀，老夫抱病獨僵卧。", "寄言賀客此未奇，來年玉粒滑流匙。", "萬艘真珠貢京師，老夫已草周頌豐年詩。"]'),
('f4e675f0-2db6-4787-91bb-21e5582c99c6','除夕送次公子入京受縣','楊萬里','宋','宋诗','song-poetry','','[]','過眼光陰又歲窮，相看父子一尊同。',64,'全唐诗/poet.song.143000.json','["過眼光陰又歲窮，相看父子一尊同。", "春回雨點溪聲裏，人醉梅花燭影中。", "汝趁暄和朝北闕，我扶衰病見東風。", "弟兄努力思報國，放我滄浪作釣翁。"]'),
('b0f2a938-8177-42cc-b517-4c1a80ac5f66','丙寅人日送藥者周叔亮歸吉水縣','楊萬里','宋','宋诗','song-poetry','','[]','拔草不拔根，塞水不塞源。',116,'全唐诗/poet.song.143000.json','["拔草不拔根，塞水不塞源。", "忽然草生更水長，敗却禾稼仍滔天。", "老夫昔歲得淋疾，初謂一日今兩年。", "服藥六千六百盞，望舒二十二回圓。", "偶逢周郎顧，一脈擒二豎。", "發藥何用多，刀圭起沉痼。", "向來肝腸痛如割，今來疾痛全然脫。", "捉著根源盡掃除，周郎神醫天下無。"]'),
('c03da1d7-f723-4c62-8e9f-7a4d9e7b6630','病中感春','楊萬里','宋','宋诗','song-poetry','','[]','老去春來已薄情，體中病後更竛竮。',64,'全唐诗/poet.song.143000.json','["老去春來已薄情，體中病後更竛竮。", "海棠紅釅飛成雪，楊柳金濃染作青。", "到得當家饒景物，不如舊日借園亭。", "一杯欲把還休去，遮莫鶑花笑獨醒。"]'),
('6e5c7c48-2dca-4777-b5ec-16d0a6087fbf','落花','楊萬里','宋','宋诗','song-poetry','','[]','紅紫成泥泥作塵，顛風不管惜花人。',32,'全唐诗/poet.song.143000.json','["紅紫成泥泥作塵，顛風不管惜花人。", "落花辭樹雖無語，別倩黄鸝告訴春。"]'),
('101ddc7c-fdc1-46a8-a758-8b564e801ad7','雨中問訊金沙','楊萬里','宋','宋诗','song-poetry','','[]','金沙道是殿羣芳，不道荼𧃲輸一場。',64,'全唐诗/poet.song.143000.json','["金沙道是殿羣芳，不道荼𧃲輸一場。", "十里紅粧踏青出，一張錦被曬晴香。", "只須舊蔭已無暑，更走新條如許長。", "若恨昨朝來草草，夜來風雨更禁當。"]'),
('63ac44e3-f914-498e-ba88-f58b6373f706','寄題劉正卿雙清軒','楊萬里','宋','宋诗','song-poetry','','[]','吾鄉今代劉更生，新序說苑落筆成。',64,'全唐诗/poet.song.143000.json','["吾鄉今代劉更生，新序說苑落筆成。", "問渠才思寧底巧，玉泉繞屋供雙清。", "此泉來從何境界，銀河飛下雙羅带。", "便好乘槎犯斗星，斫桂廣寒天上行。"]'),
('a4175e86-e74b-429d-a1c0-8c3042a01dcb','初夏病起曉步東園二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','低枝碧李壓人頭，過雨黄梅滿道周。',32,'全唐诗/poet.song.143000.json','["低枝碧李壓人頭，過雨黄梅滿道周。", "紅日漏雲初試暑，綠陰酣露已偷秋。"]'),
('81023dda-941d-4139-a539-2954e3184997','初夏病起曉步東園二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','病起烏藤强自扶，三三逕裏曉晴初。',32,'全唐诗/poet.song.143000.json','["病起烏藤强自扶，三三逕裏曉晴初。", "鶑聲只在花梢近，行去行來不見渠。"]'),
('1ef3128e-65ae-4e1d-b302-b06b5bcfd55a','送羅正夫主簿之官餘干','楊萬里','宋','宋诗','song-poetry','','[]','君家人物已數世，後有祕丞前給事。',96,'全唐诗/poet.song.143000.json','["君家人物已數世，後有祕丞前給事。", "近來復見鄉先生，武岡使君五經笥。", "君才自是一世英，珠玉照乘仍連城。", "妙年已號萬人敵，强仕初登千佛名。", "番君小屈習鑿齒，且與刺頭簿書底。", "即看給札試蘭臺，飛上木天校文字。"]'),
('050151a4-7ab3-4b9a-b0f8-ce8ee0930d8d','五月三日早起步東園示幼輿子二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雨香不及露華香，竹液花膏馥葛裳。',32,'全唐诗/poet.song.143000.json','["雨香不及露華香，竹液花膏馥葛裳。", "儂與曉星成二客，更無人共上番涼。"]'),
('d48b2f12-267c-4dc7-a1f6-871e9566c8b2','五月三日早起步東園示幼輿子二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','筠箕苕帚兩無蹤，竊果畦丁職不供。',32,'全唐诗/poet.song.143000.json','["筠箕苕帚兩無蹤，竊果畦丁職不供。", "老子不來纔幾曰，松花槲葉滿亭中。"]'),
('4b4e6323-f7db-4e77-98f4-25b978b8a1c7','端午病中止酒','楊萬里','宋','宋诗','song-poetry','','[]','病裏無聊費掃除，節中不飲更愁予。',32,'全唐诗/poet.song.143000.json','["病裏無聊費掃除，節中不飲更愁予。", "偶然一讀香山集，不但無愁病亦無。"]'),
('38500554-c66e-462f-b196-461d6d663db8','張丞相詠歸亭詞二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','湘之山兮幽幽，湘之水兮舒舒，我來兮桂之陽。',177,'全唐诗/poet.song.143000.json','["湘之山兮幽幽，湘之水兮舒舒，我來兮桂之陽。", "春聿云莫兮，上下綠浄而交如。", "鳥鳴兮花乾，彼湘之人士兮詠游而魚魚。", "長者兮矩步，童子玉雪兮趨亦趨。", "挾策兮抱琴，若將游兮物之初。", "野風兮脩脩，吹萬而不可執兮，所過而敷腴。", "長者顧謂童子曰：快哉此風，吾爲汝援琴而歌之。", "歌曰：滄浪兮濯纓，風涼兮舞雩。", "微德人兮焉歸，以斯道兮金玉。", "予欲問津兮沂之水，其則不遠兮，又焉知湘江之非歟。"]'),
('1c583e8c-df77-458f-a566-a8c98eaee6e8','張丞相詠歸亭詞二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','茞蘭圃兮沼芙蕖，有美君子兮何斯其燕居。',149,'全唐诗/poet.song.143000.json','["茞蘭圃兮沼芙蕖，有美君子兮何斯其燕居。", "孚尹兮袖間，陞白虹兮斗之虛。", "章甫兮深衣，御風騎氣而天游兮，與造化而爲徒。", "獨立萬物之表兮，室邇而人甚遠。", "山立而淵靚兮，道德燕及乎蟲魚。", "韋編兮在手，隠几而卧兮，夢一丈夫。", "首肖乎尼山兮河其目，莞爾而笑兮告予以下學而上達，知我者其天乎。", "忽寤兮四顧，欵乃一聲兮亭之西隅。"]'),
('669b3b8f-9854-4d52-8bea-36b12ea4a71d','和張欽夫望月詞','楊萬里','宋','宋诗','song-poetry','','[]','玉蟲暈以貫虹兮學林之顛，閴其宵兮聖賢畢參於前。',248,'全唐诗/poet.song.143000.json','["玉蟲暈以貫虹兮學林之顛，閴其宵兮聖賢畢參於前。", "心超兮千載，忽乎納自牖兮光寒而靜娟。", "吾興視兮何祥，望舒推轂兮轔大圜。", "生兩儀兮虛白，飾萬物兮清妍。", "彼何居兮轃茲，挈一規兮破幽偏。", "代天兮宣精，扼欹兮惡盈。", "似道兮日損，縮於一晦弦兮，萬斯年而求伸。", "宅天下兮至晦，鏡天下兮至明。", "燭吾心中之月兮，貫地緯而洞天經。", "吾奉月兮周旋，月踵吾兮後先。", "夫君寄我兮三章，招月而與寓目兮，炯筆勢之翩翩。", "想他日之獨立兮，過庭而侍側。", "誰其耳剽於玉振兮，惟此月知其然。", "月不予留兮，予亦詠而歸。", "歌三終兮謝明月，何夕復惠然兮臨我於亭乎而。"]'),
('cf6b1720-70e8-41b5-b171-0aed193b92ff','延陵懷古 延陵季子','楊萬里','宋','宋诗','song-poetry','','[]','荆之溪兮澹以幽，惠之山兮雲侔。',222,'全唐诗/poet.song.143000.json','["荆之溪兮澹以幽，惠之山兮雲侔。", "思君子兮不見，莽草樹兮脩脩。", "面句吳兮東而坐，背朱方兮北卧。", "齊楚豈不强而大兮吾王以妥，賢於國其無裨兮，不曰季子存而吳賀。", "彼懵者之躗言兮，謂兆亡於讓王。", "弗丕承於考心兮，用永五湖之與三江。", "祀太伯其忽諸兮，顧襲譽於子臧。", "曾不知民無讓而不立兮，自古皆有亡。", "諏屺岵與鋤箕兮，疇莫知其重輕。", "若千乘暨簞豆兮，絜豐約而則明。", "迨躬逢而利怵兮，亦幾何而靡爭。", "謂吾札之不懿兮，札亦恬受而茹聲。", "思復思兮君子，乾坤毀而日月息兮，則君子之亦死。"]'),
('b9d56fc5-b25e-4327-a391-f154fc029ee5','延陵懷古 蘭陵令','楊萬里','宋','宋诗','song-poetry','','[]','密雲兮終風，健順閉兮罔寸蹊之通。',200,'全唐诗/poet.song.143000.json','["密雲兮終風，健順閉兮罔寸蹊之通。", "喟葵丘踐土而迹熄兮，矧冀方岐山之與逢。", "單棠谿以鑄兵兮，靡遺蒲於董澤。", "燕簴無趾而造齊廟兮，楚甿而秦其魄。", "鬭六王於一說兮，微儀衍之舌而不國。", "嗟若先生兮，雞知時之不如。", "儲唐虞之故冕兮，鬻洙泗之敝裾。", "乘方輪與折軸兮，欲先鞭而疾驅。", "豈不家捐而人棄兮，載之萬世之亨衢。", "繄素王兮中都，若蘭陵兮聖之徒。", "征九伯而佩六印兮，晞二邑宰而不得俱。", "儻不欲以天球玉磬而貿康瓠兮，嗟爾後死者其舍諸。"]'),
('67d2a6cb-293a-483c-85b5-c0f093b6e323','延陵懷古 東坡先生','楊萬里','宋','宋诗','song-poetry','','[]','吹赤壁之月笛兮，瞻黄州之雪堂。',195,'全唐诗/poet.song.143000.json','["吹赤壁之月笛兮，瞻黄州之雪堂。", "彈湘妃之玉瑟兮，織天孫之錦裳。", "招先生其來歸兮，何必懷眉山之故鄉。", "歷九州而猶隘兮，誕寘之祝融之汪。", "酌乳泉以當醴兮，餐荔子以爲糧。", "葺榕葉以作屋兮，託桄榔之蔭以爲堂。", "驅海濤以入硯滴兮，挽南斗文星於筆鋩。", "昌黎兮歐陽，視先生兮雁行。", "韞不洩兮忠憤，炯不揜兮文章。", "乞鏡湖兮九關，營菟裘兮是邦。", "予之來兮云暮，與先生兮相望。", "視履跡兮焉在，問故宮兮就荒。", "俯仰兮永懷，渺山川兮蒼蒼。"]'),
('9bb952ed-cbc9-4ad8-a8b7-d90b2d0fb504','跋李允蹈思故山賦辭','楊萬里','宋','宋诗','song-poetry','','[]','月巖含章兮，噫。',192,'全唐诗/poet.song.143000.json','["月巖含章兮，噫。", "熟貰之璜兮，噫。", "逋不其償兮，噫。", "眉山之下兮，噫。", "既億其價兮，噫。", "胡漏于罅兮，噫。", "籲于眉山兮，噫。", "山籲于天兮，噫。", "天蹙其顔兮，噫。", "有斐孫子兮，噫。", "花披秀啟兮，噫。", "烈祖是似兮，噫。", "筆似其鋒兮，噫。", "骨似其窮兮，噫。", "栖栖其逢兮，噫。", "爾詞則古兮，噫。", "爾騷則楚兮，噫。", "爾璞孰估兮，噫。", "招招巫咸兮，噫。", "有篿爾占兮，噫。", "曷焯爾潜兮，噫。", "曷窞不濟兮，噫。", "曷蔀不賁兮，噫。", "咷初笑既兮，噫。"]'),
('94d77d3d-5a34-40f6-991d-5ef6ae2bdfd1','和淵明歸去來兮辭','楊萬里','宋','宋诗','song-poetry','','[]','歸去來兮，平生懷歸今得歸。',313,'全唐诗/poet.song.143000.json','["歸去來兮，平生懷歸今得歸。", "有未歸而不懌，豈當懌而更悲。", "媿一陶之不若，庶二疎兮可追。", "肖令威之歸遼，喟物是而人非。", "捐水蒼兮今佩，反芰製兮昨衣。", "戀豈諼夫太紫，分敢踰於少微。", "如鹿得草，望綠斯奔。", "如鶴出籠，豈復入門。", "屨雖未得，而趾故存。", "謂予不信，有如泰罇。", "月喜予之言歸，隤清暉而照顔。", "山喜予以出迎，相勞苦其平安。", "江喜予而舞波，擊碎雪於雲關。", "紛鄰曲之老穉，羌堵牆以來觀。", "沸里巷之犬雞，亦喜翁之蚤還。", "驚鬢髯之兩霜，尚赳赳而桓桓。", "歸去來兮，半天下以倦游。", "饑予驅而予出，奚俟飽而無求。", "觀一簞之屢空，躬自樂而人憂。", "暨一區之草玄，娛羲畫與箕疇。", "豈慕胥靡，濟川作舟。", "矧先人之敝廬，有一壑兮一丘。", "後千尋兮茂林，前十里兮清流。", "耿靡羨而載營，蹇何騖而不休。"]'),
('9f979f87-e295-4822-9113-429fae496f32','黄世永哀辭','楊萬里','宋','宋诗','song-poetry','','[]','聖門際天而不可逕兮，子聚糧以疾趨。',232,'全唐诗/poet.song.143000.json','["聖門際天而不可逕兮，子聚糧以疾趨。", "古文熄而哇鄭兮，子獨追而雅諸。", "衆皆賞其襮而遺其裏兮，知全者不在予。", "仕者謂贛民之嚚兮，不啻沬邦之夫。", "何子之仁以蒞兮，若膝下之乳雛。", "予惟子之觀兮，則未知封屋之迂。", "沐猴豸而罔靦兮，子髮上而衡盱。", "舍己躁進而謂子躁進兮，宜不曰沽名之非愚。", "世切齒於彼之晚霣兮，流涕於子之不晚殂。", "庸知天之不子祉兮，不厚彼之辜。", "惟師友之恩紀兮，一飯而九其吁。", "天不予棐而奪予朋兮，半其濟而亡艫。", "決汝漢而東之兮，曾足爲予淚之餘。", "若子之死而不死兮，不亦名星日而骨幽墟。"]'),
('9c847eb3-147e-4b03-b954-8aa50099c76e','曾叔謙哀辭','楊萬里','宋','宋诗','song-poetry','','[]','歲紹興之壬午兮，余負丞於零陵。',373,'全唐诗/poet.song.143000.json','["歲紹興之壬午兮，余負丞於零陵。", "汩夫君之南征兮，臨二松之寒廳。", "聞跫然於逃虛兮，辭未接而情親。", "分一日之光景兮，載鴟夷乎吾與行。", "沛吾擊其蘭橈兮，亂湘江以揚舲。", "維余笮於愚溪兮，叩柳子之柴荆。", "陟西山以茹芳兮，降鈷鉧以漱泠。", "風吹衣以拂雲兮，舉手攬乎南斗之星。", "君與我其俱醉兮，夜解手於丘亭。", "余未幾而北歸兮，君忽返乎銘旌。", "曾合離之俛仰兮，奄古今乎死生。", "羌夫君之淵偉兮，允江山之載英。", "蔚豫章之離奇兮，森楩梓其崢嶸。", "自拱把而培溉兮，俟百圍乎千尋。", "崒雪山與冰谷兮，凜霜影而雨聲。", "細猶堪於薄櫨兮，豈大者之不可杗。", "仰神臯於太紫兮，矩厚載而規圜。", "清屹建章以亙明光兮，連蕙草與蘭林。", "詔班爾以駿奔兮，旁搜巖崖之欹傾。", "締皇居及帝室兮，將涓休乎落吾成。", "蹇棟榦槁乾於空山兮，匠不獲以督繩。", "紛后皇之揠材兮，壑何幽之不徵。", "喟一擷而萬捐兮，夫孰有遭而無營。", "君方舍斯世而去之兮，豈達欣而窮憎。"]'),
('b5da10b2-b304-4133-a1fe-f47039b826ce','范女哀辭','楊萬里','宋','宋诗','song-poetry','','[]','有齊石湖之季女兮，肇葰茂而青葱。',426,'全唐诗/poet.song.143000.json','["有齊石湖之季女兮，肇葰茂而青葱。", "蘭茁芽以芬播兮，玉在璞而光融。", "茹采蘋以爲粻兮，築內則爲之宮。", "樂彤管以俶載兮，逝將眇青竹而論功。", "製菡萏以爲裾兮，裼之以秋江之芙蓉。", "紛蕙纕而菊佩兮，豈江蘺揭車之與縫。", "掇袤丈之朔雪以澡德兮，襲萬壑之清冰而在躬。", "耿吾獨傳中郎之素業兮，豈曰矜蕭然林下之風。", "沛吾乘乎桂舟兮，無小無大焉從吾公。", "何若而人之不淑兮，奄一疢而長終。", "忍舍蘭陔之孝養兮，莽玉女宓妃之與從。", "父曰嗟予膳之孰視兮，母曰嗟予命之疇同。", "衋兩親之哀潸兮，遺九宗之長恫。", "蹇石湖之慟而莫之釋兮，小極而隠几乎書之叢。", "夢漂漂而行遠兮，求吾兒乎四方上下之青穹。", "杳碧海之際天兮，巋三山之倚空。", "蓬萊方丈之攸宅兮，浮金宮銀闕之崇崇。", "若有人乎山之阿兮，飛騰往來而不可逢。", "羌可逢而不可執兮，若迥映乎復朣朧。", "摘玉李而弄金波兮，遨嬉乎倒景有無之濛鴻。", "忽臨睨乎舊鄉兮，望見石湖之仙翁。", "泫初咷而後哂兮，唁吾翁乎奚戚容。", "繄天地萬物之逆旅兮，兒與翁父子適相值於逆旅之中。", "汩倏合而忽分兮，邈千變萬化而何窮。"]'),
('b90f80c7-b3be-42dc-a718-8567de3b2662','悼雙珍辭','楊萬里','宋','宋诗','song-poetry','','[]','有傅者嶺兮，有玄者潭。',258,'全唐诗/poet.song.143000.json','["有傅者嶺兮，有玄者潭。", "崒乎瓊臺與玉堂兮，天垂光而蔚藍。", "寶祲下蟠乎九淵兮，瓌彩上絢乎千巖。", "羌旁磚轇轕而不漓兮，耿虹貫乎晴嵐。", "劬玉衡之望氣兮，九載旭考而宵參。", "曰西江之軫墟兮，孕雙珍乎泥之潛。", "匪珠胎之雙止兮，則瑴玉其美兼。", "帝令雷公以持斧兮，敕陽侯以發函。", "逝將修貢于玉府兮，旅清廟而爾瞻。", "夫何夔魖獝狂之予妬兮，肆爲伯明之讒。", "蹇訴帝以不好兮，未聽六丁之窮探。", "飛巨石以載震兮，洶怒濤以有嚴。", "連璧毀于石韞兮，雙珠裂于波涵。", "卞和慟以叫帝閽兮，隨侯泣以衣沾。", "帝亦悲傷而末如之何兮，磔不若魑魅而不厭。", "安得雙珍之再芒兮，迥映乎西江之北南。"]'),
('a548d9a2-2564-4463-b25d-efef5dfcfa4f','有宋死孝毛子仁哀辭','楊萬里','宋','宋诗','song-poetry','','[]','灝穹睠宋，方郅隆些。',240,'全唐诗/poet.song.143000.json','["灝穹睠宋，方郅隆些。", "篤生仁皇，實叡聰些。", "二堯兩舜，復時雍些。", "杜韓富范，再夔龍些。", "巍蕩奮熙，起丕功些。", "歐陽伯仲，軻與雄些。", "雲昭漢回，炳文風些。", "麟在靈囿，鳳在桐些。", "金芝專車，朱草叢些。", "懸藜結綠，牣紫宮些。", "靈蛇照乘，玉府充些。", "大江之西，文江東些。", "毛伯苗裔，河嶽鍾些。", "三辰五緯，韞心胸些。", "如漢賈生，與終童些。", "年未弱冠，收科崇些。", "連收制科，天動容些。", "玉映漢臺，驚群公些。", "棄官如泥，子職恭些。", "死孝倚廬，神明通些。", "文行有煒，垂無窮些。", "與宋一經，相始終些。", "凍黎百年，養萬鍾些。", "草腐菌朽，花霣空些。"]'),
('9556fb2b-aaf5-4c34-b379-a3d934d9d38a','趙平甫幽居八操 筠居操','楊萬里','宋','宋诗','song-poetry','','[]','公子誅茅，不木不土。',20,'全唐诗/poet.song.143000.json','["公子誅茅，不木不土。", "此君惠然，聿來胥宇。"]'),
('08940d48-de30-4eae-b51b-7ffb242e2018','趙平甫幽居八操 我娛齋操','楊萬里','宋','宋诗','song-poetry','','[]','一室容膝，納萬壑而有餘。',34,'全唐诗/poet.song.143000.json','["一室容膝，納萬壑而有餘。", "一几凝塵，載千古而不重。", "暮四朝三，吾不復夢。"]'),
('fcbde92e-53a2-4521-a44d-275ebbd2c540','趙平甫幽居八操 醉石操','楊萬里','宋','宋诗','song-poetry','','[]','望之溫其玉，即之寒於冰。',30,'全唐诗/poet.song.143000.json','["望之溫其玉，即之寒於冰。", "一飲五斗，一石解酲。", "衆人皆醉石獨醒。"]'),
('067f5a58-7381-44bd-8ba1-e2ff7e5e0092','趙平甫幽居八操 竹齋操','楊萬里','宋','宋诗','song-poetry','','[]','客來何聞，客去何嗔。',26,'全唐诗/poet.song.143000.json','["客來何聞，客去何嗔。", "左右前後惟此君。", "德不孤，必有鄰。"]'),
('c5ffd1f3-7f54-4c78-9776-3ee0897f9b01','趙平甫幽居八操 北窗操','楊萬里','宋','宋诗','song-poetry','','[]','一枕之甘，萬戶不願。',34,'全唐诗/poet.song.143000.json','["一枕之甘，萬戶不願。", "清風之快，萬玉不價。", "爲我謝避俗翁，誰在羲皇之下。"]'),
('389c17e6-6600-4177-9ef5-abb52de5a6c9','趙平甫幽居八操 梅亭操','楊萬里','宋','宋诗','song-poetry','','[]','竹屋夜明，竹戶寒聲。',38,'全唐诗/poet.song.143000.json','["竹屋夜明，竹戶寒聲。", "幽人舍琴而起視，香通國而白連城。", "梅耶雪乎，四問而四不應。"]'),
('633cf236-3502-4fc1-a304-80ecab832dc5','趙平甫幽居八操 棋臺操','楊萬里','宋','宋诗','song-poetry','','[]','爭名不亢則朝者嘻，爭利不贏則市者吁。',29,'全唐诗/poet.song.143000.json','["爭名不亢則朝者嘻，爭利不贏則市者吁。", "君子無所爭，必也弈乎。"]'),
('71fbf8d7-4280-4f1e-b403-6d7508706125','趙平甫幽居八操 龜潭操','楊萬里','宋','宋诗','song-poetry','','[]','風耆其武，波赫斯怒。',20,'全唐诗/poet.song.143000.json','["風耆其武，波赫斯怒。", "油然者淵，未遽如許。"]'),
('90ca8876-374a-4363-a9ce-e84e4e4e3c5e','題曾景山通判壽衍堂','楊萬里','宋','宋诗','song-poetry','','[]','風月暫平分，爲霖喜有人。',24,'全唐诗/poet.song.143000.json','["風月暫平分，爲霖喜有人。", "斯堂非浪扁，佐主壽躋民。"]'),
('9a3eba02-7ec3-4a1e-9a1c-700093455dcd','送劉茂才主簿之官理定','楊萬里','宋','宋诗','song-poetry','','[]','梅子青青荔未丹，葵丘縮戍便之官。',32,'全唐诗/poet.song.143000.json','["梅子青青荔未丹，葵丘縮戍便之官。", "莫言屋矮位卑甚，早晚高人振羽翰。"]'),
('abe560dc-2df5-4f9c-9189-9280157a7310','蕭照鄰參政大資挽詩','楊萬里','宋','宋诗','song-poetry','','[]','公如月欠一分圓，生死應同晝與昏。',32,'全唐诗/poet.song.143000.json','["公如月欠一分圓，生死應同晝與昏。", "鼎鼐□□□□□，□□露□留好□。"]'),
('07a3e6c7-1418-4a85-83fa-1372f069b326','贈旴江謝正之','楊萬里','宋','宋诗','song-poetry','','[]','策馬訪柴扉，庭前草亦□。',24,'全唐诗/poet.song.143000.json','["策馬訪柴扉，庭前草亦□。", "談今復談古，如子□□□。"]'),
('f8187126-602b-4550-a7bc-10bb8e01072f','太守趙山父命劉秀才寫予老醜索贊','楊萬里','宋','宋诗','song-poetry','','[]','□□如斯兼兒醜，丹青寫出十分真。',32,'全唐诗/poet.song.143000.json','["□□如斯兼兒醜，丹青寫出十分真。", "凌煙繪像吾無望，喜在山林老此身。"]'),
('97079954-3940-4a2a-9348-ef2264ade090','寄題舒州宿松知縣戴在伯重新紫霄亭','楊萬里','宋','宋诗','song-poetry','','[]','高高亭聳紫霄端，借榻高眠廛市間。',32,'全唐诗/poet.song.143000.json','["高高亭聳紫霄端，借榻高眠廛市間。", "輪奐重新無俗□，何如來此伴雲閑。"]'),
('74a703b6-c5b1-483d-8cd1-e67eef032f58','雨後至溪上三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','□□□□一番□，□□風光□□□。',32,'全唐诗/poet.song.143000.json','["□□□□一番□，□□風光□□□。", "□□渭川公子在，此時□□理絲綸。"]'),
('9d4f38cc-0808-4ae4-9f41-a6f6409c3109','雨後至溪上三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','扁舟一葉泊溪彎，一雨初收篷未乾。',32,'全唐诗/poet.song.143000.json','["扁舟一葉泊溪彎，一雨初收篷未乾。", "風浪依然平帖後，漁翁□出把漁竿。"]'),
('ac71095a-7251-47cd-9419-f7b368a12c37','雨後至溪上三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','擬借丹青畫作圖，退休老子作漁夫。',32,'全唐诗/poet.song.143000.json','["擬借丹青畫作圖，退休老子作漁夫。", "鳳凰池上雖榮貴，何似清閑看浴鳬。"]'),
('54312e06-0347-451e-873b-632f9f401da9','寄題太和宰趙嘉言勤民二圖  其一','楊萬里','宋','宋诗','song-poetry','','[]','特借丹青寫二圖，二圖之意果何如。',32,'全唐诗/poet.song.143000.json','["特借丹青寫二圖，二圖之意果何如。", "請君細看□□□，是亦□求無逸書。"]'),
('d6978da6-dd6f-41dc-b4ec-bf4cc4877e8c','寄題太和宰趙嘉言勤民二圖  其二','楊萬里','宋','宋诗','song-poetry','','[]','□民勿視作□□，勉力耕桑貴及時。',32,'全唐诗/poet.song.143000.json','["□民勿視作□□，勉力耕桑貴及時。", "上古□□猶畫像，老夫喜贈二篇詩。"]'),
('9830c02c-3a48-4ec2-8ed1-c493e490eeae','上元前一日游東園看梅三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','誰占百花頭上魁，花神推許□□□。',32,'全唐诗/poet.song.143000.json','["誰占百花頭上魁，花神推許□□□。", "東園春信知多少，今日喜晴拚一來。"]'),
('38f9d717-68fa-4080-b23f-a8872f64855e','上元前一日游東園看梅三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','東園把酒問東皇，何事梅花壓衆芳。',32,'全唐诗/poet.song.143000.json','["東園把酒問東皇，何事梅花壓衆芳。", "和靖當年一題品，到今幾載句猶香。"]'),
('2ddd0fd0-9814-46ff-8ee7-9fbb59fe421f','上元前一日游東園看梅三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','春到東園恰□□，臘前聞已破南枝。',32,'全唐诗/poet.song.143000.json','["春到東園恰□□，臘前聞已破南枝。", "□□□□□□□，□旦元□□□詩。"]'),
('1d90637c-d7e8-407b-9643-1c919914d12d','李原之主簿投贈長篇謝以唐律','楊萬里','宋','宋诗','song-poetry','','[]','寶氣亭前雙太阿，龍光再吐射銀河。',64,'全唐诗/poet.song.143000.json','["寶氣亭前雙太阿，龍光再吐射銀河。", "伯兮西嘯巴山月，仲氏南嬉楚水波。", "贈以四愁真絕唱，不如一詣聽長哦。", "簿書何至煩勾校，歸校芸香蠹簡訛。"]'),
('cc6116b0-389a-4aa0-8f02-aab96898c1ed','寄題西昌彭孝求求志堂','楊萬里','宋','宋诗','song-poetry','','[]','西江山水何處好，觀山夜泉快閣風。',80,'全唐诗/poet.song.143000.json','["西江山水何處好，觀山夜泉快閣風。", "山奇水秀産瓌寶，彭氏四傑隠此中。", "斗間異氣如白虹，少微芒寒摇太空。", "占言非劍亦非玉，長松下有幽人屋。", "似聞鳴騶入空谷，籬邊老却陶潛菊。"]'),
('23a3fb72-a72c-42b7-94d0-9dc72c7cda95','句  其一','楊萬里','宋','宋诗','song-poetry','','[]','露窠蛛卹緯，風語燕懷春。',12,'全唐诗/poet.song.143000.json','["露窠蛛卹緯，風語燕懷春。"]'),
('1d42ced7-bffd-46a6-b2e2-c87b25014e59','句  其二','楊萬里','宋','宋诗','song-poetry','','[]','立岸風大壯，還舟燈小明。',12,'全唐诗/poet.song.143000.json','["立岸風大壯，還舟燈小明。"]'),
('4f796bc5-63a2-4b55-b400-52bc142b15da','句  其三','楊萬里','宋','宋诗','song-poetry','','[]','疎星煜煜沙貫日，綠雲擾擾水舞苔。',16,'全唐诗/poet.song.143000.json','["疎星煜煜沙貫日，綠雲擾擾水舞苔。"]'),
('cb9d1ee2-72af-4140-bd7b-faf3a01ae345','句  其四','楊萬里','宋','宋诗','song-poetry','','[]','坐忘日月三杯酒，卧護江湖一釣船。',16,'全唐诗/poet.song.143000.json','["坐忘日月三杯酒，卧護江湖一釣船。"]'),
('679317d4-cc64-48b6-b9e6-1282b8c33b23','送陸先生聖修赴春闈','周必大','宋','宋诗','song-poetry','','[]','送君南浦慘離情，握手依依數去程。',64,'全唐诗/poet.song.143000.json','["送君南浦慘離情，握手依依數去程。", "日薄雲濃風轉勁，江寒水落浪還生。", "此時執別仙舟穩，後夜相思山月明。", "好把嘉猷獻丹扆，中興天子急昇平。"]'),
('906c6785-b448-4f88-aa1d-3d99b6645048','贛江','周必大','宋','宋诗','song-poetry','','[]','跡落蠻夷地，艱危分飽經。',48,'全唐诗/poet.song.143000.json','["跡落蠻夷地，艱危分飽經。", "盤渦隨櫂舞，驚浪濺船零。", "石亂舟才過，峯回眼謾青。", "晚來荒浦宿，愁緒轉冥冥。"]'),
('959c5a6a-9469-4336-8975-a34e81166a0b','留題文氏雙秀亭三首  其一','周必大','宋','宋诗','song-poetry','','[]','身在江湖欲看山，山行還憶弄潺湲。',32,'全唐诗/poet.song.143000.json','["身在江湖欲看山，山行還憶弄潺湲。", "誰知裏許雙奇絕，碧玉青羅一望間。"]'),
('cc9c7029-e65b-4e54-adad-5757e87c7d14','留題文氏雙秀亭三首  其二','周必大','宋','宋诗','song-poetry','','[]','汀蘭烟樹兩佳哉，六曲屏幃坐上開。',32,'全唐诗/poet.song.143000.json','["汀蘭烟樹兩佳哉，六曲屏幃坐上開。", "南浦彩雲飛畫棟，西山爽氣在朝來。"]'),
('99f36705-6972-44aa-89db-59aa47e4c005','留題文氏雙秀亭三首  其三','周必大','宋','宋诗','song-poetry','','[]','澄碧修眉固自奇，只愁門外苦喧早。',32,'全唐诗/poet.song.143000.json','["澄碧修眉固自奇，只愁門外苦喧早。", "要知心跡雙清處，須待人稀月上時。"]'),
('5c8c942f-b79f-4722-8a4e-be201402b711','彭永州夫人挽詞','周必大','宋','宋诗','song-poetry','','[]','夢虺端由慶閥鍾，采萍來助大夫共。',64,'全唐诗/poet.song.143000.json','["夢虺端由慶閥鍾，采萍來助大夫共。", "化行閨壺衣無綠，行應箴圖管有彤。", "石窌方生湯沐邑，黄堈俄掩斧堂封。", "不須更續更生傳，自有豐碑記肅雍。"]'),
('dc637501-6a1e-41c9-b622-87c5df76e0bc','道中憶胡季懷','周必大','宋','宋诗','song-poetry','','[]','珍重臨分白玉巵，醉中那暇說相思。',32,'全唐诗/poet.song.143000.json','["珍重臨分白玉巵，醉中那暇說相思。", "天寒道遠酒醒處，始是憶君腸斷時。"]'),
('428bfd9c-a61b-451f-9857-1f4219496011','舟行憶永和兄弟','周必大','宋','宋诗','song-poetry','','[]','一挂吳帆不計程，幾回繫纜幾回行。',64,'全唐诗/poet.song.143000.json','["一挂吳帆不計程，幾回繫纜幾回行。", "天寒有日雲猶凍，江闊無風浪亦生。", "數點家山常在眼，一聲寒壺正關情。", "長年忽得南來鯉，恐有音書急遣烹。"]'),
('42ac3b6f-59dc-4fe3-90ca-0fa0b3b83efe','抵蘇臺寄季懷','周必大','宋','宋诗','song-poetry','','[]','江浙相望寄此身，臨風回首嘆離羣。',64,'全唐诗/poet.song.143000.json','["江浙相望寄此身，臨風回首嘆離羣。", "吳雲目斷君思我，楚樹天遥我憶君。", "別後酒尊應獨酌，舊時棋局對誰分。", "狂言欲吐還須茹，俗子紛紛可得聞。"]'),
('29079ede-df49-40ec-a760-d98816e6e64f','次韻王仲謨仲寧唱酬二首  其一','周必大','宋','宋诗','song-poetry','','[]','公子翩翩正妙年，修能姱節本天然。',64,'全唐诗/poet.song.143000.json','["公子翩翩正妙年，修能姱節本天然。", "弟兄况自逢三益，事業懸知定十全。", "厚意綢繆華映鄂，新詩綺麗月流天。", "乘黄騄耳方爭駿，應笑駑駘强自鞭。"]'),
('2ffabeaf-0135-4dc9-a053-adfc7ecbc0da','次韻王仲謨仲寧唱酬二首  其二','周必大','宋','宋诗','song-poetry','','[]','別日無多似隔年，每逢佳句輒欣然。',64,'全唐诗/poet.song.143000.json','["別日無多似隔年，每逢佳句輒欣然。", "詞傾江漢無留礙，語轉珠璣更渾全。", "目共荆谿千里月，人居吳郡五湖天。", "興來儻有山陰作，即上扁舟往執鞭。"]'),
('e44095e0-0c56-46a4-a7fb-a48bc84cfbaf','和仲寧中秋赴飲莊宅','周必大','宋','宋诗','song-poetry','','[]','方訝頑陰蔽月堂，坐看凉吹動枯腸。',64,'全唐诗/poet.song.143000.json','["方訝頑陰蔽月堂，坐看凉吹動枯腸。", "疾驅雲陣千重翳，盡放冰輪萬丈光。", "莫問蚌珠圓合浦，且聽羯鼓打西凉。", "疏狂似我何須撓，撓取吹笙玉雪郎。"]'),
('b58796cf-0a9c-4be9-934a-b251290bf181','羅主簿妻朱氏挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','早歲從孫寶，中年訓孟軻。',48,'全唐诗/poet.song.143000.json','["早歲從孫寶，中年訓孟軻。", "節高資內助，機斷激儒歌。", "枳棘鸞先逝，雲霄鶴正摩。", "即看膺命服，何遽掩卷阿。"]'),
('3ad40260-f8dd-46a3-9c1d-5f2640045054','羅主簿妻朱氏挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','素羃帷堂日，青烏甫竁時。',48,'全唐诗/poet.song.143000.json','["素羃帷堂日，青烏甫竁時。", "薤凝朝露冷，樹動晚風悲。", "七十年無憾，平生壺有儀。", "孝哉難與穀，猶慟蓼莪詩。"]'),
('8c287ce4-3ae8-480b-bd2b-f740a774e23f','送趙富文倅洪州三首  其一','周必大','宋','宋诗','song-poetry','','[]','期集分携五載前，衝泥各上浙江船。',32,'全唐诗/poet.song.143000.json','["期集分携五載前，衝泥各上浙江船。", "如今再贈城南柳，依舊黄梅夜雨天。"]'),
('6e126bea-78c4-4d81-a85c-0ac36bedc8e2','送趙富文倅洪州三首  其二','周必大','宋','宋诗','song-poetry','','[]','花發河陽政早成，策勳恩擢佐藩臣。',32,'全唐诗/poet.song.143000.json','["花發河陽政早成，策勳恩擢佐藩臣。", "鷄翹豹尾他年從，且作銀章第一人。"]'),
('7cf505fa-382c-4fb5-bb34-f7109312128c','送趙富文倅洪州三首  其三','周必大','宋','宋诗','song-poetry','','[]','南浦飛雲繞棟桴，西山爽氣入魚須。',32,'全唐诗/poet.song.143000.json','["南浦飛雲繞棟桴，西山爽氣入魚須。", "公庭吏散文書靜，許我他時解榻無。"]'),
('ca2ea484-9ad5-41e5-9ed5-03d79e25ba3a','次韻丁維皋糧料牡丹未開','周必大','宋','宋诗','song-poetry','','[]','拙速那能鬭巧遲，從教綠暗與紅稀。',64,'全唐诗/poet.song.143000.json','["拙速那能鬭巧遲，從教綠暗與紅稀。", "天香未染蜂猶懶，日幄先籠蝶已飛。", "羯鼓只應催上苑，鶴林誰復倩紅衣。", "請君多釀淮南米，縱賞先拚倒載歸。"]'),
('625f2e99-b7d6-4708-b8ae-c722bcdee516','適蒙折簡見約烹茶再次前韻','周必大','宋','宋诗','song-poetry','','[]','清明過後日初遲，春服成時瑟漸希。',64,'全唐诗/poet.song.143000.json','["清明過後日初遲，春服成時瑟漸希。", "浪蘂總隨流水遠，名花獨待羽觴飛。", "催開已奏清平調，唱徹猶須金縷衣。", "活火新泉太清絕，何如沉醉詠而歸。"]'),
('3af063e0-3699-4f87-9b63-b6561c506918','次韻白蓮','周必大','宋','宋诗','song-poetry','','[]','汙溝濁水葉田田，又見新栽京府蓮。',64,'全唐诗/poet.song.143000.json','["汙溝濁水葉田田，又見新栽京府蓮。", "玉井謾傳青壁外，雪膚如在射山前。", "泛紅入幕王家俗，種白開池陸子賢。", "不用若耶溪畔女，蘭橈夜採月娟娟。"]'),
('e379a6a4-db75-4fa4-b363-2747a37051ce','次韻紅白蓮間生','周必大','宋','宋诗','song-poetry','','[]','閒花不遣倚門牆，獨挹芙蕖冉冉香。',64,'全唐诗/poet.song.143000.json','["閒花不遣倚門牆，獨挹芙蕖冉冉香。", "艷質施朱窺宋玉，冰姿傅粉試何郎。", "青莖翠蓋元相映，縞袂霞裾各自芳。", "聞道金鑾行豹直，炬蓮先已兆嘉祥。"]'),
('de07b57d-48de-4dce-bd93-1cfe1bfc4cb9','次韻秋日禪房','周必大','宋','宋诗','song-poetry','','[]','官閒未覺往來妨，疏懶從公意自長。',64,'全唐诗/poet.song.143000.json','["官閒未覺往來妨，疏懶從公意自長。", "松柏有心寒始見，芝蘭入室久彌香。", "送秋容我無何飲，畦夏憐渠有底忙。", "霜倒池蓮雨荒菊，禪房真似贊公房。"]'),
('ac58bc24-6971-4cf3-b5f3-104cba8720f0','次韻沈世德撫幹川詠軒','周必大','宋','宋诗','song-poetry','','[]','江山倏清麗，雲月助色澤。',240,'全唐诗/poet.song.143000.json','["江山倏清麗，雲月助色澤。", "向來面面景，今日誰洗滌。", "主人倚晴檻，回首笑謂客。", "府公實知己，餘事懶經畫。", "汙幪廓大厦，軒窗開澤園。", "架簷逼象緯，植礎壓鹵斥。", "仰看天宇大，俯覺地軸窄。", "端如倩巨靈，妙手重開闢。", "此興固非淺，無入不自適。", "華關望中敬，棠陰坐上得。", "波光動藻井，帆影落几席。", "所欣魚依蒲，未許蝎見壁。", "陰晴及朝暮，氣象知幾易。", "飈回有餘韻，鳥度無留迹。", "市聲沉浩浩，漁唱聞昔昔。", "油幕多風流，翛然晉八伯。", "淋漓傳翰墨，鏦擊間金石。", "連璧喜同志，倚玉許凉德。", "頗慙陂量容，未忍俗駕勒。", "惡詩信非備，勿作春秋責。"]'),
('17ccc4cb-b84e-4af4-a953-50563374b663','又次韻二首  其一','周必大','宋','宋诗','song-poetry','','[]','川流元滾滾，客至喜津津。',48,'全唐诗/poet.song.143000.json','["川流元滾滾，客至喜津津。", "卜築新形勢，逢迎舊主人。", "酒杯容我醉，詩句味君醇。", "大隠聊城市，巖耕笑子真。"]'),
('fbab8366-07d8-45e5-b05f-2c541a0b3cf1','又次韻二首  其二','周必大','宋','宋诗','song-poetry','','[]','宮槐分影直，官柳著行疏。',48,'全唐诗/poet.song.143000.json','["宮槐分影直，官柳著行疏。", "畫棟飛翬遠，晴霞散綺餘。", "池邀山簡馬，水勝武昌魚。", "只恐封泥召，驂鸞上帝居。"]'),
('75aa5ef0-6533-48ab-b5c4-804d19695a87','又次韻醵飲','周必大','宋','宋诗','song-poetry','','[]','層軒發天藏，初日照粉雘。',192,'全唐诗/poet.song.143000.json','["層軒發天藏，初日照粉雘。", "雄觀跨鵬背，煩促陋蠶箔。", "飛綏會蘭亭，傳觴寫桑落。", "飲興江海窄，逸氣雲天薄。", "雖無漢侯鯖，粗勝周禮醵。", "清歡謝絲竹，賀厦驚燕雀。", "圍棋角勝負，獻俳紛戲謔。", "凉風徧廣坐，長夏失重熇。", "高會方繼日，初筵今告朔。", "要令四難并，詎止一餉樂。", "明朝傳絕唱，百年無此作。", "薦聞須狗監，賡絕愧鼠璞。", "今王馳蒲輪，之子尚蓮幕。", "行參瑚璉用，歸助棟梁託。", "讀書照青藜，視草詠紅藥。", "回顧廣文寒，莫忘鷄黍約。"]'),
('d88e89db-baed-479e-898f-9e93bf134044','次韻趙公直賞心亭醵會古風','周必大','宋','宋诗','song-poetry','','[]','晉人誇新亭，假日輒高會。',192,'全唐诗/poet.song.143000.json','["晉人誇新亭，假日輒高會。", "中間伯仁輩，未免楚囚對。", "江山猶古昔，人物已曖昧。", "東郊今保釐，翠華記行在。", "佳麗壓淮楚，追遊盛冠蓋。", "茲樓貫城雉，于邁無小大。", "令威雖不歸，靈光故無礙。", "烟雲互明滅，川郭相映带。", "當年烏衣游，此日思一槩。", "從容值休沐，登臨多慷慨。", "幽懷忽軒豁，細故絕芥蒂。", "已尋詩社盟，更許食期戒。", "佳賓滿座上，好語來天外。", "舟移白鷺遠，目送飛鳥快。", "方種淵明秫，粗免監河貸。", "一醉儻可期，與君時倒載。"]'),
('4ea0ff35-05b8-415e-ab02-f11d30d56c4e','送鄧漕移帥揚州二首  其一','周必大','宋','宋诗','song-poetry','','[]','碧幢紅旆擁西風，幾點淮山落眼中。',64,'全唐诗/poet.song.143000.json','["碧幢紅旆擁西風，幾點淮山落眼中。", "卧轍正看留使者，褰帷早已識元戎。", "兒童騎竹迎并牧，父老封棠記召公。", "人望汲卿居禁闥，淮揚只恐又匆匆。"]'),
('1de3d421-0005-480f-9958-c48362faefe2','送鄧漕移帥揚州二首  其二','周必大','宋','宋诗','song-poetry','','[]','聞道維揚地望雄，風流人物似江東。',64,'全唐诗/poet.song.143000.json','["聞道維揚地望雄，風流人物似江東。", "六龍前日臨淮海，五馬由來說醉翁。", "璧月幾橋留夜色，珠簾十里待春風。", "遥知九日平山會，笑插茱萸滿鬢紅。"]'),
('fb562f2d-2a7d-469a-b71a-239973c400cf','送葛謙問運幹','周必大','宋','宋诗','song-poetry','','[]','少年扶犁事西疇，老陪英游帝王州。',128,'全唐诗/poet.song.143000.json','["少年扶犁事西疇，老陪英游帝王州。", "才高韻勝各有得，志合情親君更優。", "離筵忽席洛定鼎，戍期云異齊葵丘。", "君行共歎空冀北，我衰謾作周南留。", "欲持菊觴止君飲，單車已戒難停輈。", "欲挽長條贈君別，金城柳落空悲秋。", "悲秋惜別置勿道，資望久合登瀛洲。", "仙凡一隔在何許，指點蓬萊雲氣浮。"]'),
('ab3f0d71-15d1-44c7-b6ed-99ee71217c24','送毛平仲','周必大','宋','宋诗','song-poetry','','[]','父祖同登六十春，相逢草草大江濆。',64,'全唐诗/poet.song.143000.json','["父祖同登六十春，相逢草草大江濆。", "羨君不使囊錐見，笑我空將芰製焚。", "聞道都人時載酒，未容俗客細論文。", "他年小築柯山畔，泉石風光賸欲分。"]'),
('c9d7bc60-ed95-457f-928c-df766029855c','次韻邢懷正通判遊蔣山','周必大','宋','宋诗','song-poetry','','[]','仙人薄蓬萊，乘槎度河滸。',240,'全唐诗/poet.song.143000.json','["仙人薄蓬萊，乘槎度河滸。", "舊觀桑田變，今訪鍾山古。", "駕言出東門，恍若之帝所。", "朝曦霽青霜，楓葉落紅雨。", "亭亭望浮圖，隠隠插天宇。", "坡垂北溟鼇，石卧南山虎。", "遥聞飯後鍾，絕勝紞如鼓。", "恭惟布金地，草木誰敢侮。", "孤芳破冰雪，喜見梅萼吐。", "同遊皆大雅，緇素競先睹。", "巾車似元亮，漱石雜孫楚。", "相將挹靈泉，何用照牛渚。", "西方化人國，未覺道修阻。", "法筵盛龍象，一一會心侶。", "茗盌散午夢，蒲團便軟語。", "懸知雨花社，重辯風幡舞。", "相投甚針芥，味道真酪乳。", "從來草堂靈，俗駕回吾祖。", "况如雲仍輩，么麽那復數。", "後車倘許隨，未羨黄金塢。"]'),
('ad0d1f79-0d8b-4f47-8595-3d5e90dc6ba6','次韻周德友運幹','周必大','宋','宋诗','song-poetry','','[]','曾見麻姑過蔡經，却陪王導宴新亭。',64,'全唐诗/poet.song.143000.json','["曾見麻姑過蔡經，却陪王導宴新亭。", "博文正自鄙木彊，操論未應談竹形。", "入幕久依池水綠，讀書行照杖藜青。", "篋中知有還丹在，不用臨溪憐鬢星。"]'),
('ce213397-6e5a-4422-a1e8-d66a6f12ffb4','送蔡德輝教授三首  其一','周必大','宋','宋诗','song-poetry','','[]','天馬元從西極來，頻年伏櫪伴駑駘。',32,'全唐诗/poet.song.143000.json','["天馬元從西極來，頻年伏櫪伴駑駘。", "如今始覺升沉異，萬里追風道路開。"]'),
('62e61024-7e57-415b-96b3-0dd457b043b9','送蔡德輝教授三首  其二','周必大','宋','宋诗','song-poetry','','[]','曉折臺城楊柳枝，夕登瓜步佛貍祠。',32,'全唐诗/poet.song.143000.json','["曉折臺城楊柳枝，夕登瓜步佛貍祠。", "請君收拾江山助，歸和薰風殿閣詩。"]'),
('634469d8-4dd3-49be-830a-79e6a824c134','送蔡德輝教授三首  其三','周必大','宋','宋诗','song-poetry','','[]','幾回送客大江頭，今渡江頭特地愁。',32,'全唐诗/poet.song.143000.json','["幾回送客大江頭，今渡江頭特地愁。", "豈是陽關動凄怨，同僚情分正綢繆。"]'),
('768c80f7-158d-4cc3-b057-18eb4f0395cf','送徐漕移憲浙東二首  其一','周必大','宋','宋诗','song-poetry','','[]','一去中臺十九年，愛君憂國得華顛。',64,'全唐诗/poet.song.143000.json','["一去中臺十九年，愛君憂國得華顛。", "久疑使節留江上，稍喜除書近日邊。", "寒碧軒窗餘舊句，汗青簡冊奏新篇。", "文章入相公家舊，沙路從今穩著鞭。"]'),
('0f24ed8c-028e-40d6-a1bb-bdd65fac8875','送徐漕移憲浙東二首  其二','周必大','宋','宋诗','song-poetry','','[]','滿歲蹣跚泮水間，獨公不作腐儒看。',64,'全唐诗/poet.song.143000.json','["滿歲蹣跚泮水間，獨公不作腐儒看。", "幾陪佳客芙蓉幕，聊慰窮愁苜蓿槃。", "此去高山空自仰，向來流水爲誰彈。", "割鞭截鐙知無益，但覺輪囷激肺肝。"]'),
('360693dc-cedc-42aa-9017-f6821b555ec3','送子開弟還江西','周必大','宋','宋诗','song-poetry','','[]','十年樂家居，豈知離別愁。',240,'全唐诗/poet.song.143000.json','["十年樂家居，豈知離別愁。", "言遊冠蓋場，聚散靡自由。", "子從何方來，訪我金陵州。", "情多語反默，喜極涕翻流。", "不如並轡出，庶以寫我憂。", "沉沉長干寺，南軒清且幽。", "烏衣訪王謝，湮滅那可求。", "却登覽輝亭，下瞰白鷺洲。", "羣山競合沓，萬室相牽鈎。", "回首指鍾阜，黎明戒前騶。", "林泉與臺殿，勝處皆窮搜。", "紛紛六朝舊，莽莽今幾邱。", "弔古轍未環，劇談興方稠。", "胡爲理書劍，復欲從遠遊。", "蹉跎六年別，邂逅半月留。", "臨分敢不盡，苦語誠非偷。", "期子如良農，勤勤事西疇。", "慎勿因水旱，而令廢鋤耰。", "豐歲會可必，行行真有秋。", "十月風霜動，待子江之頭。"]'),
('6095c94c-44c9-437a-ae2b-a879f5c503e6','送張端明赴召  其一','周必大','宋','宋诗','song-poetry','','[]','春殿曾收最上科，甘泉扈駕早鳴珂。',32,'全唐诗/poet.song.143000.json','["春殿曾收最上科，甘泉扈駕早鳴珂。", "金陵已奏三年課，玉燭宜調四氣和。"]'),
('523c7d09-67f0-43f8-8a7e-590511780b39','送張端明赴召  其二','周必大','宋','宋诗','song-poetry','','[]','家傳圯上一編書，二紀論思只緒餘。',32,'全唐诗/poet.song.143000.json','["家傳圯上一編書，二紀論思只緒餘。", "此去籌帷方倚重，赤松那得便從渠。"]'),
('74dfa936-0106-49e1-8f4d-af6b1307ce5c','送張端明赴召  其三','周必大','宋','宋诗','song-poetry','','[]','歸粟招提刻翠珉，羯胡稽首歎名臣。',32,'全唐诗/poet.song.143000.json','["歸粟招提刻翠珉，羯胡稽首歎名臣。", "今聞整轡登廊廟，應有先聲讋四隣。"]'),
('818c7cb9-4125-4b24-aa7f-07cc3ffde0e0','送張端明赴召  其四','周必大','宋','宋诗','song-poetry','','[]','管籥分來二十年，何人從此得朝天。',32,'全唐诗/poet.song.143000.json','["管籥分來二十年，何人從此得朝天。", "介圭入覲由公始，莫把題名取次鎸。"]'),
('c533a562-bb6e-4510-b028-059ec878b92d','送張端明赴召  其五','周必大','宋','宋诗','song-poetry','','[]','曾以詩書化蜀人，更恢文教大江垠。',32,'全唐诗/poet.song.143000.json','["曾以詩書化蜀人，更恢文教大江垠。", "諸生亦有如何武，爭詠三章轉上聞。"]'),
('c7124465-c96e-4877-ba70-c560d94c81c6','送張端明赴召  其六','周必大','宋','宋诗','song-poetry','','[]','心正能教筆不欹，古來書法獨公知。',32,'全唐诗/poet.song.143000.json','["心正能教筆不欹，古來書法獨公知。", "顔筋柳骨留蕭寺，總是甘棠去後思。"]'),
('b8d79653-35c4-4f03-99df-9fd8443cc6b6','送張端明赴召  其七','周必大','宋','宋诗','song-poetry','','[]','尺一催歸侍冕旒，邦人無路止前騶。',32,'全唐诗/poet.song.143000.json','["尺一催歸侍冕旒，邦人無路止前騶。", "却因遥祝南山壽，小作臺城十日留。"]'),
('29db0436-ee8a-4229-bc65-8ea57af30fc4','送張端明赴召  其八','周必大','宋','宋诗','song-poetry','','[]','延英引對寵章新，都下傳觀拜輔臣。',32,'全唐诗/poet.song.143000.json','["延英引對寵章新，都下傳觀拜輔臣。", "沙路緩驅金騕褭，閣間新上玉麒麟。"]'),
('822e6304-a4f3-4368-994e-1c039a3333b3','送張端明赴召  其九','周必大','宋','宋诗','song-poetry','','[]','公門如海亦如龍，解榻鈴齋獨見容。',32,'全唐诗/poet.song.143000.json','["公門如海亦如龍，解榻鈴齋獨見容。", "慚愧深知何以報，歲寒千尺澗邊松。"]'),
('a21ca40b-fb31-4583-b66c-53263ac01e10','送張端明赴召  其一○','周必大','宋','宋诗','song-poetry','','[]','欲驅羸馬從金鞍，顧藉微官進自難。',32,'全唐诗/poet.song.143000.json','["欲驅羸馬從金鞍，顧藉微官進自難。", "但願斯民均暖律，小儒不歎廣文寒。"]'),
('65533703-d779-4045-9df9-b4432469e9a1','送沈世德撫幹還朝','周必大','宋','宋诗','song-poetry','','[]','元戎已趣曹裝覲，上客難教儉幕留。',64,'全唐诗/poet.song.143000.json','["元戎已趣曹裝覲，上客難教儉幕留。", "積雨半篙生別浦，清風十幅送歸舟。", "槐庭衮綉行虞侍，芸閣鉛黄待校讎。", "池有遊鱗雲有鴈，尺書能寄故人不。"]'),
('c378708c-33a6-492f-94f0-8e7e3db9d313','次韻徽州胡推官旅中遇雪且約同登雨花臺三首  其一','周必大','宋','宋诗','song-poetry','','[]','歲晚相逢古帝鄉，長松百尺傲冰霜。',32,'全唐诗/poet.song.143000.json','["歲晚相逢古帝鄉，長松百尺傲冰霜。", "青鞋踏遍江南岸，更賦名花似漫郎。"]'),
('db2f26c5-0e2c-480f-925d-6938d556fe2e','次韻徽州胡推官旅中遇雪且約同登雨花臺三首  其二','周必大','宋','宋诗','song-poetry','','[]','傳道詩仙折簡來，破卷雪屋爲君開。',32,'全唐诗/poet.song.143000.json','["傳道詩仙折簡來，破卷雪屋爲君開。", "要將好句誇張籍，故放歌謠吏部才。"]'),
('7aa5666b-b9df-433b-893c-5638a755f05d','次韻徽州胡推官旅中遇雪且約同登雨花臺三首  其三','周必大','宋','宋诗','song-poetry','','[]','天女來參彼上人，逆知君動雨花心。',32,'全唐诗/poet.song.143000.json','["天女來參彼上人，逆知君動雨花心。", "故令六出繽紛下，免使荒臺更重臨。"]'),
('3db262d7-cfd9-4153-813b-c1707ce41867','方孺人挽詞','周必大','宋','宋诗','song-poetry','','[]','處士詩名滿古今，外家文采切星辰。',64,'全唐诗/poet.song.143000.json','["處士詩名滿古今，外家文采切星辰。", "中郎有女曾傳業，武子趨庭更慰人。", "諼草正開堂北向，扶桑莫返日西淪。", "可憐寂寞湘江路，燐走螢飛翠柏新。"]'),
('4a6255b2-f239-4657-9eaf-a4fe8933fa24','送別邢懷正直閣赴江西提舉二首  其一','周必大','宋','宋诗','song-poetry','','[]','大江西畔米流脂，歛散新陳倚綉衣。',64,'全唐诗/poet.song.143000.json','["大江西畔米流脂，歛散新陳倚綉衣。", "旗展春山千嶺暗，霜飛暑路萬艘歸。", "朝家法備農商信，臺府官閒案牘稀。", "廬阜虎溪天下景，未妨行部款禪扉。"]'),
('1f407e25-10fe-4d77-8837-41ad33c355b8','送別邢懷正直閣赴江西提舉二首  其二','周必大','宋','宋诗','song-poetry','','[]','二年疏懶累深知，喜見皇華授節時。',64,'全唐诗/poet.song.143000.json','["二年疏懶累深知，喜見皇華授節時。", "歸里欲依東道主，登畿恰負北山移。", "黄間遥想前驅弩，白下空攀遠別枝。", "坐席未溫公入覲，却教南蕩候旌麾。"]'),
('ad3f77cf-9d1d-41d0-bdd6-3372971e6fc8','留別金陵韓帥二首  其一','周必大','宋','宋诗','song-poetry','','[]','十二麟符玉截肪，腰間仍映带圍黄。',64,'全唐诗/poet.song.143000.json','["十二麟符玉截肪，腰間仍映带圍黄。", "化行江國春常早，訟息階除日自長。", "槐影緩趨三接晝，棠陰先滿十連堂。", "子淵去踏長安道，待賦中和奏未央。"]'),
('ab794670-a355-42e8-81f8-6bff7930d627','留別金陵韓帥二首  其二','周必大','宋','宋诗','song-poetry','','[]','再點賓筵又一期，千金敝帚頼提撕。',64,'全唐诗/poet.song.143000.json','["再點賓筵又一期，千金敝帚頼提撕。", "泮宮正采僖侯藻，太學俄甘吏部虀。", "人似塞鴻春向北，心隨江水日潮西。", "太平勳業須公助，不用頻年戀節犀。"]'),
('7e006327-34a9-48fb-9053-1073d8626b07','留別蘇仁仲通判','周必大','宋','宋诗','song-poetry','','[]','公才豈合尚題輿，天遣寒儒此曳裾。',64,'全唐诗/poet.song.143000.json','["公才豈合尚題輿，天遣寒儒此曳裾。", "午夜燈光曾共賞，三春樂事未全疏。", "尊前窈窕傳新唱，耳畔瀾翻聽異書。", "此別不須勤怨惜，君王日日問嚴徐。"]'),
('d9dbfe38-a5c9-49b6-815b-b2c3e183584b','九日哭子柔弟','周必大','宋','宋诗','song-poetry','','[]','自酹黄花酒，心酸苦淚零。',24,'全唐诗/poet.song.143000.json','["自酹黄花酒，心酸苦淚零。", "常時愛鳴鴈，從此不堪聽。"]'),
('225afd95-7f89-4498-b0e6-68ed24567487','劉韶美監丞以予發策玉堂小詩送筆墨云腹囊英物吐長虹翰墨區區有底功也要同盟作旗鼓三山直上一帆風走筆次韻時在雨中','周必大','宋','宋诗','song-poetry','','[]','風雨驚呼未霽虹，筆精墨妙策新功。',32,'全唐诗/poet.song.143000.json','["風雨驚呼未霽虹，筆精墨妙策新功。", "要令快草三千牘，故借泠然九萬風。"]'),
('742d93f1-3b2f-426c-a290-ddcfc6b0ac12','次韻程泰之正字奉祠惠照院詠雪五首  其一','周必大','宋','宋诗','song-poetry','','[]','天女飛花現化城，禪房深處想神清。',32,'全唐诗/poet.song.143000.json','["天女飛花現化城，禪房深處想神清。", "齋心正使無低唱，擁鼻何妨效洛生。"]'),
('7e19b7bc-02c6-44fd-bfd7-a9396e577c9d','次韻程泰之正字奉祠惠照院詠雪五首  其二','周必大','宋','宋诗','song-poetry','','[]','造化平心混萬殊，高低一色眩離朱。',32,'全唐诗/poet.song.143000.json','["造化平心混萬殊，高低一色眩離朱。", "如何尚愛南枝瘦，偏以凝脂助曼膚。"]'),
('134848d4-bcd1-4194-aab5-71c9cf50c31c','次韻程泰之正字奉祠惠照院詠雪五首  其三','周必大','宋','宋诗','song-poetry','','[]','方丈仙人定好奇，行吟合璧作瓊蕤。',32,'全唐诗/poet.song.143000.json','["方丈仙人定好奇，行吟合璧作瓊蕤。", "兔園且就如今賦，鳳沼重看異日詩。"]'),
('c5f14ae6-a2bb-43ab-a2bf-996a0265b8ca','次韻程泰之正字奉祠惠照院詠雪五首  其四','周必大','宋','宋诗','song-poetry','','[]','吻燥誰濡翰墨場，絕思齒煩漱甘芳。',32,'全唐诗/poet.song.143000.json','["吻燥誰濡翰墨場，絕思齒煩漱甘芳。", "粉身莫惜歸湯鼎，要與團龍發暗香。"]'),
('d7edc951-52d1-42a6-a19a-ca3f720aa016','次韻程泰之正字奉祠惠照院詠雪五首  其五','周必大','宋','宋诗','song-poetry','','[]','剝啄朝來送好音，唱妍酬麗自書林。',32,'全唐诗/poet.song.143000.json','["剝啄朝來送好音，唱妍酬麗自書林。", "柴門未掃簷垂溜，筆退誰知抱膝吟。"]'),
('d9a04354-6cc1-4e96-b7ae-8f05a4d2a349','胡原仲正字特改官除宮觀館中置酒餞別會者七人以先生早賦歸去來爲韻人各賦一首僕得早字','周必大','宋','宋诗','song-poetry','','[]','西伯王業興，海濱歸二老。',192,'全唐诗/poet.song.143000.json','["西伯王業興，海濱歸二老。", "漢家念羽翼，坐致商山皓。", "恭惟陛下聖，尊德繼雍鎬。", "先生學孔孟，不但遺編抱。", "致身雖苦晚，聞道固已早。", "昨隨弓旌招，著脚歷蓬島。", "夜陪藜杖青，朝奏囊封皂。", "第令坐臺閣，不減照乘寶。", "思歸獨何事，豈爲子規惱。", "祠官厚稟假，命秩畧資考。", "恩榮固無愧，出處吾有道。", "漫漫七閩路，去去春風好。", "都門送別處，懷抱要傾倒。", "相思常情耳，再拜請善禱。", "臨雍有故事，乞言非草草。", "指期裹蒲輪，未可迹如掃。"]'),
('d2b1b801-cc27-4c08-8061-8389c1ee9a06','送光祿寺丞李德遠得請奉祠','周必大','宋','宋诗','song-poetry','','[]','君家臨川我廬陵，兩郡相望宜相親。',128,'全唐诗/poet.song.143000.json','["君家臨川我廬陵，兩郡相望宜相親。", "長安城中初結綬，石灰橋畔還卜鄰。", "扣門問道日不足，篝燈照夜論心曲。", "寸莛那許撞洪鐘，跛鼈逝將隨驥騄。", "聞君上書苦求歸，君今豈是當歸時。", "滿朝留君君不顧，我雖歎息何能爲。", "莫攀楊柳濤江岸，莫唱陽關動凄斷。", "行行但祝加餐飯，潮落風生牢繫纜。"]'),
('d695d73a-9ad2-4dc1-a7e5-83f6c99c2705','次韻史院洪景盧檢詳館中紅梅','周必大','宋','宋诗','song-poetry','','[]','紅羅亭深宮漏遲，宮花四面誰得知。',128,'全唐诗/poet.song.143000.json','["紅羅亭深宮漏遲，宮花四面誰得知。", "蓬山移植自何世，國色含酒紛滿枝。", "初疑太真欲起舞，霓裳拂飾天然姿。", "又如東家窺牆女，施朱映粉尤相宜。", "不然朝雲頩薄怒，自持似對襄王時。", "須臾燕支著雨落，整裝俯照含風漪。", "遊蜂戲蝶日採掇，嗟爾何異氓之蚩。", "提壺火急就公飲，他日墮馬空啼眉。"]'),
('31da3728-968f-4b08-aec5-512ead81005c','次韻王龜齡大著省中黄梅','周必大','宋','宋诗','song-poetry','','[]','化工未幻酴醿菊，先放緗梅伴羣玉。',64,'全唐诗/poet.song.143000.json','["化工未幻酴醿菊，先放緗梅伴羣玉。", "幽姿著意慕鉛黄，正色何心輕萼綠。", "粧成自淺風味深，對此寧辭食無肉。", "可憐涪翁被渠惱，中歲梅屏杯杓醁。"]'),
('33fa3c19-2e63-40d8-9e04-8ed9e6c66859','送王嘉叟編修通判洪州','周必大','宋','宋诗','song-poetry','','[]','籍甚西樞掾，居然出處光。',48,'全唐诗/poet.song.143000.json','["籍甚西樞掾，居然出處光。", "人猶思賀監，天未起張良。", "南浦雲應碧，東湖柳正黄。", "古來求別駕，不是薄星郎。"]'),
('f0293b68-d9be-4d51-94c2-f54314951963','送王龜齡赴越州宗丞','周必大','宋','宋诗','song-poetry','','[]','冊府號冀北，一時聚奇材。',180,'全唐诗/poet.song.143000.json','["冊府號冀北，一時聚奇材。", "嗟我雖末至，尚及相追陪。", "胡子真老驥，元章蓋龍媒。", "爾來厭名韁，蹙踏游九垓。", "王子乃汗血，疑是西極徠。", "忠精貫日月，聲名震陪儓。", "君王市駿骨，得此七尺騋。", "秣以天山禾，貯之黄金臺。", "玉勒綉羅鞍，映带文錦韉。", "謂言開道路，亦復薄蓬萊。", "乞歸丞相府，連月書百回。", "東郊台公姓，笑渡濤江雷。", "奉身信美矣，體國安在哉。", "帝家十二閑，何嘗列駑駘。", "遲子復立仗，來歸勿徘徊。"]'),
('244004aa-58dc-47e0-86b4-7f843aaf1897','送聞人茂德刪定歸嘉禾','周必大','宋','宋诗','song-poetry','','[]','七年束带趁朝參，共喜儒林得指南。',64,'全唐诗/poet.song.143000.json','["七年束带趁朝參，共喜儒林得指南。", "經傳注成頭未白，公卿閲徧綬猶藍。", "秋來去國懷張翰，此去論詩憶鄭覃。", "別酒易闌情不盡，會憑清夢聽清談。"]'),
('cd2bed14-860f-41f0-96f3-6ed9ef61e076','去秋芮國器以詩賀入館今渠繼來次韻','周必大','宋','宋诗','song-poetry','','[]','一自傳刀夢，遲君已隔秋。',48,'全唐诗/poet.song.143000.json','["一自傳刀夢，遲君已隔秋。", "浪傳迷弱水，未省礙虛舟。", "天子方神武，狂胡敢寇讎。", "應須漢充國，早晚與兵謀。"]'),
('17c08dec-7683-4fe1-904a-b646e547986d','陸務觀病彌旬僕不知也佳篇謝鄰里次韻自解','周必大','宋','宋诗','song-poetry','','[]','閉戶十日雨，陸居如坐舫。',120,'全唐诗/poet.song.143000.json','["閉戶十日雨，陸居如坐舫。", "吾身固已困，未省子疾狀。", "昨朝拜床前，不敏祇自愴。", "蕭然維摩几，高謝桓榮帳。", "是身本何有，更慮不已恙。", "全人豆肩肩，大癭誰甕盎。", "擲杯蛇自去，靜耳蟻爲諒。", "乃知閲肘後，未免信紙上。", "大哉橫氣機，寄此語清壯。", "我雖問疾晚，可以無悵怏。"]'),
('cde66cae-a809-409e-b815-af766961b0eb','次韻芮國器正字館中木樨三首  其一','周必大','宋','宋诗','song-poetry','','[]','多生定自爲黄卷，一念無如魚蠹何。',32,'全唐诗/poet.song.143000.json','["多生定自爲黄卷，一念無如魚蠹何。", "今度前身散金粟，芸香從此不須多。"]'),
('36ca0a28-3ef3-41bb-98cb-272f131b55c4','次韻芮國器正字館中木樨三首  其二','周必大','宋','宋诗','song-poetry','','[]','曉翻汗簡因遮眼，午對枯枰輒爛柯。',32,'全唐诗/poet.song.143000.json','["曉翻汗簡因遮眼，午對枯枰輒爛柯。", "天遣幽香一喚起，醒然頓作出瓶鵝。"]'),
('909c27cd-30c3-4d50-a545-99c1fd7b8c09','次韻芮國器正字館中木樨三首  其三','周必大','宋','宋诗','song-poetry','','[]','怪底花開已兩回，先生儤直未銜杯。',32,'全唐诗/poet.song.143000.json','["怪底花開已兩回，先生儤直未銜杯。", "若猶不領渠儂意，猶向階前一再開。"]'),
('358b0c0a-5d80-46bf-af7c-43748c115da7','慧海大師日智索詩  其一','周必大','宋','宋诗','song-poetry','','[]','人人飽食即安眠，慙愧師營粥飯緣。',32,'全唐诗/poet.song.143000.json','["人人飽食即安眠，慙愧師營粥飯緣。", "三篾繞身猶未解，齋厨已報爨無烟。"]'),
('84623409-b99a-4322-bc54-e68301c81f6a','慧海大師日智索詩  其二','周必大','宋','宋诗','song-poetry','','[]','徑山說法口瀾翻，慧海精勤三十年。',32,'全唐诗/poet.song.143000.json','["徑山說法口瀾翻，慧海精勤三十年。", "他日宣城傳僧寶，莫分禪律一時編。"]'),
('42403834-9d6f-491f-8d8a-2ef08dd98f37','湯孺人挽詞','周必大','宋','宋诗','song-poetry','','[]','歎息閨房秀，霜摧鬢未華。',48,'全唐诗/poet.song.143000.json','["歎息閨房秀，霜摧鬢未華。", "女功丞相念，婦道里人嗟。", "石窌脂田廢，濤江粉旐斜。", "西風看花淚，寂寞小窗紗。"]'),
('74905f7a-12f8-4537-9a73-dbad40a1c9b3','年家太夫人鄭氏挽詞','周必大','宋','宋诗','song-poetry','','[]','早適王孫貴，中成令子名。',48,'全唐诗/poet.song.143000.json','["早適王孫貴，中成令子名。", "齊眉餘婦順，截髮助交情。", "三釜應天相，重泉奈日傾。", "升堂今已矣，淚灑越溪橫。"]'),
('f307b66e-7e9e-4ea7-b695-6c5a4f5f09b4','王季海正言父宣義挽詞','周必大','宋','宋诗','song-poetry','','[]','三世儒科獨隠淪，功名豈必在吾身。',64,'全唐诗/poet.song.143000.json','["三世儒科獨隠淪，功名豈必在吾身。", "早看伯氏囊荷舊，晚喜郎君諫草新。", "絳縣人存疑甲子，論衡書就困庚辛。", "遥知會葬車千兩，絮酒淋漓卧冢麟。"]'),
('3762f1c6-6816-460e-b591-fb1d0c894902','送司農少卿杜起莘出守遂寧','周必大','宋','宋诗','song-poetry','','[]','識公七年前，青衫騎破韉。',132,'全唐诗/poet.song.143000.json','["識公七年前，青衫騎破韉。", "送公七年後，金章大州守。", "窮達反掌耳，置之勿復論。", "憶公出蜀日，避名如避喧。", "神羊一在首，慷慨眉宇軒。", "朝陳擊奸疏，暮進興邦言。", "炎炎中郎將，解带西南奔。", "矯矯內押班，掛冠神武門。", "所以杜御史，姓名滿乾坤。", "人生有聚散，安所非游宦。", "徵黄不作難，聖主方味諫。"]'),
('9ed1ea65-cbe7-447d-ba93-1adc6c6a46cf','次韻張真父著作遊湖山','周必大','宋','宋诗','song-poetry','','[]','今休閣鉛黄，昔念長安遠。',168,'全唐诗/poet.song.143000.json','["今休閣鉛黄，昔念長安遠。", "出遊寫我憂，駕言豈顧返。", "撐舟度平湖，蠟屐試疊巘。", "境幽客更佳，風靜日亦烜。", "爾僕毋告勞，我足尚忘蹇。", "眼明見孤山，地禁接上苑。", "却登靈隠寺，巖壑此其本。", "經行盡精舍，一一爲排鍵。", "勝游固可繼，况乃春未晚。", "所嗟蟣蝨臣，無術助龍衮。", "頗聞議深討，將士不及飯。", "古稱格苗頑，不必侵自阮。", "吾民戰吾地，甌脫未少損。", "願言休王師，歲熟禾自稛。"]'),
('b1ecf9ec-c8a9-4eac-bf77-d114f0926aef','次韻真父著庭緗梅','周必大','宋','宋诗','song-poetry','','[]','繭黄織就費天機，付與園林晚出枝。',64,'全唐诗/poet.song.143000.json','["繭黄織就費天機，付與園林晚出枝。", "東觀奇童承詔後，南昌故尉欲仙時。", "芳心向日重重展，清馥因風細細知。", "詩老品題猶誤在，紅梅未是獨開遲。"]'),
('d4c20e74-863d-45c0-adbe-175caa64481a','送馮圓仲吏部出守邛州  其一','周必大','宋','宋诗','song-poetry','','[]','戰伐驚前日，安危决此時。',48,'全唐诗/poet.song.143000.json','["戰伐驚前日，安危决此時。", "諸侯今有望，萬里子何之。", "市駿甘求骨，呼鷹苦待饑。", "寸心懸日月，不爲去來移。"]'),
('640b7116-0fce-4fa6-802e-a31805ae0749','送馮圓仲吏部出守邛州  其二','周必大','宋','宋诗','song-poetry','','[]','錐末藏銛利，刀頭愜寢興。',48,'全唐诗/poet.song.143000.json','["錐末藏銛利，刀頭愜寢興。", "爲郎非白首，補郡有高能。", "交分看前輩，離愁愧老僧。", "亭亭望中塔，高處待重登。"]'),
('f571751d-32f6-4aa1-8336-907b7d587e9d','送湯相守紹興二十韻','周必大','宋','宋诗','song-poetry','','[]','漢闢蕭居守，周興畢保釐。',240,'全唐诗/poet.song.143000.json','["漢闢蕭居守，周興畢保釐。", "安危元注想，中外自隨時。", "憶昨生戎馬，誰知死佛貍。", "天其永我命，王乃大巡師。", "收拾鑪錘手，經綸管籥司。", "南圖忘震蕩，北上得逶迤。", "銅刻新符獸，金塗舊印龜。", "從容時屬耳，填撫效如斯。", "帝意仍調鼎，親榮寧擁麾。", "班衣加畫綉，通帛雜牙旗。", "餘力今循霸，洪鈞昔相夔。", "斯民先已覺，此地更何爲。", "玉帛塗山會，銀黄越將垂。", "圖經千古事，賓幕幾人詩。", "有客叨恩顧，無才負己知。", "身留蓬島直，夢度浙江湄。", "投劾難何有，登庸恐不遲。", "行逢三月褉，看即百錢齎。", "祖餞紛離席，班迎指後期。", "一夫非自喜，正爲太平基。"]'),
('0c066dfa-5e66-438d-8e33-3a3f627c65d2','次韻鄒德章監簿官舍芙蓉芭蕉','周必大','宋','宋诗','song-poetry','','[]','君不見蜀都之城百里長，無數芙蓉遮女牆。',230,'全唐诗/poet.song.143000.json','["君不見蜀都之城百里長，無數芙蓉遮女牆。", "遂令邦人記舊俗，往往空巷爭新妝。", "又不見雲夢澤中吞美惡，相如所夸殊落落。", "獨將巴且并蘭芷，楚客至今猶憶昨。", "兩邦不爲天下溪，顧乃著意濁水泥。", "眼看紅綠意先眩，玩物固應爲物迷。", "豈知弱質甚蒲柳，成毀須臾翻覆手。", "春風秋露畧紛敷，皓雪青霜已摧朽。", "主人學道窮三餘，俯視官舍真蘧廬。", "從渠草木榮與枯，只有此心常自如。", "水邊比色寧見素，隍中覆鹿初何據。", "似耶非耶誰與論，彼夢我夢隨所住。", "大篇字字皆披沙，清晨走送驚鄰家。", "鈍根也復發深省，世間何物非空花。"]'),
('766c5b91-7477-4462-85a7-821779858c7e','奉常林黄中博士以黄甘食陸務觀司直陸賦長句林邀予次韻','周必大','宋','宋诗','song-poetry','','[]','林子勇報國，太華欲力擘。',168,'全唐诗/poet.song.143000.json','["林子勇報國，太華欲力擘。", "吾嘗歎其材，浮海中巨舶。", "向來固不用，今用猶迫迮。", "比興柑纍纍，霜飽實未摘。", "不使供王羞，何異棄道側。", "山東一百郡，風氣久限隔。", "子如又思歸，殊勳定誰冊。", "孝哉狄梁公，竚立望雲白。", "親舍豈不念，王事正求索。", "前聞獻果餘，手餉懷橘客。", "雖非木奴千，殆過庭實百。", "兩公相親意，初不主殽核。", "當于古人求，未可度以臆。", "如我乃無用，甘作下惠阨。"]'),
('3d764dbc-70c0-4b12-bd30-8a9b682e42c9','許陸務觀館中海棠未與而詩來次韻','周必大','宋','宋诗','song-poetry','','[]','莫嗔芳意太矜持，曾得三郎觱篥吹。',32,'全唐诗/poet.song.143000.json','["莫嗔芳意太矜持，曾得三郎觱篥吹。", "今日若無工部句，慇懃猶惜最殘枝。"]'),
('1a20b589-1bbf-4751-8c63-cdab8e4bb62e','以紅碧二色桃花送務觀','周必大','宋','宋诗','song-poetry','','[]','碧雲欲合带紅霞，知是秦人洞裏花。',32,'全唐诗/poet.song.143000.json','["碧雲欲合带紅霞，知是秦人洞裏花。", "俗眼只應窺燕麥，不如送與謫仙家。"]'),
('ea214769-9f33-404e-80b3-89ef12fe5cb4','范致能以詩求二色桃再次韻二首  其一','周必大','宋','宋诗','song-poetry','','[]','霓裳舞罷醉流霞，翠袖頻揎眼欲花。',32,'全唐诗/poet.song.143000.json','["霓裳舞罷醉流霞，翠袖頻揎眼欲花。", "丈室蕭然那用此，春深料得客思家。"]'),
('7eefb852-f077-4b57-a8f5-4121dcb83e75','范致能以詩求二色桃再次韻二首  其二','周必大','宋','宋诗','song-poetry','','[]','翰墨場中蔡少霞，如今悟徹頌桃花。',32,'全唐诗/poet.song.143000.json','["翰墨場中蔡少霞，如今悟徹頌桃花。", "看朱成碧吾方眩，試把橫枝問作家。"]'),
('0e84b5d6-a2e3-41e2-b683-0ef1fc1e0275','劉信叔太尉挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','今代詩書帥，收功百戰餘。',48,'全唐诗/poet.song.143000.json','["今代詩書帥，收功百戰餘。", "人誰不開府，公獨带除書。", "死後家無甔，生前客有車。", "輕財并待士，此意果何如。"]'),
('47d10874-a0c3-42ef-a5d6-7fd9494dc5e2','劉信叔太尉挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','不謂擒胡月，妖星犯將營。',48,'全唐诗/poet.song.143000.json','["不謂擒胡月，妖星犯將營。", "伊吾空有志，渭上不成耕。", "衆議磨圭玷，他年聽鼓聲。", "何妨築高冢，爲象順昌城。"]'),
('ce1ccfa5-1c20-4625-87a6-32c2fddb6501','務觀得曾吉甫茶反以詩見遺因次其韻','周必大','宋','宋诗','song-poetry','','[]','詩仙餉予北苑雪，正欲一洗東華塵。',32,'全唐诗/poet.song.143000.json','["詩仙餉予北苑雪，正欲一洗東華塵。", "道山廷尉俱夢事，喚醒野軒真主人。"]'),
('a65d8bd4-f2e4-463a-90aa-e1cb427fa094','送洪景盧舍人北使','周必大','宋','宋诗','song-poetry','','[]','嘗記揮毫草檄初，必知鳴鏑集單于。',64,'全唐诗/poet.song.143000.json','["嘗記揮毫草檄初，必知鳴鏑集單于。", "由來筆下三千牘，可勝軍中十萬夫。", "已許乞盟朝渭上，不妨持節過幽都。", "吾君甚似仁皇帝，宜有韓公贊廟謨。"]'),
('cc9f3e96-ffa1-4501-94d4-c436e599bcc8','次韻務觀迎駕','周必大','宋','宋诗','song-poetry','','[]','法駕朝西內，諸臣許後陪。',48,'全唐诗/poet.song.143000.json','["法駕朝西內，諸臣許後陪。", "蹕煩民更喜，鳶載路無埃。", "我輩猶簪筆，君才合面槐。", "如何車九九，獨不與偕來。"]'),
('dccc74f1-b527-42ca-ad73-fbd80c8fc232','次子中兄韻三首  其一','周必大','宋','宋诗','song-poetry','','[]','獻納深慙杜少陵，驟紆皇眷秩頻增。',32,'全唐诗/poet.song.143000.json','["獻納深慙杜少陵，驟紆皇眷秩頻增。", "羽書日日驚飛電，給札歸來欲飲冰。"]'),
('d7acd0cc-af90-4aea-ab65-3e6b595a58ae','次子中兄韻三首  其二','周必大','宋','宋诗','song-poetry','','[]','讀罷新詩暖似春，手摇食指舌生津。',32,'全唐诗/poet.song.143000.json','["讀罷新詩暖似春，手摇食指舌生津。", "平生口腹何曾計，自笑如今枉累人。"]'),
('45079a85-d914-4f48-9616-450cb551cf90','次子中兄韻三首  其三','周必大','宋','宋诗','song-poetry','','[]','黄道初開日月新，容光應不間孤臣。',64,'全唐诗/poet.song.143000.json','["黄道初開日月新，容光應不間孤臣。", "左螭立近焚香案，右掖名參視草人。", "三聖深恩空刺骨，幾年歸夢已通神。", "阿兄念我勤招憶，好爲丹爐養汞銀。"]'),
('5268b172-04e9-4853-a7ea-42e86f2cb271','陸務觀編修以石芥送劉韶美吏部劉飲以勁酒二公皆舊鄰也因其有詩次韻二首  其一','周必大','宋','宋诗','song-poetry','','[]','芥辛酒苦却多情，田舍翁成嫵媚名。',32,'全唐诗/poet.song.143000.json','["芥辛酒苦却多情，田舍翁成嫵媚名。", "屋角風號天欲雪，胸中浩浩正春生。"]'),
('5a3fadcc-fd8a-4711-b63e-49738cf2f8b9','陸務觀編修以石芥送劉韶美吏部劉飲以勁酒二公皆舊鄰也因其有詩次韻二首  其二','周必大','宋','宋诗','song-poetry','','[]','自移家具失連牆，不復燈前共詠觴。',32,'全唐诗/poet.song.143000.json','["自移家具失連牆，不復燈前共詠觴。", "手裏有詩憐指動，甕邊無分笑頭方。"]'),
('aaca731a-bc58-422d-81a3-47f5c085ffd0','招陸務觀食江西笋歸有絕句云色如玉版貓頭筍味抵駝峰牛尾狸歸向妻孥誇至夕書生寒乞定難醫戲和','周必大','宋','宋诗','song-poetry','','[]','東厨日日厭侯鯖，却羨萍虀擣韭根。',32,'全唐诗/poet.song.143000.json','["東厨日日厭侯鯖，却羨萍虀擣韭根。", "如我乃真寒乞耳，只知肉味筍殊村。"]'),
('aacfb6d0-f6cf-4155-a9e7-84f8f255ea6f','次韻程泰之駕部送猴','周必大','宋','宋诗','song-poetry','','[]','團團擾擾便生憎，誰暇徐觀棘刺能。',32,'全唐诗/poet.song.143000.json','["團團擾擾便生憎，誰暇徐觀棘刺能。", "駕部猶嫌無駿馬，他人須用土牛乘。"]'),
('6066d723-bdf9-49f8-a26f-a8170374de41','寄題新居羅長卿觀瀾閣蘭堂二首  其一','周必大','宋','宋诗','song-poetry','','[]','大江來章貢，小江出香城。',180,'全唐诗/poet.song.143000.json','["大江來章貢，小江出香城。", "快哉一閣上，揖此二水清。", "江落波瀾靜，江漲波瀾驚。", "四時五變化，兩目常兼并。", "登臨苟得要，坐使萬象呈。", "吾聞鄒國軻，耻作么麽生。", "平生浩然氣，直與天地盈。", "觀水必觀瀾，寓言見真情。", "雨集溝澮間，肯把青眼橫。", "長卿軻之徒，胸中氣崢嶸。", "學障百川東，詞如三峽傾。", "此道素自得，此景宜天成。", "我本烟波徒，臨流嘗濯纓。", "他年理漁艇，往尋鷗鷺盟。", "倘繪新居圖，載我一葉輕。"]'),
('45e27bd2-2bef-4e59-a243-921cb5a0aaf7','寄題新居羅長卿觀瀾閣蘭堂二首  其二','周必大','宋','宋诗','song-poetry','','[]','君不見漢家築臺臨咸京，圖籍排比如魚鱗。',230,'全唐诗/poet.song.143000.json','["君不見漢家築臺臨咸京，圖籍排比如魚鱗。", "又不見晉人創亭稽山陰，羣賢畢集羅簪紳。", "古今名蘭固多矣，而此二者常不泯。", "乃知草木本無取，必假人物始可珍。", "夫君名高斗以南，築臺宛在江之漘。", "楚人盈要競服艾，羌獨滋蘭真絕倫。", "風摇綠葉劍戟舞，雨折香苞檀麝新。", "不寧充幃悅鼻觀，正自紉佩持吾身。", "堂奧藏書三萬軸，盡校魚魯分根銀。", "堂中延客三千履，可結僑札參雷陳。", "定知斯堂閲千載，與昔臺亭知共振。", "僕也生憎鮑魚肆，扣門屢作君家賓。", "小槽珠滴不待滿，有時旋漉頭上巾。", "醉留惡語涴君壁，有客如此君勿嗔。"]'),
('666e6bc3-77d0-430c-bb38-8e8d346b9793','讀史二首  其一','周必大','宋','宋诗','song-poetry','','[]','舜作九成樂，丹鳳儀其宮。',120,'全唐诗/poet.song.143000.json','["舜作九成樂，丹鳳儀其宮。", "周備既醉福，高岡始鳴桐。", "區區漢宣帝，雜覇期羣聾。", "惲誅廣漢族，一變高文風。", "德教既不任，覽輝理未通。", "惟昔周道衰，麟出大野中。", "尼父絕史筆，蓋傷吾道窮。", "漢治非虞周，鳳來與麟同。", "胡然潁川守，乃敢貪天功。", "下義上賞姦，甚哉其相蒙。"]'),
('4be814b1-5035-4a38-b5f6-aa15b0f386e2','讀史二首  其二','周必大','宋','宋诗','song-poetry','','[]','洪喬晉名士，恥爲致書郵。',120,'全唐诗/poet.song.143000.json','["洪喬晉名士，恥爲致書郵。", "扁舟石頭路，百函委湍流。", "惠固有不費，俛從諒何尤。", "性也倘自異，却之尚爲優。", "奈何負諾責，而令任沉浮。", "天報在爾子，晚解桓溫仇。", "答謝豈不審，何至空函投。", "坐此竟棄絕，侘傺歸山丘。", "乃知網恢恢，小惡靡不酬。", "寄語輕薄子，勿貽子孫憂。"]'),
('51ad420a-dc69-48e2-a6da-0fbb6667416a','漁父四時歌  其一','周必大','宋','宋诗','song-poetry','','[]','三湘七澤雲連水，短棹意行無遠邇。',80,'全唐诗/poet.song.143000.json','["三湘七澤雲連水，短棹意行無遠邇。", "江花時傍綠蓑飛，水鳥忽從清唱起。", "醉後懽呼踏浪兒，鮪可鱠兮秔可炊。", "芳草從教天樣遠，都無閒恨可萋迷。", "碧桃幾片來何處，試訪秦人武陵路。"]'),
('bcb10d34-0774-494b-b8e3-571867190aa2','漁父四時歌  其二','周必大','宋','宋诗','song-poetry','','[]','朝霞沉綺烏鵲興，釣車徐理桹一鳴。',80,'全唐诗/poet.song.143000.json','["朝霞沉綺烏鵲興，釣車徐理桹一鳴。", "夕蟾散金鷗鷺浴，乘流蕩槳清江曲。", "行人卓午汗如流，綠陰濃處杙扁舟。", "絲綸卷盡身無事，日長睡足風颼颼。", "覺來一觴仍起舞，未信人間有炎暑。"]'),
('b848782a-d313-4510-a0b4-c9f7c5a09a81','漁父四時歌  其三','周必大','宋','宋诗','song-poetry','','[]','世人只詠江如練，此景何曾眼中見。',80,'全唐诗/poet.song.143000.json','["世人只詠江如練，此景何曾眼中見。", "露零月白人已眠，萬頃風光儂自占。", "尊鱸况復生計優，酒醒還醉餘何求。", "有時閒看飛鴻字，斜倚篙竿不掉頭。", "曉來誰誤招招渡，一笑夤緣葦間去。"]'),
('b706409e-5ec7-4d29-b1a1-a6f89ce4ce5f','漁父四時歌  其四','周必大','宋','宋诗','song-poetry','','[]','白浪粘天雲覆地，津人斷渡征人喟。',80,'全唐诗/poet.song.143000.json','["白浪粘天雲覆地，津人斷渡征人喟。", "欲矜好手傲風波，故把扁舟恣游戲。", "雪蓑不博狐白裘，尺寸之膚暖即休。", "賣魚得錢沽美酒，翁媼兒孫交勸酬。", "田家禾熟疲輸送，樂哉篷底華胥夢。"]'),
('470d5d24-2dcc-4785-a521-74420844fdde','四禽','周必大','宋','宋诗','song-poetry','','[]','人言百舌巧，暑至輒無聲。',48,'全唐诗/poet.song.143000.json','["人言百舌巧，暑至輒無聲。", "不如鳩雖拙，四時知陰晴。", "提壺勸我飲，我醉誰解酲。", "布穀獨可聽，要當早歸耕。"]'),
('bde05ae9-d6a4-49a4-9dd0-d11c27445e15','恩許奉祠子中兄重寄臣字韻詩再次韻','周必大','宋','宋诗','song-poetry','','[]','迂儒豈足助維新，日奉威顔謝主臣。',64,'全唐诗/poet.song.143000.json','["迂儒豈足助維新，日奉威顔謝主臣。", "可罷本非緣一事，致疑初不怨三人。", "弟兄有祿供溫飽，畎畝何階答聖神。", "此去讀書真事業，向來正字誤根銀。"]'),
('e2af0c40-c2fa-4678-bb92-a59244ac9f19','次韻子中兄相迎詩中有奠松楸之語追念別後□叔母子柔下世故卒章及之','周必大','宋','宋诗','song-poetry','','[]','浙水秦淮度十霜，官清誰薄簡編香。',64,'全唐诗/poet.song.143000.json','["浙水秦淮度十霜，官清誰薄簡編香。", "春來怪底鳥烏樂，歸去喜同燈燭光。", "身近廣寒猶內熱，手遮赫日却心凉。", "只愁初踏江邊路，封土累然似斧堂。"]'),
('a2aad9bf-89b0-4e61-a660-2a11348c02c0','次韻陸務觀送行二首  其一','周必大','宋','宋诗','song-poetry','','[]','蓬閣虛生白，蘭臺汗殺青。',48,'全唐诗/poet.song.143000.json','["蓬閣虛生白，蘭臺汗殺青。", "英遊迷歲月，神武動風霆。", "遷擢恩頻忝，黔黎困未醒。", "空希范蠡去，羞對浙江亭。"]'),
('44c6c4b4-21e2-417b-8a68-f26f90cdeb8b','次韻陸務觀送行二首  其二','周必大','宋','宋诗','song-poetry','','[]','議論今誰及，詞章更可宗。',48,'全唐诗/poet.song.143000.json','["議論今誰及，詞章更可宗。", "三年依玉樹，一別送塵容。", "盡日尋山寺，思君傍塞烽。", "五言何敢續，持用當緘封。"]'),
('122fc63e-f807-44f1-9ccc-187a5bd2e82a','張淵道侍郎挽詞二首  其一','周必大','宋','宋诗','song-poetry','','["\u8861\u5c71"]','籍甚中興日，歸歟載戢秋。',48,'全唐诗/poet.song.143000.json','["籍甚中興日，歸歟載戢秋。", "周旋黄石法，邂逅赤松遊。", "名與衡山埒，身隨楚水流。", "若爲窺智勇，家世本留侯。"]'),
('0cffefd7-e1be-4a9c-a6e3-64faa00f4964','張淵道侍郎挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','南國頻移鎮，西清疊進班。',48,'全唐诗/poet.song.143000.json','["南國頻移鎮，西清疊進班。", "衮衣元繾綣，貝錦謾斕斑。", "斜日逢單閼，流金識大還。", "惟餘千字誄，傳誦滿人間。"]'),
('e7eb12f5-d9df-4caa-84f9-7f3d7a7a4778','重九竹園見梨花懷子中兄','周必大','宋','宋诗','song-poetry','','[]','春花著雨即塵埃，何似深秋耐久開。',64,'全唐诗/poet.song.143000.json','["春花著雨即塵埃，何似深秋耐久開。", "菊尚無多饒瑞質，霜如有意護香腮。", "也知林下風光早，不爲山中曆日催。", "望斷行人思折寄，却疑呼作嶺頭梅。"]'),
('4cde2c78-a675-40d6-b9b6-160dc0a3defb','九月十八日夜忽夢作送王龜齡詩兩句枕上足成之','周必大','宋','宋诗','song-poetry','','[]','匈奴何敢渡江東，一士真過萬馬雄。',64,'全唐诗/poet.song.143000.json','["匈奴何敢渡江東，一士真過萬馬雄。", "唐室安危誰可佩，雪山輕重屬之公。", "天臺不納尚書履，鄉縣猶乘御史驄。", "行樂休嫌園小小，高歌幸有婢隆隆。"]'),
('226331c9-af1f-40cc-a805-8226fe2664c2','寄題龍泉孫大同司戶三桂堂','周必大','宋','宋诗','song-poetry','','[]','山居速化植千荻，孫家種木惟種德。',69,'全唐诗/poet.song.143000.json','["山居速化植千荻，孫家種木惟種德。", "一朝仙籍浮桂香，昔笑其迂今改色。", "鄰翁笞兒乞條枚，條枚不惜莫浪栽。", "君不見天街十二綠槐滿，獨有城東之槐應三台。"]'),
('64b62982-e831-48ee-9f1e-1a406b6cbbf5','題神岡廟其神蓋六朝時劉竺使君也','周必大','宋','宋诗','song-poetry','','[]','岸斷川平拔一峯，丹青剝落古靈宮。',64,'全唐诗/poet.song.143000.json','["岸斷川平拔一峯，丹青剝落古靈宮。", "邦人歲久忘遺愛，賈客時來乞好風。", "二水有情猶磬折，霜楓無數尚旗紅。", "岡頭故址宜亭榭，城郭江山盡眼中。"]'),
('39263440-6923-480d-b7df-749b59fa42c7','去年會慶節初定上壽儀敕差翰林承旨今樞密洪景嚴攝殿中監執酒盞予攝少監以酒注于盞既而準故事權停此禮但拜表文德殿下從駕朝德壽宮今年赴永和寺觀罷散武弁三數人而已有感成小詩','周必大','宋','宋诗','song-poetry','','[]','去歲茲辰侍赤墀，詔黄親許奉瑶巵。',32,'全唐诗/poet.song.143000.json','["去歲茲辰侍赤墀，詔黄親許奉瑶巵。", "如今不及封人賤，猶對君王效祝辭。"]'),
('87f4c86e-7532-4f98-9d20-c91330de6eec','再次去年子中兄送黄雀不至韻','周必大','宋','宋诗','song-poetry','','[]','祝壽筵開正小春，兄酬弟勸喜津津。',32,'全唐诗/poet.song.143000.json','["祝壽筵開正小春，兄酬弟勸喜津津。", "披綿走送非無意，小愧乘成多忘人。"]'),
('da04e9d3-61bf-4c02-a6dc-c071f6051f17','送芮國器察院漕廣東','周必大','宋','宋诗','song-poetry','','[]','星聚曾尊德，箕張客避風。',48,'全唐诗/poet.song.143000.json','["星聚曾尊德，箕張客避風。", "別離雙鬢異，邂逅一尊同。", "五嶺皇華使，扁舟漁釣翁。", "江分鴻不到，書札若爲通。"]'),
('41461679-3c1f-4c68-b53c-4119557e4ad6','龍須道中','周必大','宋','宋诗','song-poetry','','[]','客勞田頭餉，渠憐馬上郎。',24,'全唐诗/poet.song.143000.json','["客勞田頭餉，渠憐馬上郎。", "作勞并罄控，未用別閒忙。"]'),
('6c467778-d68b-4e0c-ac48-593509dc31ae','同子中兄遊龍須吉祥善生諸寺歸至柞樹渡大風雨中登舟','周必大','宋','宋诗','song-poetry','','[]','徧尋山寺穿雲子，歸戲風波踏浪兒。',32,'全唐诗/poet.song.143000.json','["徧尋山寺穿雲子，歸戲風波踏浪兒。", "事業如斯官給廩，廬陵米貴有人饑。"]'),
('30cc2707-cc77-455d-a3ae-744454709b20','甲申中秋子中兄賦詩有人月分圓二十年之句蓋歎中間多難且離別未嘗爲會也次韻','周必大','宋','宋诗','song-poetry','','[]','世事渾如蚋過前，刀頭喜對鏡飛天。',64,'全唐诗/poet.song.143000.json','["世事渾如蚋過前，刀頭喜對鏡飛天。", "陰晴萬里同茲夕，離別前時照幾年。", "此去莫令疎會合，從來無意必騰騫。", "幾思種秫迎佳節，窮鬼還來笑買田。"]'),
('945b51d8-a87d-41db-a6bd-417bb625e501','夜坐困甚','周必大','宋','宋诗','song-poetry','','[]','馬通新熟夜爐深，拄膝承頦夢欲成。',32,'全唐诗/poet.song.143000.json','["馬通新熟夜爐深，拄膝承頦夢欲成。", "不記坐來湯沸鼎，却疑蓬底聽灘聲。"]'),
('4a2c5a78-7b3d-498e-8c82-fb78be691fd7','乘成臺觀雪憶子上兄','周必大','宋','宋诗','song-poetry','','[]','南雪霏微積便晞，兒童只慣管中窺。',64,'全唐诗/poet.song.143000.json','["南雪霏微積便晞，兒童只慣管中窺。", "誰知今歲望不斷，天與一臺成此奇。", "苔護屐痕氈疊疊，松垂談麈玉枝枝。", "團欒忽憶新令尹，天際帆飛歸不疑。"]'),
('b9946595-5405-4b65-a817-8e75faab1507','次韻王少府送焦坑茶','周必大','宋','宋诗','song-poetry','','[]','昏然午枕困漳濱，醒以清風頼子真。',64,'全唐诗/poet.song.143000.json','["昏然午枕困漳濱，醒以清風頼子真。", "初似參禪逢硬語，久如味諫得端人。", "王程不趁清明宴，野老先分浩蕩春。", "敢向柘羅評綠玉，待君同碾試飛塵。"]'),
('3f28cae6-1bca-4a3b-84f8-49c4239e661b','同年劉辰告妻易氏挽詞','周必大','宋','宋诗','song-poetry','','[]','曾師班女頌兄功，何意安仁悼德宮。',64,'全唐诗/poet.song.143000.json','["曾師班女頌兄功，何意安仁悼德宮。", "圍解鴒原芳譽遠，塵昏鸞鏡玉容空。", "蕭騷風棘悲諸子，寂寞笙歌泣舞童。", "莫訝無從出衰涕，良人契合四般同。"]'),
('003888ae-d822-4d90-94b8-e2a9ce3ff6c7','二月十七夜與諸弟小酌嘗榧實誤食烏喙烏喙堇也古書云以堇寘酒殺人戲成小詩','周必大','宋','宋诗','song-poetry','','[]','伏神老芋不傷生，江蠏蟛蜞禍亦輕。',32,'全唐诗/poet.song.143000.json','["伏神老芋不傷生，江蠏蟛蜞禍亦輕。", "我獨好奇嘗酒堇，誤思榧實殺三彭。"]'),
('32105713-3e10-47fa-8f26-bea48011a8ce','題聳寒圖二絕  其一','周必大','宋','宋诗','song-poetry','','[]','浪傳魁梧越滄溟，過譽清夷得好銘。',32,'全唐诗/poet.song.143000.json','["浪傳魁梧越滄溟，過譽清夷得好銘。", "今見畫圖寒乞甚，心聲心畫果難形。"]'),
('ae63372f-de5c-4c6d-a5e7-9f08e896d8ab','題聳寒圖二絕  其二','周必大','宋','宋诗','song-poetry','','[]','道山仙聖典刑真，原廟功臣劍佩新。',32,'全唐诗/poet.song.143000.json','["道山仙聖典刑真，原廟功臣劍佩新。", "歸掩柴門無此夢，撚鬚畫腹對斯人。"]'),
('67675af2-726c-449b-b392-1f5b50c028eb','二月二十六日携家游青原歸入陽園酴醿盛開誦子中兄摛雲摇碧露繁星之句賦此詩','周必大','宋','宋诗','song-poetry','','[]','偶從山寺賞春還，問訊名花已破慳。',64,'全唐诗/poet.song.143000.json','["偶從山寺賞春還，問訊名花已破慳。", "清絕比梅加馥鬰，丰容似菊更妖嫻。", "碧雲重憶尊前句，紅纈遥思醉後顔。", "寒食清明祇旬日，綠齋芍藥待君攀。"]'),
('d1560b9d-0c38-4174-a8ce-564cd9da38c3','故翰林汪公端明居零陵時嘗作玩鷗亭今彊中提幹敬以其榜揭荆溪第中命某賦詩','周必大','宋','宋诗','song-poetry','','[]','賈生問鵩謾傷神，應愧先生入理深。',64,'全唐诗/poet.song.143000.json','["賈生問鵩謾傷神，應愧先生入理深。", "肝膽何曾分楚越，心形真欲混人禽。", "亭郵永鎮愚溪上，扁榜重開罨畫陰。", "見說騎鯨游汗漫，倘憑鷗鳥一傳音。"]'),
('2b762d5a-315c-441d-88b5-4a334e153b84','永新賀升卿携中原六圖相過其論古名將出師道路形勢可指諸掌爲賦此詩','周必大','宋','宋诗','song-poetry','','[]','歷歷山河一卷書，博聞疑是古潜夫。',64,'全唐诗/poet.song.143000.json','["歷歷山河一卷書，博聞疑是古潜夫。", "金城未入職方考，玉座正披輿地圖。", "取虢不應須假道，勝齊終恐用真儒。", "從來美玉勞三獻，豈比巾箱襲碔砆。"]'),
('384e82c5-9a73-4cfc-8fe5-35062f276a88','次韻芮漕國器憶去年上元二首  其一','周必大','宋','宋诗','song-poetry','','[]','使節番禺重，中朝社稷臣。',48,'全唐诗/poet.song.143000.json','["使節番禺重，中朝社稷臣。", "喜沉刁斗夜，遠布玉墀春。", "古寺看紅葉，蕃街試幻人。", "餘歡曾盡否，應記繞梁塵。"]'),
('6555721c-472c-49e0-90a7-cd344905ac90','次韻芮漕國器憶去年上元二首  其二','周必大','宋','宋诗','song-poetry','','[]','門外人隨月，窗前竹動風。',48,'全唐诗/poet.song.143000.json','["門外人隨月，窗前竹動風。", "老便佳節靜，病幸綠樽空。", "春至鴻聲北，人遥蝶夢東。", "隔年詩有債，生理固知窮。"]'),
('348342d5-4ffb-40c2-98b3-f950df84084d','次韻廣東芮漕時聞其部中寇退而湖湘之民方避地來此  其一','周必大','宋','宋诗','song-poetry','','[]','笑酌貪泉爲賦詩，凜然清節照南夷。',64,'全唐诗/poet.song.143000.json','["笑酌貪泉爲賦詩，凜然清節照南夷。", "廐空不納如羊馬，才大常嗤捕鼠貍。", "盜已奔秦非地險，心遲去魯只天知。", "愛君勤把歸鞍促，莫待鸞旗訪具茨。"]'),
('2d351357-2d37-47d8-bce1-69b38047e433','次韻廣東芮漕時聞其部中寇退而湖湘之民方避地來此  其二','周必大','宋','宋诗','song-poetry','','[]','病廢壺觴懶廢詩，漸參禪悅學希夷。',64,'全唐诗/poet.song.143000.json','["病廢壺觴懶廢詩，漸參禪悅學希夷。", "志非鴻鵠寧憎燕，路怯豺狼更畏貍。", "節物匆匆愁裏度，人情擾擾靜中知。", "已營二頃親籉笠，何日三間看塈茨。"]'),
('bc54da75-e225-4d0f-b800-5cfded306ef4','胡季懷有詩約羣從爲秋泉之集輒以山果助筵戲作二疊  其一','周必大','宋','宋诗','song-poetry','','[]','近詩通譜江西社，新釀纔先天下秋。',32,'全唐诗/poet.song.143000.json','["近詩通譜江西社，新釀纔先天下秋。", "已許眼中窺一豹，可容杯裏散千憂。"]'),
('21d30095-18c9-4a13-8769-e2fa890aa4e3','胡季懷有詩約羣從爲秋泉之集輒以山果助筵戲作二疊  其二','周必大','宋','宋诗','song-poetry','','[]','君家香醪蜜不如，試投木桃望瑶琚。',32,'全唐诗/poet.song.143000.json','["君家香醪蜜不如，試投木桃望瑶琚。", "敢誇所有易所無，潘郎一出果盈車。"]'),
('c15c9ba5-7f5f-4bfb-81d4-51573c89536d','病中次務觀通判韻','周必大','宋','宋诗','song-poetry','','[]','老眼亂蟬翼，樂事歎何有。',120,'全唐诗/poet.song.143000.json','["老眼亂蟬翼，樂事歎何有。", "經年不銜杯，更暇問濡首。", "愛山空在山，擿埴詎容走。", "塵埃登高帽，生澀彈棋手。", "三年一蒲團，近者坐欲朽。", "朝來獨何事，乾鵲窺甕牖。", "開門得新詩，刮膜如釋負。", "卷舒幾百回，呼舞駭鄰友。", "吾曹交以淡，悠久或采韭。", "此味只自知，他人薄玄酒。"]'),
('6079e780-ce01-48b1-9ea8-a0516351bd0a','次折仲古樞密韻寄題耒陽曹欽臣彥若藏書室','周必大','宋','宋诗','song-poetry','','[]','讀書清凈業，病亦與心違。',48,'全唐诗/poet.song.143000.json','["讀書清凈業，病亦與心違。", "簡蠹蟫穿字，帙藏蛛織衣。", "羨君傳七畧，何日款重闈。", "不憚浮湘去，其如失步歸。"]'),
('61c920fe-2320-4ea8-8161-8ce6f0975d08','訪胡邦衡庭前四菊茂甚因賦二絕  其一','周必大','宋','宋诗','song-poetry','','[]','大杓親分兩玉瓶，東籬手植萬金英。',32,'全唐诗/poet.song.143000.json','["大杓親分兩玉瓶，東籬手植萬金英。", "荒園有酒愁無菊，擬乞繁華助眼明。"]'),
('acbe5617-52d3-47b5-8481-0fb2712ebb56','訪胡邦衡庭前四菊茂甚因賦二絕  其二','周必大','宋','宋诗','song-poetry','','[]','揮毫曾對沈郎花，好事今同元亮家。',32,'全唐诗/poet.song.143000.json','["揮毫曾對沈郎花，好事今同元亮家。", "看即槐庭滿桃李，霜枝留與野人誇。"]'),
('22983032-78d8-494a-89d7-310f666cd127','往蒙丘宗元知縣以佳句爲壽今承解印次韻贈別','周必大','宋','宋诗','song-poetry','','[]','百里人人卧去輪，兒從父老季從昆。',64,'全唐诗/poet.song.143000.json','["百里人人卧去輪，兒從父老季從昆。", "飛鳬空戀古仙伯，展驥難留龐士元。", "蟾桂影圓人欲別，驪駒歌闋客無言。", "太微已動哀烏色，應待循良款相垣。"]'),
('a18b0988-8e7a-4d52-aa80-08caa2894584','十月十七日大椿堂小集胡從周季懷以予目疾皆許送白酒彌旬不至戲成長韻','周必大','宋','宋诗','song-poetry','','[]','畏疾甚畏威，目昏口止酒。',240,'全唐诗/poet.song.143000.json','["畏疾甚畏威，目昏口止酒。", "爾來時一中，免使論薄厚。", "儀康業廢祀，釀具散莫糾。", "採藥山已焚，種秫時轉後。", "門稀問字客，室乏借書缶。", "尚頼金石交，每顧貧病叟。", "前時相娛樂，如對疏廣受。", "有漿不待乞，似驗歲在酉。", "今日掃風軒，明日芼園䔩。", "白衣兩不來，往往化烏有。", "頗聞繼高會，霑醉牛馬走。", "寧忘伐木詩，酤湑吝朋友。", "或疑决西江，恥復餉升斗。", "胡不玩易象，樽簋納吾牖。", "二義倘未然，諾責何爲負。", "君兮優阮籍，僕也減兖守。", "結交十五年，果可不飲否。", "食言能無肥，有孚乃免咎。", "速宜倒糟牀，走送昔與醙。", "勿學比舍郎，夜半招吏部。"]'),
('ddf994f2-8e36-41d8-b4a2-5d82004d0a97','送七兄監廟赴南宮兼呈大兄知縣二首  其一','周必大','宋','宋诗','song-poetry','','[]','俊兄才學衆人知，富貴功名自有時。',64,'全唐诗/poet.song.143000.json','["俊兄才學衆人知，富貴功名自有時。", "海運今看鵬怒擊，韶成始是鳳來儀。", "狀頭謾詫文階峻，榜眼常多紫綬垂。", "家有鄭公遺笏在，一聞吉語即相貽。"]'),
('ca2924e8-5c35-44f5-8076-fcf42a82325c','送七兄監廟赴南宮兼呈大兄知縣二首  其二','周必大','宋','宋诗','song-poetry','','[]','河梁曾誦送行篇，蝸角牛毛十五年。',64,'全唐诗/poet.song.143000.json','["河梁曾誦送行篇，蝸角牛毛十五年。", "畢竟中間皆夢爾，祗今相對各蒼然。", "蕭蕭暫隔連床雨，蕩蕩初行萬斛船。", "誰近上林看躣馬，東陽詩句定先傳。"]'),
('3f85716e-11a4-4ca7-a586-3a3500fb75dc','曾英發運幹頃携二詩相過今復寄贈大篇且惠漢唐金石刻輒次前韻道謝  其一','周必大','宋','宋诗','song-poetry','','[]','君家奕葉播芳馨，室有圖書暴兩榮。',64,'全唐诗/poet.song.143000.json','["君家奕葉播芳馨，室有圖書暴兩榮。", "詩什編成風雅頌，寶章臨徧草真行。", "興來文陣千軍掃，醉後談鋒一座傾。", "已許春風來過我，從今日日聽嚴程。"]'),
('7d8b33a8-9f2b-4bb4-a057-5e99e659af36','曾英發運幹頃携二詩相過今復寄贈大篇且惠漢唐金石刻輒次前韻道謝  其二','周必大','宋','宋诗','song-poetry','','[]','屢空不擬論錢神，多病惟思對藥臣。',64,'全唐诗/poet.song.143000.json','["屢空不擬論錢神，多病惟思對藥臣。", "驟獲斷碑勝與縞，徐觀妙語可書紳。", "起予字字興三歎，集古駸駸訪九垠。", "欲寄佳州選何物，折楊聊復和韶鈞。"]'),
('56bc67e8-d35d-44b5-b7bf-a1d90ccbdc4b','贈孫次山','周必大','宋','宋诗','song-poetry','','[]','南澗有奇松，歲晚鬰青蒼。',120,'全唐诗/poet.song.143000.json','["南澗有奇松，歲晚鬰青蒼。", "北隴有寒梅，同傲雪與霜。", "實大華更榮，二美乃相望。", "我從採樵歸，聞此百步香。", "不辭踐荒穢，所欣識孤芳。", "可玩不可折，折枝亦何傷。", "但恐入市門，羞薄時世妝。", "少須子含酸，且復成其章。", "味宜調鼎食，材可中虹梁。", "知音不難逢，會當貢明光。"]'),
('2b4eecc6-e7b5-4afb-a02a-7938a48c656a','十二月二十二日葛守送羊羔酒戲占小詩','周必大','宋','宋诗','song-poetry','','[]','馬乳三年隔大官，羊羔今日倒芳樽。',32,'全唐诗/poet.song.143000.json','["馬乳三年隔大官，羊羔今日倒芳樽。", "淺斟低唱非吾事，醉夢惟應踏菜園。"]'),
('6961d6cc-9842-4b94-8252-b40a6a6f967c','胡邦衡送酒有酒婢之語次韻','周必大','宋','宋诗','song-poetry','','[]','侍郎情所寄，九醖屈楊枝。',24,'全唐诗/poet.song.143000.json','["侍郎情所寄，九醖屈楊枝。", "釀熟仍親酌，方成一段奇。"]'),
('612dd842-70d9-4a0f-aa55-28085c696ed8','青衣道人羅尚簡論予命宜退不宜進甚契鄙心連日求詩爲賦一首','周必大','宋','宋诗','song-poetry','','[]','亦知磨蝎直身宮，懶訪星官與曆翁。',64,'全唐诗/poet.song.143000.json','["亦知磨蝎直身宮，懶訪星官與曆翁。", "豈有虛名望蘇子，謾令簸惡似韓公。", "時清早退人誰肯，命薄當閒我自通。", "破戒問君君會否，幾人于此不相蒙。"]'),
('9ffbe57c-fa6b-4bfe-b991-bb3dd0e95c3a','次韻胡邦衡二首  其一','周必大','宋','宋诗','song-poetry','','[]','馮翊當年助匪頒，殊方此日奉賓歡。',64,'全唐诗/poet.song.143000.json','["馮翊當年助匪頒，殊方此日奉賓歡。", "淺斟想對銷金帳，生意重尋白玉槃。", "蟻泛似緣羶足慕，海凝如得毳逃寒。", "十羊百榼何須辨，試問東風可味酸。"]'),
('ac83775b-1e2a-4da9-9cd0-b3b0d6ee691b','次韻胡邦衡二首  其二','周必大','宋','宋诗','song-poetry','','[]','姚魏紛紛殆百家，天香一出自無譁。',64,'全唐诗/poet.song.143000.json','["姚魏紛紛殆百家，天香一出自無譁。", "傷多莫厭扶頭醉，貴少翻嫌滿眼花。", "康樂舊聞宜水竹，翰林新調带烟霞。", "從渠草木呈新巧，終愧吾公正且葩。"]'),
('7ca6c018-f958-4eab-bce0-17ddc1902d1d','再賦羊羔酒','周必大','宋','宋诗','song-poetry','','[]','日日茅柴帚掃愁，羶葷暫逐富兒游。',32,'全唐诗/poet.song.143000.json','["日日茅柴帚掃愁，羶葷暫逐富兒游。", "山中萬足天美祿，賸作酒材供拍浮。"]'),
('f1e47dde-1578-49ce-8030-0492a10ae45e','二月十五日同兄弟甥姪遊西臺次子載弟韻','周必大','宋','宋诗','song-poetry','','[]','地飲成真率，天風恕澀慳。',48,'全唐诗/poet.song.143000.json','["地飲成真率，天風恕澀慳。", "臺臨平野迥，人對老僧閒。", "已是尋春至，仍容載月還。", "郊坰有如此，能不數追攀。"]'),
('09781ec3-359a-4a74-8e40-9e2bf21f8b41','頃創棋色之論邦衡深然之明日府中花會戲成二絕  其一','周必大','宋','宋诗','song-poetry','','[]','局勢方迷棋有色，歌聲不發酒無飲。',32,'全唐诗/poet.song.143000.json','["局勢方迷棋有色，歌聲不發酒無飲。", "明朝一彩定三賽，國手秋唇雙牡丹。"]'),
('457524bb-5e11-4aa8-9f3f-8aa88458a971','頃創棋色之論邦衡深然之明日府中花會戲成二絕  其二','周必大','宋','宋诗','song-poetry','','[]','醉紅政不妨文飲，呼白從來要助歡。',32,'全唐诗/poet.song.143000.json','["醉紅政不妨文飲，呼白從來要助歡。", "棋色應同三昧色，牡丹何似九秋丹。"]'),
('efd732e4-4108-4039-870e-e8ace19aa735','二月十七日葛守錢倅出所和胡邦衡羊羔酒詩再次韻簡二公','周必大','宋','宋诗','song-poetry','','[]','德似羊羔春共頒，政如醇酎野多歡。',64,'全唐诗/poet.song.143000.json','["德似羊羔春共頒，政如醇酎野多歡。", "屬厭靖節杯中物，屢費將軍竹裏槃。", "疇昔調饑惟飲濕，祗今軟飽不言寒。", "唱酬妍麗歸公等，自笑梅翁語带酸。"]'),
('a2d42115-1919-404b-9bbe-ae72073680e8','次韻江州林黄中上巳日會邛州劉侍郎梓漕任直閣于庾樓','周必大','宋','宋诗','song-poetry','','[]','牙旗排檻曉鳴風，樓上何人清宴同。',64,'全唐诗/poet.song.143000.json','["牙旗排檻曉鳴風，樓上何人清宴同。", "東道主開軍府盛，西都賓共聖賢中。", "詞鋒永日論堅白，輦路他年記軟紅。", "頗念平生故人否，羽觴寂寞坐談空。"]'),
('b4f7db2e-c393-46cb-ab51-c1dff95d29db','五月南山蛟壞民田百畝胡英彥有詩次韻','周必大','宋','宋诗','song-poetry','','[]','旌陽昔屠蛟，勳塞天宇大。',108,'全唐诗/poet.song.143000.json','["旌陽昔屠蛟，勳塞天宇大。", "涵淹此遺種，千歲不悔過。", "良苗蔚懷新，倏作渺茫墮。", "懦夫愧鼻祖，無策祗愁卧。", "勇哉韓退之，切齒鰐爲禍。", "雄詞坐以逐，豈必勞㓠剁。", "有如衛承光，經物誰能涴。", "清泉復化土，魚鼈枯可剉。", "從今仕執珪，先已最郡課。"]'),
('a936e24f-f491-46a1-aba6-4a8b46dfc59b','胡長彥母解氏挽詞','周必大','宋','宋诗','song-poetry','','[]','蘐死蘭枯及老堂，翩翩丹旐逐風翔。',64,'全唐诗/poet.song.143000.json','["蘐死蘭枯及老堂，翩翩丹旐逐風翔。", "冰間鱗躍悲餘閣，紙上鸞迴閟古囊。", "年過九齡今代少，家留一桂異時芳。", "衰宗自恨通姻晚，不及陶家饌客觴。"]'),
('a232f94f-f002-4272-8520-381e3c5f4cfb','橫州太守趙持挽詩','周必大','宋','宋诗','song-poetry','','[]','憶驅千騎過田間，充國年耆鬢未斑。',64,'全唐诗/poet.song.143000.json','["憶驅千騎過田間，充國年耆鬢未斑。", "遺事劇談黄閣老，舊游追記玉門關。", "橫槎只道南通海，妖夢那知夜裂山。", "宿將如今幾人在，稍聽鼙鼓涕先潸。"]'),
('57003f60-acd4-4c5b-b7dd-a83128093b36','次韻湯朝美古意二首  其一','周必大','宋','宋诗','song-poetry','','[]','來賓有雙鴈，峨峨漸江皋。',48,'全唐诗/poet.song.143000.json','["來賓有雙鴈，峨峨漸江皋。", "豈嘗謀稻粱，逝將辨卑高。", "乃知可爲儀，初不在羽毛。", "鄙哉負塗豕，蹢躅爭一槽。"]'),
('6e7a4754-d001-40bb-a9f9-2a0849b43f6c','次韻湯朝美古意二首  其二','周必大','宋','宋诗','song-poetry','','[]','雲間兩鳴鶴，清聲聞蘭皋。',48,'全唐诗/poet.song.143000.json','["雲間兩鳴鶴，清聲聞蘭皋。", "洗我蛙黽耳，興逐秋天高。", "頗欲從之游，安得六翮毛。", "歸來三歎息，誰家鬧檀槽。"]'),
('f2999393-23fb-4fee-9543-a0708a67004f','游茅山道中望岡阜西南來勢若連環既赴三茅而尾北擲馬上口占','周必大','宋','宋诗','song-poetry','','[]','千峯溧陽來，勢若西南奔。',60,'全唐诗/poet.song.143000.json','["千峯溧陽來，勢若西南奔。", "遥拱三茅峯，不敢迫至尊。", "三茅如軒懸，次序儼弟昆。", "正西闢夷塗，群仙之所門。", "至今下泊官，往往彌旗旛。"]'),
('4a2a44d0-8201-4c00-97d8-5f9f9e54085a','戲示凝神庵張椿齡','周必大','宋','宋诗','song-poetry','','[]','仙師足厭踏京洛，亦復懶控茅峯鶴。',32,'全唐诗/poet.song.143000.json','["仙師足厭踏京洛，亦復懶控茅峯鶴。", "遺形聊示德充符，閉目定從陳鐵脚。"]'),
('654b0c2e-1a77-4395-af5a-a1e5c42530b7','次韻溧水令李彥平清賞圖','周必大','宋','宋诗','song-poetry','','[]','俗吏才拘拘，書生志落落。',192,'全唐诗/poet.song.143000.json','["俗吏才拘拘，書生志落落。", "均之窘几案，底處著丘壑。", "中山李長官，整暇非政學。", "庭虛吏早散，園古句頻琢。", "問之何能爾，行道輕去就。", "誰如班孟堅，齷齪事元舅。", "紛紛名利場，風俗日益蠱。", "腰圍黄金带，巧宦不難取。", "惟有佳兒孫，未易以力致。", "君看房杜輩，勳業照文字。", "徐勣尚笑之，垂誡甚切至。", "何如遺清白，世有賢者類。", "詩書聞過庭，杖屨奉安步。", "邑人爭指似，玉立稱祖父。", "豈惟慰眼前，門戶頼不仆。", "翁乎復何憂，弦歌樂朝暮。"]'),
('1bfa0797-18b4-475d-a7de-0a54f7609ad2','蕪湖宰沈約之端節惠詩編次韻爲謝','周必大','宋','宋诗','song-poetry','','[]','令君到處即文場，未怕簿書期會忙。',64,'全唐诗/poet.song.143000.json','["令君到處即文場，未怕簿書期會忙。", "神術有時朝賜履，賡歌無路贊垂裳。", "彭州篇什元飛動，工部交游更老蒼。", "自古詩人貴磨琢，試看淇澳詠文章。"]'),
('f4e1c427-0511-4c61-95e1-aa01fca343ca','池陽四詠  其一','周必大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','夜泊清溪弄水亭，棹謳徐起月華明。',32,'全唐诗/poet.song.143000.json','["夜泊清溪弄水亭，棹謳徐起月華明。", "水晶宮畔西湖上，除却兩邦無此清。"]'),
('3baae6b5-029f-4878-b7f4-f3d9960a91dc','池陽四詠  其二','周必大','宋','宋诗','song-poetry','','[]','天遣江山助牧之，詩材猶及杜筠兒。',32,'全唐诗/poet.song.143000.json','["天遣江山助牧之，詩材猶及杜筠兒。", "向來稍喜唐風集，今信樊川是父師。"]'),
('a5e88b7e-7a0c-47a8-a55e-4b8a67219bdd','池陽四詠  其三','周必大','宋','宋诗','song-poetry','','[]','君葺城樓望九峯，我能徧踏九芙蓉。',32,'全唐诗/poet.song.143000.json','["君葺城樓望九峯，我能徧踏九芙蓉。", "飛雲捲雨輸賢守，透月穿天乞老農。"]'),
('1681e5d7-3b44-4e88-b216-29319cf477bc','池陽四詠  其四','周必大','宋','宋诗','song-poetry','','[]','地占齊山最上頭，州城宛在水中洲。',32,'全唐诗/poet.song.143000.json','["地占齊山最上頭，州城宛在水中洲。", "蜿蜒正作長虹墮，吸住江河萬里流。"]'),
('969a19ea-e804-404f-b048-5c15d75bf0a0','再登翠微亭和同年湯平甫知縣二首  其一','周必大','宋','宋诗','song-poetry','','[]','上清別殿舊通明，仙聖飛騰戶不扃。',64,'全唐诗/poet.song.143000.json','["上清別殿舊通明，仙聖飛騰戶不扃。", "出郭尚疑窗列岫，絕堤始露嶽真形。", "奇奇怪怪無非洞，下下高高總可亭。", "但把醺酣酬絕景，天風吹面徑須醒。"]'),
('648eb56f-2a74-490f-9b1d-8402554e5f44','再登翠微亭和同年湯平甫知縣二首  其二','周必大','宋','宋诗','song-poetry','','[]','相君早日翼天飛，晚落江湖罪以微。',64,'全唐诗/poet.song.143000.json','["相君早日翼天飛，晚落江湖罪以微。", "好事一時開翠壁，佳名千古記黄扉。", "朝游要及鴉翻樹，夕返何妨螢濕衣。", "更得湯休奇絕句，後來誰憶謝玄暉。"]'),
('ca7ec641-948c-42bf-80f7-3f4568a344ae','登九華山化城峰','周必大','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','攀蘿度險捷猱猿，石角鈎衣屨盡穿。',32,'全唐诗/poet.song.143000.json','["攀蘿度險捷猱猿，石角鈎衣屨盡穿。", "莫訝遠尋金地藏，也曾徐步玉階前。"]'),
('93c275b4-5720-4b38-8c12-fdfc384be991','登龜山','周必大','宋','宋诗','song-poetry','','[]','注坡緣壁化城中，客慍奴嗔我亦慵。',32,'全唐诗/poet.song.143000.json','["注坡緣壁化城中，客慍奴嗔我亦慵。", "及至龜山還一上，爲憐高閣對雙峯。"]'),
('019bdcfc-aeec-4577-b2ba-12dd08779ffe','贈崇壽寺僧善修','周必大','宋','宋诗','song-poetry','','[]','老僧九十視眈眈，二十年來不下山。',32,'全唐诗/poet.song.143000.json','["老僧九十視眈眈，二十年來不下山。", "我得九華充法供，亦能禁足老山間。"]'),
('caec68b0-5b6a-48ea-a051-30db502e0266','游雲光寺李提舉領客將至留二小詩  其一','周必大','宋','宋诗','song-poetry','','[]','來如負弩先，去爲乘驄避。',24,'全唐诗/poet.song.143000.json','["來如負弩先，去爲乘驄避。", "江左一片石，留伴幽人醉。"]'),
('6f51fa8e-870d-4abc-bb7f-d62f39d9ccf9','游雲光寺李提舉領客將至留二小詩  其二','周必大','宋','宋诗','song-poetry','','[]','作者正七人，飲中空八仙。',24,'全唐诗/poet.song.143000.json','["作者正七人，飲中空八仙。", "長齋詎容醉，晉也合逃禪。"]'),
('1cbc7839-788f-4489-9809-a8820e08fbac','泛清溪至玉鏡潭','周必大','宋','宋诗','song-poetry','','[]','清溪水色勝於藍，祖石移舟下鏡潭。',32,'全唐诗/poet.song.143000.json','["清溪水色勝於藍，祖石移舟下鏡潭。", "妙絕畫屏并碧玉，謫仙不見與誰談。"]'),
('432205e6-89c2-4ca3-9144-02818166fc34','望皖公山','周必大','宋','宋诗','song-poetry','','[]','太婆嶺獨高秋浦，皖公山正望龍舒。',32,'全唐诗/poet.song.143000.json','["太婆嶺獨高秋浦，皖公山正望龍舒。", "端如牛女隔天漢，不似彭郎近小姑。"]'),
('c72c90a3-1382-4a44-97a4-0581a960c2b2','遊廬山佛手巖雪霽望南山','周必大','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','十日頑陰不見山，山中一夜雪封菴。',32,'全唐诗/poet.song.143000.json','["十日頑陰不見山，山中一夜雪封菴。", "伊予的有尋山分，日照北窗雲在南。"]'),
('bcf696ec-c621-4357-8a43-2e922868d0a1','遊廬山弔大林','周必大','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','上盡諸峯地轉平，天低雲近日多陰。',64,'全唐诗/poet.song.143000.json','["上盡諸峯地轉平，天低雲近日多陰。", "古來南北通雙徑，此去東西啟二林。", "虞世南碑從泯沒，白居易序合推尋。", "匡廬第一真僊境，忍使如今遂陸沉。"]'),
('430d7b31-8db9-4374-85b6-ff381d76277b','天池觀文殊燈','周必大','宋','宋诗','song-poetry','','[]','代馬腥膻暗五臺，南方世界且徘徊。',32,'全唐诗/poet.song.143000.json','["代馬腥膻暗五臺，南方世界且徘徊。", "一燈別是真知識，不用奔波學善財。"]'),
('c2906e3c-5a6d-4071-bf5c-9cde1de6a402','贈栖賢藏主可昇','周必大','宋','宋诗','song-poetry','','[]','我比同年百不能，只餘霜鬢愧師兄。',32,'全唐诗/poet.song.143000.json','["我比同年百不能，只餘霜鬢愧師兄。", "慇懃覓句無言說，共撥寒灰聽水聲。"]'),
('853381a5-0dff-4b61-9042-9e0266a306c7','游廬山舟中賦四韻','周必大','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','南北周廬阜，東西徧九華。',48,'全唐诗/poet.song.143000.json','["南北周廬阜，東西徧九華。", "宴安無酖毒，痼疾有烟霞。", "淡薄村村酒，甘香院院茶。", "馳驅君莫厭，此出勝居家。"]'),
('2cfec8f9-b0aa-4c34-8f78-8f65b3c129dc','陳宰有詩來迎次韻','周必大','宋','宋诗','song-poetry','','[]','沿泝江湖樂有餘，慆慆何必歎東徂。',64,'全唐诗/poet.song.143000.json','["沿泝江湖樂有餘，慆慆何必歎東徂。", "賞心到處窮佳境，好事逢人得異書。", "風浪送帆時一快，魚龍潜穴不須驅。", "歸來正使無泥洗，合壓香醪作歲除。"]'),
('48738225-ae80-48b3-bfcf-f33b296906cc','七兄以詩相迎次韻','周必大','宋','宋诗','song-poetry','','[]','昔作匆匆去，今成緩緩歸。',48,'全唐诗/poet.song.143000.json','["昔作匆匆去，今成緩緩歸。", "江山苦招隠，鷗鷺信忘機。", "已分漁舟老，還思鴈序飛。", "天公知客意，帆飽水生肥。"]'),
('437575c8-3f83-40f5-988a-355fe5e862fc','走筆次七兄韻戲奉新新莊','周必大','宋','宋诗','song-poetry','','[]','臘月更兼逢臘日，滿江飛雪兆豐年。',32,'全唐诗/poet.song.143000.json','["臘月更兼逢臘日，滿江飛雪兆豐年。", "從兄預借南昌米，多釀新醪醉樂天。"]'),
('c4cd2e4d-87d7-4e91-9bbb-ea26efe61628','次韻胡邦衡相迎','周必大','宋','宋诗','song-poetry','','[]','路逢驛使嶺頭回，喜得新詩勝得梅。',64,'全唐诗/poet.song.143000.json','["路逢驛使嶺頭回，喜得新詩勝得梅。", "情似春風繰楚柳，句如臘雪屑韓瑰。", "祇今皇側求賢席，底事公銜樂聖杯。", "台路六符行復煥，丹心一寸未應灰。"]'),
('1090ba58-a572-4317-8c2c-4e51c14cf80f','向以書戲邦衡云某自廬山游西山當就迎公召節今邦衡有詩督此語不驗次韻','周必大','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','慧遠遥同社，洪崖近拍肩。',48,'全唐诗/poet.song.143000.json','["慧遠遥同社，洪崖近拍肩。", "松枝年紀萬，棐實歲踰千。", "徑欲通天漢，忙因櫂酒船。", "香城均一握，易地即皆然。"]'),
('29b9545e-8421-4b33-9b4d-42cfaf6f482f','次韻張安國二首  其一','周必大','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','往時渡長蘆，行役甚迫束。',120,'全唐诗/poet.song.143000.json','["往時渡長蘆，行役甚迫束。", "忽逢萬人傑，大勝十年讀。", "升沉既日異，歲月空電速。", "公乎國元龜，用捨興替卜。", "如何白玉堂，儤直不滿宿。", "共惟中興主，志掃伊吾北。", "寧容廊廟具，尚賦諸侯祿。", "相茵朝以登，胡騎夕可逐。", "斯民補瘡痏，郡縣寬金穀。", "重將大手筆，繼鏤泰山玉。"]'),
('4d974ae6-4821-4cd3-a320-821e6576d6e8','次韻張安國二首  其二','周必大','宋','宋诗','song-poetry','','[]','子房思赤松，冠掛带不束。',120,'全唐诗/poet.song.143000.json','["子房思赤松，冠掛带不束。", "高風動縉紳，盛事爭誦讀。", "向來進匪銳，今退那得速。", "皇帝六載冬，熏燎郊再卜。", "均釐際蓋壤，賫予首耆宿。", "煌煌舊使星，密映紫微北。", "要令對青黎，聊復寓天祿。", "人言驥雖老，萬馬未易逐。", "方爲帝者師，敢請罷辟穀。", "魯公從周公，榮哉佩聯玉。"]'),
('ecc2300d-1eab-4262-99fb-52d6125da342','致政楊圖南僉判惠園亭石刻來索惡語寄題四首 湖山亭 其一','周必大','宋','宋诗','song-poetry','','[]','七十歸休古亦稀，誰瀕四十掛朝衣。',32,'全唐诗/poet.song.143000.json','["七十歸休古亦稀，誰瀕四十掛朝衣。", "天如不發湖山閟，林下真無一士歸。"]'),
('fc68361d-7989-45d6-b4b6-c114d23a26b0','致政楊圖南僉判惠園亭石刻來索惡語寄題四首 湖山亭 其二','周必大','宋','宋诗','song-poetry','','[]','不向山林不背村，清江東畔邑東門。',32,'全唐诗/poet.song.143000.json','["不向山林不背村，清江東畔邑東門。", "雨餘徐步看山罷，植杖沙邊試水痕。"]'),
('34bdbe65-5dc8-4d7b-92af-adaf99dcbe80','致政楊圖南僉判惠園亭石刻來索惡語寄題四首 秀野堂 其一','周必大','宋','宋诗','song-poetry','','[]','一見堂名憶豫州，豈知身在楚江頭。',32,'全唐诗/poet.song.143000.json','["一見堂名憶豫州，豈知身在楚江頭。", "主人久享園中樂，晚歲宜先天下憂。"]'),
('f83a459f-ea6c-4540-8750-e47a75d871bc','致政楊圖南僉判惠園亭石刻來索惡語寄題四首 秀野堂 其二','周必大','宋','宋诗','song-poetry','','[]','有竹無花山澤癯，有花無竹雪肌膚。',32,'全唐诗/poet.song.143000.json','["有竹無花山澤癯，有花無竹雪肌膚。", "洛陽城裏花連竹，迂叟規模定不迂。"]'),
('07a32a10-89a4-44dc-9014-44611e2aaa5a','次韻楊文發承議','周必大','宋','宋诗','song-poetry','','[]','才思春江下瀨船，腹藏經笱更便便。',64,'全唐诗/poet.song.143000.json','["才思春江下瀨船，腹藏經笱更便便。", "坐觀林谷升初日，吟到雲山合暮烟。", "憶昨傾囊携過我，知君得句總堪傳。", "古來虛誕相如賦，枉使劉郎意欲仙。"]'),
('9219c8d2-e37e-4160-bdf6-5ce1e5a4b2c0','樂順之司理用楊韻贊予去歲江行遊山之樂再次韻','周必大','宋','宋诗','song-poetry','','[]','遡洄險過峽中船，頼有名山寄靜便。',64,'全唐诗/poet.song.143000.json','["遡洄險過峽中船，頼有名山寄靜便。", "丘壑遂將從栗里，功名何敢夢凌烟。", "吾賢才術今誰敵，野老風流未可傳。", "趁取桃花日千里，蓬萊方丈會群仙。"]'),
('845cda12-1648-4bda-a4c2-5ed7984bf292','寄題太和陳氏益龜堂','周必大','宋','宋诗','song-poetry','','[]','講堂昔日飛三鱣，學館如今益十龜。',32,'全唐诗/poet.song.143000.json','["講堂昔日飛三鱣，學館如今益十龜。", "文字之神君勿卜，明年春榜印纍纍。"]'),
('645509b8-0098-4d83-b744-3c424519d4c1','次韻樂順之司理新釋花權及上元不張燈二絕句  其一','周必大','宋','宋诗','song-poetry','','[]','一自樂卿司樂籍，夭桃穠李鬭誇張。',32,'全唐诗/poet.song.143000.json','["一自樂卿司樂籍，夭桃穠李鬭誇張。", "陰成却落他人手，始悟分廂作法凉。"]'),
('80fadde7-600e-4943-b7e5-b41a680f1aef','次韻樂順之司理新釋花權及上元不張燈二絕句  其二','周必大','宋','宋诗','song-poetry','','[]','天閟華燈亦有情，知君新不顧傾城。',32,'全唐诗/poet.song.143000.json','["天閟華燈亦有情，知君新不顧傾城。", "遥憐擁被哦詩句，却遣隋珠照夜明。"]'),
('fc75a774-2b83-4b3f-a21e-59ac8421f907','信國太夫人慕容氏挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','門地榮聽履，夫家世夢松。',48,'全唐诗/poet.song.143000.json','["門地榮聽履，夫家世夢松。", "初終無一欠，富貴有三從。", "疾愈龍宮藥，恩加象服封。", "乘鸞期忽至，談笑返仙峯。"]'),
('6f2b8314-5377-4a72-ab40-a530f371015e','信國太夫人慕容氏挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','早暮闚遊識，曾饕截髮餐。',48,'全唐诗/poet.song.143000.json','["早暮闚遊識，曾饕截髮餐。", "升堂乖宿約，禊洛罷榮觀。", "女史新彤管，宗臣泣素冠。", "哀榮誰可擬，嘉祐富之韓。"]'),
('8443af53-1621-4dc0-a218-bbd1d4241bab','胡邦衡相過賞金鳳許詩未送邦衡復作木犀會二花殆是的對偶成四韻','周必大','宋','宋诗','song-poetry','','[]','身閒端合醉秋光，兩地名花况並芳。',64,'全唐诗/poet.song.143000.json','["身閒端合醉秋光，兩地名花况並芳。", "金作鳳形如許巧，木成犀理若爲香。", "髻頭自笑辜釵色，沙面誰知識带黄。", "莫問詩壇偃旗鼓，天生的對欠平章。"]'),
('d14644d0-50e7-4279-a21c-651f17ef11be','鹿鳴宴坐上次錢守韻','周必大','宋','宋诗','song-poetry','','[]','制舉巍科世有賢，聞孫傳業中興年。',64,'全唐诗/poet.song.143000.json','["制舉巍科世有賢，聞孫傳業中興年。", "貢才合益諸侯地，寵餞真開刺史天。", "有弟已容持布鼓，無能仍許鬻梔鞭。", "太平故事西崑體，指日皇都萬口傳。"]'),
('cb36219c-f910-49d8-b9f3-062057476243','曾季欽少卿安序堂次朱希真韻','周必大','宋','宋诗','song-poetry','','[]','行藏本同塗，明哲遇輒安。',144,'全唐诗/poet.song.143000.json','["行藏本同塗，明哲遇輒安。", "畎畝道可樂，肯思負鼎干。", "膰肉倘愛禮，豈遽涉汶川。", "大哉天地準，笑汝士女耽。", "丈人三吳秀，此理久已參。", "緬懷洛京老，知音賞英咸。", "佳名表棟宇，妙語來江山。", "至今編簡香，不謂室有蘭。", "君看爲邦問，正在簞瓢間。", "閲世從川流，如愚安石磐。", "聖門惟若人，始可語易占。", "不見繫辭中，巋然特書顔。"]'),
('4c9aeda4-8553-49e8-a8bf-d0e3d9678a9b','邦衡置酒出小鬟予以官柳名之聞邦衡近買婢名野梅故以爲對','周必大','宋','宋诗','song-poetry','','[]','濁水難攀清路塵，偶曾先後掌絲綸。',64,'全唐诗/poet.song.143000.json','["濁水難攀清路塵，偶曾先後掌絲綸。", "歸來久侍茵憑舊，至後初逢梅柳新。", "湖水欹斜應有意，春光漏洩不無因。", "絳帷幸許天荒破，日日當爲問道人。"]'),
('27870d28-420c-4555-afd4-2fc547374db8','楊昌英示性說次韻爲謝','周必大','宋','宋诗','song-poetry','','[]','聖學榛蕪欠掃際，誠齋刻意紹淵輿。',64,'全唐诗/poet.song.143000.json','["聖學榛蕪欠掃際，誠齋刻意紹淵輿。", "羊岐自昔迷多徑，鷄甕從今識廣居。", "西洛窮源談近似，南宗投隙說真如。", "早知大道容方軌，何用危塗轉棧車。"]'),
('e0b16a10-3324-4d65-b3c4-195752fa1a12','再次韻送楊昌英赴麻陽宰','周必大','宋','宋诗','song-poetry','','[]','未結絇絲侍玉除，聊紆墨綬奉安輿。',64,'全唐诗/poet.song.143000.json','["未結絇絲侍玉除，聊紆墨綬奉安輿。", "諸君相尚耻爲令，明府何妨大所居。", "歲美莫憂君不足，日長當念民無如。", "玉牀箭鏃何勞寄，只願章交使者車。"]'),
('70baa6d4-b1f9-4e51-b0a0-9fee5bda9670','胡季懷惠六出梅一枝仍枉絕句率然次韻勿笑迂拙','周必大','宋','宋诗','song-poetry','','[]','怪底雪花今歲少，東君聚巧入壺春。',32,'全唐诗/poet.song.143000.json','["怪底雪花今歲少，東君聚巧入壺春。", "老夫只學龜藏六，未羨梢頭首面新。"]'),
('df3cc4ee-919e-48bf-9d62-14d4ede6d2b8','夜夢次陳立夫韻','周必大','宋','宋诗','song-poetry','','[]','慣伴山僧汲澗泉，懶隨年少夢游仙。',32,'全唐诗/poet.song.143000.json','["慣伴山僧汲澗泉，懶隨年少夢游仙。", "風流輸與賢兄弟，朱閣臨風教李娟。"]'),
('e535ef21-8a3e-4dc5-9207-ae68c5f5cb65','七兄夜以小詩相戲走筆和韻','周必大','宋','宋诗','song-poetry','','[]','小蠻未解囀鶑簧，鑿壁偷分富燭光。',32,'全唐诗/poet.song.143000.json','["小蠻未解囀鶑簧，鑿壁偷分富燭光。", "不是龐公靈照女，誰人爲作起予商。"]'),
('11be535f-03ee-4f3d-8285-ab9e80a1d1dd','戊子歲除以粣代酒送邦衡邦衡有詩見戲仍送牛尾貍次韻','周必大','宋','宋诗','song-poetry','','[]','先生豈比習池徒，薄醖仍慙校尉厨。',64,'全唐诗/poet.song.143000.json','["先生豈比習池徒，薄醖仍慙校尉厨。", "獻粣聊將追粔籹，餔糟只欲伴屠蘇。", "削肌知自何人手，灌頂疑嘗釋氏醐。", "必許尋花兼問柳，敢辭挈榼更提壺。"]'),
('2c215c16-97ca-49b9-841e-b2dabba96d54','邦衡再送二詩一和爲甚酥二和牛尾貍  其一','周必大','宋','宋诗','song-poetry','','[]','金谷烹煎豈我徒，磨舂爭語夜闌厨。',64,'全唐诗/poet.song.143000.json','["金谷烹煎豈我徒，磨舂爭語夜闌厨。", "六年不賜湯官餌，除日猶分刺史酥。", "小惠無多真畫餠，大篇有味勝清醐。", "遥知發羃烘堂處，不見蒸鵝只瓠壺。"]'),
('80e7fbfe-8518-4dd6-be3c-058f251e9a5b','邦衡再送二詩一和爲甚酥二和牛尾貍  其二','周必大','宋','宋诗','song-poetry','','[]','追跡猶應怨獵徒，截肪何敢恨庖厨。',64,'全唐诗/poet.song.143000.json','["追跡猶應怨獵徒，截肪何敢恨庖厨。", "鱠鱸湖上休誇玉，煮豆瓶中未是酥。", "伴食偏宜十字餠，先驅正頼一巵餬。", "却因玉面新名字，腸斷元正白獸壺。"]'),
('942a8a49-5a89-4948-b474-e66718070374','後兩日大雪邦衡復用前韻作窮語戲和','周必大','宋','宋诗','song-poetry','','[]','天憐寓客混緇徒，十日無烟香積厨。',64,'全唐诗/poet.song.143000.json','["天憐寓客混緇徒，十日無烟香積厨。", "暮雪故教投碎米，饞涎那更忍流酥。", "旃毛齧盡寒生粟，風絮吟時韻怕醐。", "誰似維摩坐芳縟，散花別是一方壺。"]'),
('71b9bc7b-b2e7-4a82-9205-46982a2e0c04','己丑二月七日雨中讀漢元帝紀效樂天體','周必大','宋','宋诗','song-poetry','','[]','昭君顔如花，萬里度鷄漉。',168,'全唐诗/poet.song.143000.json','["昭君顔如花，萬里度鷄漉。", "古今罪畫手，妍醜亂羣目。", "誰知漢天子，袨服自列屋。", "有如公主親，尚許穹廬辱。", "况乃嬪嬙微，未得當獯鬻。", "奈何弄文士，太息爭度曲。", "生傳琵琶聲，死對青塚哭。", "向令老後宮，安得載簡牘。", "一時抱微恨，千古留賸馥。", "因嗟當時事，賢佞手反覆。", "守道蕭傅死，效忠京房戮。", "史臣一張紙，此外誰復錄。", "有琴何人操，有塚何人肅。", "重色不重德，聊以砭世俗。"]'),
('1708e4da-0a37-41fc-a764-ccc8d2802801','楊文甫主簿頃惠佳篇今赴松溪次韻送別','周必大','宋','宋诗','song-poetry','','[]','投林倦翼久知還，尚客君家伯仲間。',64,'全唐诗/poet.song.143000.json','["投林倦翼久知還，尚客君家伯仲間。", "入市每嫌妨杖屨，臨岐那忍問河山。", "家聲好在金陵簿，人物爭看玉笋班。", "他日銀黄夸里後，不妨徐伴野夫閒。"]'),
('c358b6c1-3bca-41d2-b1b8-c6717ac3eaee','錢守青原瑞靄圖','周必大','宋','宋诗','song-poetry','','[]','青原臺成知幾春，倚欄但愛江山新。',96,'全唐诗/poet.song.143000.json','["青原臺成知幾春，倚欄但愛江山新。", "那知遇事發奇秘，使君著眼惟憂民。", "魯臺當年有故事，首驗雲黄期歲美。", "鳳翔仙伯記新亭，不志游觀名雨喜。", "紛紛烟靄何足祥，豐年上瑞不可忘。", "江頭白粲連萬檣，賸與官家實太倉。"]'),
('cddec645-457c-4c16-9561-fd18aec17eef','胡邦衡生日以詩送北苑八銙日注二瓶','周必大','宋','宋诗','song-poetry','','[]','賀客稱觴滿冠霞，懸知酒渴正思茶。',64,'全唐诗/poet.song.143000.json','["賀客稱觴滿冠霞，懸知酒渴正思茶。", "尚書八餠分閩焙，主簿雙瓶揀越芽。", "妙手合調金鼎鉉，清風穩到玉皇家。", "明年敕使宣臺餽，莫忘幽人賦葉嘉。"]'),
('8f4e8536-b3e0-4716-ae18-9757cee58be9','邦衡再和再次韻','周必大','宋','宋诗','song-poetry','','[]','金華絕出氣凌霞，不愧君王坐賜茶。',64,'全唐诗/poet.song.143000.json','["金華絕出氣凌霞，不愧君王坐賜茶。", "商嶺烹來思舊樣，洛泉煎處歎新芽。", "詩評未怕人生癭，鹽濟惟防賊破家。", "賸欲蒼生蘇息否，剛嚴須是相王嘉。"]'),
('3a2b592c-88de-4657-b849-fee7231ad0c9','邦衡姪季懷亦惠二詩再次韻二首一頌其叔姪之美一解季懷生日不送茶之嘲  其一','周必大','宋','宋诗','song-poetry','','[]','竹林終日醉流霞，下客窮空祇戹茶。',64,'全唐诗/poet.song.143000.json','["竹林終日醉流霞，下客窮空祇戹茶。", "更欲打門奴酪粥，何殊歛手捧薑芽。", "賜金指日揮疏傅，盛饌常時設謝家。", "莫爲唱酬供一笑，從今便廢爾殽嘉。"]'),
('13980329-db35-4293-b903-f7f7b2544e7f','邦衡姪季懷亦惠二詩再次韻二首一頌其叔姪之美一解季懷生日不送茶之嘲  其二','周必大','宋','宋诗','song-poetry','','[]','蕭散玄真吏少霞，樵青日日爲煎茶。',64,'全唐诗/poet.song.143000.json','["蕭散玄真吏少霞，樵青日日爲煎茶。", "莫因閩粵臯蘆葉，却厭神仙掌上芽。", "竹戶勝棋非我事，菊潭試水是君家。", "不須更酹蘋洲塚，世以詩鳴句自嘉。"]'),
('1c0d2f22-928e-42e8-bb16-6f6f68f371fa','季懷設醴且示佳篇再賦一章以酬五詠','周必大','宋','宋诗','song-poetry','','[]','卯飲高樓徹暮霞，絕勝茅屋己公茶。',64,'全唐诗/poet.song.143000.json','["卯飲高樓徹暮霞，絕勝茅屋己公茶。", "篛包句好逢真賞，荷葉甌深稱嫩芽。", "詩老坐中容我輩，朝賢乞處藉君家。", "從來佳茗如佳什，屢酌新烹味轉嘉。"]'),
('3e6bab59-365f-45e0-815d-85a055475153','尚長道見和次韻二首  其一','周必大','宋','宋诗','song-poetry','','[]','詩成蜀錦粲雲霞，宮樣宜嘗七寶茶。',64,'全唐诗/poet.song.143000.json','["詩成蜀錦粲雲霞，宮樣宜嘗七寶茶。", "壓倒柳州甘露飲，洗空梅老白膏芽。", "睡魔豈是驚軍將，茗戰都緣避作家。", "怪底清風失炎暑，朝來吉甫誦柔嘉。"]'),
('94c4afd3-532e-4bf8-9a75-7312365f938f','尚長道見和次韻二首  其二','周必大','宋','宋诗','song-poetry','','[]','鍾山處士映高霞，止酒惟親睡起茶。',64,'全唐诗/poet.song.143000.json','["鍾山處士映高霞，止酒惟親睡起茶。", "遠向溪邊尋活水，閒于竹裏試陽芽。", "一鷗休問帝前席，七椀且同僧在家。", "所愧叔孫無五善，若爲重拜晉君嘉。"]'),
('f20c9a8d-2ba1-43bd-a5ae-0dd74f3da49d','頃嘗夢至善生院賦詩一聯己丑七月十三日因遊續成一絕','周必大','宋','宋诗','song-poetry','','[]','門外千竿竹繞牆，清風終日注回廊。',32,'全唐诗/poet.song.143000.json','["門外千竿竹繞牆，清風終日注回廊。", "五年未續夢中夢，得得來追三伏凉。"]'),
('a299f5f2-769d-4612-a487-430057b3a0c1','七月十五日邦衡用前韻送薰衣香二貼次韻爲謝','周必大','宋','宋诗','song-poetry','','[]','天香猶带曳裙霞，銀合行參到闕茶。',64,'全唐诗/poet.song.143000.json','["天香猶带曳裙霞，銀合行參到闕茶。", "賸馥欲霑吾臭味，普薰聊發善萌芽。", "心清此去誇僧舍，意可由來出內家。", "乞與博山添正氣，嶄巖曾辱更生嘉。"]'),
('232e7337-d1b8-4e17-8f41-91c36e7a5803','胡渙季享示壽詩二首十月二十五日因其生日次韻答之  其一','周必大','宋','宋诗','song-poetry','','[]','諸父聲名塞兩間，圭分青白轂朱丹。',64,'全唐诗/poet.song.143000.json','["諸父聲名塞兩間，圭分青白轂朱丹。", "莫年勛業心方壯，前日姦諛骨尚寒。", "聞道秋官還簡擢，獨憐處士失榮觀。", "如今喜見當家子，應賦忠州此日歡。"]'),
('022c2236-3783-4183-8099-0ed31f76e543','胡渙季享示壽詩二首十月二十五日因其生日次韻答之  其二','周必大','宋','宋诗','song-poetry','','[]','杲杲朝曦正在東，文心詩耳一時聰。',64,'全唐诗/poet.song.143000.json','["杲杲朝曦正在東，文心詩耳一時聰。", "學當鼎盛猶無敵，才過頤期想更工。", "此去宦游談笑裏，後來家慶畫圖中。", "俾昌俾乂詩人事，不似荒虛漢少翁。"]'),
('b07826f1-7f5a-4c5b-859f-a65492896fba','紫竹  其一','周必大','宋','宋诗','song-poetry','','[]','曾到蓬山驗異聞，浮筠翻動雪披紛。',32,'全唐诗/poet.song.143000.json','["曾到蓬山驗異聞，浮筠翻動雪披紛。", "紫莖綠葉騷人句，不在秋蘭在竹君。"]'),
('eefe7c36-4211-47a2-85d2-94cb24a5a2f7','紫竹  其二','周必大','宋','宋诗','song-poetry','','[]','青紫從來豈異端，要看同傲折膠寒。',32,'全唐诗/poet.song.143000.json','["青紫從來豈異端，要看同傲折膠寒。", "若輕間色思方節，圓竹應須斬萬竿。"]'),
('e5ca5292-1bd1-47ae-a441-6686a91d70a8','武崗太守羅挽辭二首  其一','周必大','宋','宋诗','song-poetry','','[]','富貴由身致，廉勤守自然。',48,'全唐诗/poet.song.143000.json','["富貴由身致，廉勤守自然。", "常珍惟脫粟，老伴只殘編。", "天已償高壽，人猶望百年。", "千車會葬者，誰間大夫賢。"]'),
('6fc664f6-f78c-4e99-818f-33dcd34a4dbd','武崗太守羅挽辭二首  其二','周必大','宋','宋诗','song-poetry','','[]','憶昨登門日，蟠齋擁夜爐。',48,'全唐诗/poet.song.143000.json','["憶昨登門日，蟠齋擁夜爐。", "疾姦頻齽齘，悼往一喑嗚。", "激烈看前輩，疲庸愧小儒。", "英靈那戢木，尚想抗狂胡。"]'),
('8602b465-6afd-4835-a40f-ed0b642a2b9b','萬安韋邦彥字俊臣携王民瞻楊廷秀謝昌國絕句相過次韻勉之  其一','周必大','宋','宋诗','song-poetry','','[]','盧溪筆力透天心，楊令文追正始音。',32,'全唐诗/poet.song.143000.json','["盧溪筆力透天心，楊令文追正始音。", "更讀池塘惠連句，識君何待接清襟。"]'),
('92a8319b-260a-452b-891f-a218c18eedd4','萬安韋邦彥字俊臣携王民瞻楊廷秀謝昌國絕句相過次韻勉之  其二','周必大','宋','宋诗','song-poetry','','[]','後學爭欹雨後巾，前賢久澤霧中文。',32,'全唐诗/poet.song.143000.json','["後學爭欹雨後巾，前賢久澤霧中文。", "韋郎勉力追三傑，他日人還傚五雲。"]'),
('33822ca4-d83c-4cef-9cc1-2f13a8f907b3','陳平叔相從四年文行粹然臨分惠詩有立身行道之問敢用陽司業勉學者之意次韻爲贈','周必大','宋','宋诗','song-poetry','','["\u534e\u5c71"]','好因輪斲悟觀書，莫守筌蹄覓兔魚。',64,'全唐诗/poet.song.143000.json','["好因輪斲悟觀書，莫守筌蹄覓兔魚。", "華嶽登來卑步仞，滄溟浮罷眇支渠。", "命窮且戲娛親綵，道合須牽奉詔裾。", "此外文章真小技，未應傾慕蜀相如。"]'),
('9001aff1-be29-4355-bb21-bd6526c2687e','贈黄格非','周必大','宋','宋诗','song-poetry','','[]','詩社飄零二十年，春官老子復登仙。',32,'全唐诗/poet.song.143000.json','["詩社飄零二十年，春官老子復登仙。", "豫章幸有橫枝在，好覓鸞膠續斷絃。"]'),
('65d356a7-6026-447c-a89e-91cd21a928e6','送梁山長老智顯','周必大','宋','宋诗','song-poetry','','[]','秦人溪畔漢人山，萬木參天六月寒。',32,'全唐诗/poet.song.143000.json','["秦人溪畔漢人山，萬木參天六月寒。", "寫向湯休詩集裏，老夫要作畫圖看。"]'),
('3fe50248-43fb-4cf8-a1e4-b427ec9b9ccd','丘成之司理明遠閣二首  其一','周必大','宋','宋诗','song-poetry','','[]','榜題聊復借揚雲，千古行藏本自明。',32,'全唐诗/poet.song.143000.json','["榜題聊復借揚雲，千古行藏本自明。", "此閣定非天祿閣，肯因寂寞便輕生。"]'),
('36d3788c-0666-4fd3-ad4d-b6a48ad1a55c','丘成之司理明遠閣二首  其二','周必大','宋','宋诗','song-poetry','','[]','家傳秘籍慕班斿，有子當追嗣與彪。',32,'全唐诗/poet.song.143000.json','["家傳秘籍慕班斿，有子當追嗣與彪。", "好事一瓻如許借，樓前百榼果爲丘。"]'),
('e8974406-8a38-4797-bac7-79f74ed16255','奉新宰楊廷秀携詩訪別次韻送之','周必大','宋','宋诗','song-poetry','','[]','誠齋詩名牛斗寒，上規大雅非小山。',96,'全唐诗/poet.song.143000.json','["誠齋詩名牛斗寒，上規大雅非小山。", "向來志氣薄黄散，忽爲五斗輟萬卷。", "兒童笑君非良圖，丈夫出處寧知渠。", "吳公適爲南州起，昔日河南今在此。", "好賢薦士任以身，門下賈生子其人。", "鄙夫料事倘不誤，早寄重脩滕閣句。"]'),
('939e716a-087f-4f36-800e-55f372e15877','五月三日遊簡寂食甜苦笋知觀歐陽齊年求詩','周必大','宋','宋诗','song-poetry','','[]','疏食山間荼亦甘，况逢苦笋十分甜。',32,'全唐诗/poet.song.143000.json','["疏食山間荼亦甘，况逢苦笋十分甜。", "君看齒頰留餘味，端爲森森正且嚴。"]'),
('0c1a8340-7cae-46ba-8ec2-5adb36b685ef','去夏邦衡胡侍郎生日嘗因茶詩致善頌其語果驗再賦一篇爲大用長生之祝且求賜茗作潤筆','周必大','宋','宋诗','song-poetry','','[]','壽杯又是酌流霞，醉眼還醒講殿茶。',64,'全唐诗/poet.song.143000.json','["壽杯又是酌流霞，醉眼還醒講殿茶。", "舉世甿謠思舊德，隔年詩讖託新芽。", "漢帷果慶登三傑，胡幕何愁不一家。", "賜也多言如屢中，合分龍餠示旌嘉。"]'),
('9da91b9c-dce5-4da3-94ad-3d8c83527eef','秘閣簷摧李監仁甫得湖北漕用溫公故事作小詩送之','周必大','宋','宋诗','song-poetry','','[]','臺門屋壞中丞去，秘閣簷摧少令歸。',32,'全唐诗/poet.song.143000.json','["臺門屋壞中丞去，秘閣簷摧少令歸。", "頼有溫公遺事在，故應早晚入黄扉。"]'),
('76915de2-91bb-4250-b6cf-0917af9db095','昨以清醇之酒爲邦衡侍郎壽乃蒙惠詩且約深秋清集至時侍郎當捨芙蓉而面三槐某已歸醉東籬悠然見南山矣次韻爲謝','周必大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','觚稜回首六經春，重挈荷囊上要津。',64,'全唐诗/poet.song.143000.json','["觚稜回首六經春，重挈荷囊上要津。", "桑下未忘三宿戀，柳邊仍喜一番新。", "即開東閣招奇士，快與西湖作主人。", "濁酒誇張真過矣，如公詩句乃清醇。"]'),
('ed94d986-c470-4f48-8f15-5ff5c82c17a4','邦衡侍郎再惠春字韻詩次韻懷舊敘謝且致登庸之祝','周必大','宋','宋诗','song-poetry','','[]','年年郡圃共尋春，夜夜神岡醉問津。',64,'全唐诗/poet.song.143000.json','["年年郡圃共尋春，夜夜神岡醉問津。", "公從鷄翹恩典厚，我遊麟省寵光新。", "願聞玉鉉調元日，幸攝金鑾草制人。", "致主勛華端有望，澆風于此合還醇。"]'),
('be437eab-e932-4eb3-81f6-a9038143a1b2','邦衡侍郎用舊韻慶予生朝賡續爲謝','周必大','宋','宋诗','song-poetry','','[]','蓬山落拓復經春，宦海茫洋懶問津。',64,'全唐诗/poet.song.143000.json','["蓬山落拓復經春，宦海茫洋懶問津。", "志節漸消平日壯，鬢毛空比去年新。", "午橋早並緋衣相，一月還同赤壁人。", "天遣駑駘追驥騄，無如才德異疵醇。"]'),
('522146d0-371c-4342-b3ee-5b6fe618bb31','夜直懷永和兄弟','周必大','宋','宋诗','song-poetry','','[]','玉堂清冷夜初長，風雨蕭蕭憶對牀。',32,'全唐诗/poet.song.143000.json','["玉堂清冷夜初長，風雨蕭蕭憶對牀。", "徼道傳呼鐘鼓密，夢魂那得到君傍。"]'),
('a5fb0a87-f2af-4feb-a981-a4eb2e5eee38','重陽預約三館同舍登高于真珠園前數日李粹伯秘丞除殿院','周必大','宋','宋诗','song-poetry','','[]','勝遊元在十人中，健翮先培萬里風。',64,'全唐诗/poet.song.143000.json','["勝遊元在十人中，健翮先培萬里風。", "落帽有歡追戲馬，峩冠無計屈乘驄。", "對門尚許官曹近，光館猶期燕會同。", "幸可誇張少年在，未須細數菊花叢。"]'),
('e2842e56-f30d-4fc7-b803-32a45308cd58','與館中同僚會邦衡侍郎于南山真珠園後兩日翰苑作開講會予不赴邦衡有詩見懷次韻','周必大','宋','宋诗','song-poetry','','[]','講席人期相鄭覃，石渠我忝繼齊堪。',64,'全唐诗/poet.song.143000.json','["講席人期相鄭覃，石渠我忝繼齊堪。", "碧琳殿邃同宣召，白玉堂深接笑談。", "寓直敢陪東道主，登高尚想北山南。", "洞巖勝集空回首，何日芒鞵許再探。"]'),
('ebb62895-28b2-4aa8-9e2e-07ed25856630','次韻邦衡哭季懷','周必大','宋','宋诗','song-poetry','','[]','談鋒激烈劍芒寒，素藴光輝珠在簞。',64,'全唐诗/poet.song.143000.json','["談鋒激烈劍芒寒，素藴光輝珠在簞。", "萬里未行騏驥死，百圍將半豫章殘。", "山中宰相今誰繼，地下修文古亦難。", "一讀名章三太息，淚流何待雍門彈。"]'),
('bb9bb1b0-9986-4be8-a8ea-ab110a7a5f92','紹興庚辰九月二十三日與浙東權帥同年程龍圖並試玉堂庚寅歲由少蓬寓直摛文發策試館職亦九月也有懷泰之輒寄四韻','周必大','宋','宋诗','song-poetry','','[]','當年給札踏金鑾，重到依然九月寒。',64,'全唐诗/poet.song.143000.json','["當年給札踏金鑾，重到依然九月寒。", "學士策詢學士策，秘書官試秘書官。", "自憐綠鬢非前度，尚喜青衫總一般。", "寄與浙東程閣老，莫矜紅旆笑儒酸。"]'),
('d5a10841-54fd-4ae8-ad66-053cdfb121eb','陳叔進祕書送鶉分粟爲謝乃辱佳句次韻發笑','周必大','宋','宋诗','song-poetry','','[]','有鶉不博禾三百，却向枯河擲釣緡。',32,'全唐诗/poet.song.143000.json','["有鶉不博禾三百，却向枯河擲釣緡。", "他日陳平宰天下，如瑜翻作指囷人。"]'),
('b5ffd7cb-6706-453f-b088-353421dd4b05','夜直玉堂讀王仲行正字文編用入館新詩韻','周必大','宋','宋诗','song-poetry','','[]','軼材騰驥騄，湧思决河渠。',48,'全唐诗/poet.song.143000.json','["軼材騰驥騄，湧思决河渠。", "枝茂根先實，名高士豈虛。", "君王憐舊土，館殿有新除。", "努力功名會，燕然欠大書。"]'),
('abb88fb3-6532-4307-aea8-f8e96dbda3c5','草具屈邦衡侍郎蒙賦即事新詩次韻皆敘坐上語他時共發一笑也','周必大','宋','宋诗','song-poetry','','[]','舊第閑梅塢，新知泥柳橋。',48,'全唐诗/poet.song.143000.json','["舊第閑梅塢，新知泥柳橋。", "情先春色動，節後歲寒凋。", "久矣承三接，宜然冠百僚。", "不須驚鶴髮，未礙插蟬貂。"]'),
('c7f5a1ee-1758-4508-bc4a-76f464d37780','和范至能舍人農圃堂韻','周必大','宋','宋诗','song-poetry','','[]','荒淫吳以顛，戰勝越云吉。',84,'全唐诗/poet.song.143000.json','["荒淫吳以顛，戰勝越云吉。", "是非兩安在，阡陌眇蕭瑟。", "公來開別墅，草莽手爬櫛。", "陰晴及寒暑，每到皆勝日。", "新詩弔興廢，收拾滿箱帙。", "有客師元亮，甫謝彭澤秩。", "幸分北窗風，容此易安膝。"]'),
('edc1c5c4-4b13-42b8-a3aa-41bb50e925f7','徐稚山龍學挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','有美傳清雅，無心問介通。',48,'全唐诗/poet.song.143000.json','["有美傳清雅，無心問介通。", "僉言宜僕射，累疏避司空。", "身後疏巾歛，生前濁酒中。", "吳鈎無路掛，灑淚寄西風。"]'),
('cdfb3ddf-ab6b-41da-88c5-21603fb52c5d','徐稚山龍學挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','昔者陪簪筆，比鄰記鑿垣。',48,'全唐诗/poet.song.143000.json','["昔者陪簪筆，比鄰記鑿垣。", "十年間何闊，一見欲無言。", "哭鯉何多難，葬嬴真少恩。", "天乎如可恃，門戶看諸孫。"]'),
('a2e99e79-1c00-442f-84a4-c250cb248311','徐子禮宗丞挽詞','周必大','宋','宋诗','song-poetry','','[]','符節何妨彩服斑，專心溫凊寧求閒。',64,'全唐诗/poet.song.143000.json','["符節何妨彩服斑，專心溫凊寧求閒。", "賓朋忽弔西河上，父子繼遊東岱間。", "前日臺門哭瓜葛，同時華屋落丘山。", "不須更問相從舊，行道之人亦涕潸。"]'),
('04f8343f-97af-47d6-a388-d64e7f75f335','慶邦衡生朝用去年韻','周必大','宋','宋诗','song-poetry','','[]','勁氣危言五十春，今騎廄馬踏天津。',64,'全唐诗/poet.song.143000.json','["勁氣危言五十春，今騎廄馬踏天津。", "葵傾夏日心彌切，松度秋霜色轉新。", "鼎鼐調和知有日，君臣慶會豈因人。", "周流四府須三紀，壽斚休辭痛飲醇。"]'),
('7d700bc3-08fb-4664-8c2b-b61fcf7cdb87','入直召對選德殿賜茶而退','周必大','宋','宋诗','song-poetry','','[]','綠槐夾道集昏鴉，敕使催宣坐賜茶。',32,'全唐诗/poet.song.143000.json','["綠槐夾道集昏鴉，敕使催宣坐賜茶。", "歸到玉堂清不寐，月鈎初上紫薇花。"]'),
('1d99a7b2-d4b8-464a-aa59-c0c14ee62e46','陳君舉示張孝愷行狀且求詩孝愷嘗攝令華亭有善狀','周必大','宋','宋诗','song-poetry','','[]','簡惠唐蘇令，文章漢甲科。',48,'全唐诗/poet.song.143000.json','["簡惠唐蘇令，文章漢甲科。", "滿朝空慰藉，漫仕竟蹉跎。", "有命窮何病，無年理則那。", "挽謳嗟不及，留與邑人歌。"]'),
('95c7bfc9-6d1c-43cf-a68c-d9eadddca671','過鄔子湖','周必大','宋','宋诗','song-poetry','','[]','萬頃湖光似鏡平，蜿蜒得得導舟行。',32,'全唐诗/poet.song.143000.json','["萬頃湖光似鏡平，蜿蜒得得導舟行。", "從來仕路風波惡，却是江神不世情。"]'),
('3658729d-fe62-4d4d-9a8c-6de0c5521ea4','奉祠還家姪繹以詩相迎次韻','周必大','宋','宋诗','song-poetry','','[]','聖朝有道合羞貧，清晝那容裹路珍。',64,'全唐诗/poet.song.143000.json','["聖朝有道合羞貧，清晝那容裹路珍。", "金馬玉堂辭漢殿，桃花流水訪秦人。", "敢吟莫莫休休句，且佚膠膠擾擾身。", "高會竹林欣有日，剩篘玉友釣溪鱗。"]'),
('6161188c-0d80-4cd0-add2-3e5727cf5c54','頃在道中聞邦衡侍郎將進周禮新解嘗賦詩就爲六月三日壽或謂名在丹書不當玷汙西清之儶老羞愧而止今蒙俯記生朝特貽佳作既仍舊韻敢隠鄙言狗尾之續斐然鶴頭之側必矣','周必大','宋','宋诗','song-poetry','','[]','九十談經似子春，三公虛位待平津。',64,'全唐诗/poet.song.143000.json','["九十談經似子春，三公虛位待平津。", "禮文元秉周邦舊，義訓重頒楚老新。", "鴟閣行看迎太宰，象篦應記講庖人。", "太平致了陰謀息，方信儒真道粹醇。"]'),
('ca9d2c29-0217-44fe-809e-a57b81e86012','次胡長彥司戶韻爲其生日壽長彥新授桂掾','周必大','宋','宋诗','song-poetry','','[]','丁年筆力斡千鈞，齒宿于今意轉新。',64,'全唐诗/poet.song.143000.json','["丁年筆力斡千鈞，齒宿于今意轉新。", "櫻伐廣陵聊作賦，梅開桂嶺定宜人。", "暫從南極通冠冕，會向東方領縉紳。", "菊有黄花潭有水，願尋漢事壽佳辰。"]'),
('9b22806f-fdfd-4295-924f-abe4a491bd55','前歲冬至與胡邦衡小語端誠殿下道值夏舊事今年邦衡舉易緯六日七分之說輒用子美五更三點爲對後數日得劉文潜運使書記去年館中團拜人今作八處感嘆成詩','周必大','宋','宋诗','song-poetry','','[]','青城小語慶新陽，共向紅雲拜玉皇。',64,'全唐诗/poet.song.143000.json','["青城小語慶新陽，共向紅雲拜玉皇。", "六日七分驚歲月，五更三點憶班行。", "屬車誰從黄麾仗，釣艇還飛白羽觴。", "猶勝去年三館客，十人八處耿相望。"]'),
('27fd37ca-b966-4c65-a2ef-05c53ee810ad','十二月十九日餞別劉文潜運使明日書來云醉夢中作小詩但記後兩句爲足成之','周必大','宋','宋诗','song-poetry','','[]','幽人門巷冷如冰，使節光華肯再登。',32,'全唐诗/poet.song.143000.json','["幽人門巷冷如冰，使節光華肯再登。", "今夕青燈話三館，明年何處說廬陵。"]'),
('cb00e8a1-a69f-4827-85fa-e0ee0525cf9e','胡邦衡賦琉璃燈簾詩次韻','周必大','宋','宋诗','song-poetry','','[]','鷄林空詫夜明簾，鰲禁曾迎金炬蓮。',64,'全唐诗/poet.song.143000.json','["鷄林空詫夜明簾，鰲禁曾迎金炬蓮。", "却向江城度元日，同看燈箔樂新年。", "盤紅坐覺光如晝，鞍白端令意欲仙。", "歸對短檠惟寂寞，酒醒漏永不成眼。"]'),
('6214e371-81b2-4a02-af0f-96f81a3cc357','送劉子和教授赴贛州兼簡府主洪景盧二首  其一','周必大','宋','宋诗','song-poetry','','[]','伊昔青衿地，于今絳帳師。',48,'全唐诗/poet.song.143000.json','["伊昔青衿地，于今絳帳師。", "家聲傳叔贛，宦學類先之。", "久已鴞音革，居然鱣服宜。", "誰開丞相閣，此士獨非奇。"]'),
('99b60b97-1935-4c59-aaff-0a23c7b40a59','送劉子和教授赴贛州兼簡府主洪景盧二首  其二','周必大','宋','宋诗','song-poetry','','[]','藉甚書詩帥，中和正爾歌。',48,'全唐诗/poet.song.143000.json','["藉甚書詩帥，中和正爾歌。", "人留河內寇，帝念禁中頗。", "餘事裒丁志，多聞重乙科。", "固無官長駡，解使客氈多。"]'),
('304b4f4e-421a-42ff-9c0f-4e874d1e99b7','邦衡再送皇字韻詩來次韻','周必大','宋','宋诗','song-poetry','','[]','賓鴻列陣競隨陽，却向丹山隠鳳凰。',64,'全唐诗/poet.song.143000.json','["賓鴻列陣競隨陽，却向丹山隠鳳凰。", "銀管題詩紛滿帙，金釵度曲儼分行。", "漢宮早促三更席，梁苑行稱萬壽觴。", "顧我飄零無著處，非公湔祓尚誰望。"]'),
('cc857c90-cd6a-4291-8fd5-ab8acd7b36fa','又次邦衡長子總幹韻','周必大','宋','宋诗','song-poetry','','[]','乃公剛骾迅詞章，濟美人推小贊皇。',64,'全唐诗/poet.song.143000.json','["乃公剛骾迅詞章，濟美人推小贊皇。", "君實固難安洛汭，子虛亦合薦周行。", "牛屠十九看游刃，媠擊三千始濫觴。", "早向秦淮迎輦輅，北征旗鼓正相望。"]'),
('ca4d57dc-199b-495c-a562-1b37ebcfa8ab','又次邦衡族姪長彥司戶韻','周必大','宋','宋诗','song-poetry','','[]','聖世恩榮盛孝章，北窗自欲傲羲皇。',64,'全唐诗/poet.song.143000.json','["聖世恩榮盛孝章，北窗自欲傲羲皇。", "通家喜燕鷄豚社，治郡愁親鴈鶩行。", "陌上花開人鬭草，甕頭酒熟客傳觴。", "及時行樂君休厭，召驛相將項背望。"]'),
('fdccdfbb-a7cd-4d5e-b4b2-812e650b20eb','同年楊謹仲教授以詩慶予得郡次韻二首  其一','周必大','宋','宋诗','song-poetry','','[]','謬向初元從九旒，坐狂朝蹟自宜收。',64,'全唐诗/poet.song.143000.json','["謬向初元從九旒，坐狂朝蹟自宜收。", "虛名誰競兩蝸角，懶性敢居千騎頭。", "聞道宵衣勞聖主，有時夜舞憶神州。", "二千石祿猶前却，何事真封萬戶留。"]'),
('6373481b-548d-48f9-9f1d-5069efc41faf','同年楊謹仲教授以詩慶予得郡次韻二首  其二','周必大','宋','宋诗','song-poetry','','[]','才氣崢嶸早斷鰲，詩豪不獨酒中豪。',64,'全唐诗/poet.song.143000.json','["才氣崢嶸早斷鰲，詩豪不獨酒中豪。", "其誰代匠頻傷斲，之子良庖却善刀。", "莫嘆廣文官獨冷，絕勝州郡職徒勞。", "泮宮方采僖侯藻，高士休尋仲蔚蒿。"]'),
('cfd02a23-e3a1-4831-a6a9-f069d107d05f','邦衡侍郎作一字韻詩贈麻姑觀道士李惟賓次韻仍效其體','周必大','宋','宋诗','song-poetry','','[]','蓋世成功陋漢黥，翩翩弨掛許誰檠。',64,'全唐诗/poet.song.143000.json','["蓋世成功陋漢黥，翩翩弨掛許誰檠。", "氣凌霄漢哮崖鶻，文闊波瀾掣海鯨。", "囊水謾疑韓信怯，柵淮終畏晉兵勍。", "先生餘事爲詩老，天宇行將一柱擎。"]'),
('997925bf-89e3-433c-bb01-64db938a7933','邦衡生日用舊歲韻','周必大','宋','宋诗','song-poetry','','[]','翊戴南陽第一春，馳驅北伐太原津。',64,'全唐诗/poet.song.143000.json','["翊戴南陽第一春，馳驅北伐太原津。", "天開今代風雲會，運應中興歲月新。", "霖雨正宜蘇大旱，清風未可作閑人。", "一杯安足爲公壽，看飲思堂萬斛醇。"]'),
('e5f8b153-224a-48f8-aac8-b69153098bfc','李秀實生日','周必大','宋','宋诗','song-poetry','','[]','泰陵耆舊日衰槁，白也胡爲顔色好。',128,'全唐诗/poet.song.143000.json','["泰陵耆舊日衰槁，白也胡爲顔色好。", "何曾山林採大藥，更說方書試鴻寶。", "千年鼻祖翔太清，至言八千授長生。", "坐令耳孫守家法，八十鬢綠雙瞳明。", "昨日人爲澹菴壽，今朝竹院笙歌奏。", "二老風流總健强，盛事他時恐難又。", "陛下聖德師文王，作興銳欲恢封疆。", "盍歸乎來不可緩，凜凜梁棟扶明堂。"]'),
('11791e08-3612-499d-b0d8-75fbede54fd0','同年楊謹仲教授生日  其一','周必大','宋','宋诗','song-poetry','','[]','玉笥岧嶤秀倚空，清江汀瀅日朝東。',32,'全唐诗/poet.song.143000.json','["玉笥岧嶤秀倚空，清江汀瀅日朝東。", "杜蕭安在王陳遠，極貴長生總屬公。"]'),
('be2cabe9-3771-4901-afde-6a3f0eff0bd9','同年楊謹仲教授生日  其二','周必大','宋','宋诗','song-poetry','','[]','伯起宜橫講殿經，若爲臨賀復廬陵。',32,'全唐诗/poet.song.143000.json','["伯起宜橫講殿經，若爲臨賀復廬陵。", "朝來冠雀銜三鱣，敢賀先生自此升。"]'),
('e63f020e-6f7b-40fa-9843-f1fee0adf2a3','同年楊謹仲教授生日  其三','周必大','宋','宋诗','song-poetry','','[]','孝行陰功未易量，從來家住玉田坊。',32,'全唐诗/poet.song.143000.json','["孝行陰功未易量，從來家住玉田坊。", "人間聊復三千歲，海上他時日更長。"]'),
('a6e11cd4-82a2-4d74-bc00-adcf671eab96','同年楊謹仲教授生日  其四','周必大','宋','宋诗','song-poetry','','[]','載酒過門欲壽公，酒杯有限壽無窮。',32,'全唐诗/poet.song.143000.json','["載酒過門欲壽公，酒杯有限壽無窮。", "玉樽祇在天西北，不惜年年爲一中。"]'),
('8dc4cc21-f554-46b7-9fac-8cceb0a9dfcd','邦衡侍郎用洪範五行推薄命而成傑句歎仰大手幾至閣筆勉賡盛意兼敘天人之應庶知託契辱愛如此其厚决非偶然耳','周必大','宋','宋诗','song-poetry','','[]','五行陳範推箕子，三壽爲朋及魯申。',64,'全唐诗/poet.song.143000.json','["五行陳範推箕子，三壽爲朋及魯申。", "二紀環周元附驥，四辰鱗次豈因人。", "交承紫掖追隨舊，遞宿金鑾契分申。", "人事天時已如此，更看坯甈累陶鈞。"]'),
('d8de2151-1b6e-4c53-9ae9-7639a0f47ad6','艤舟清江鎮從任子嚴運使求菊','周必大','宋','宋诗','song-poetry','','[]','陶令思歸未得歸，黄花想見遶東籬。',32,'全唐诗/poet.song.143000.json','["陶令思歸未得歸，黄花想見遶東籬。", "滿頭須插何容易，且向盤園乞一枝。"]'),
('141b6920-1282-47c4-90ed-c62dd90cea4b','近會同年賞芍藥嘗櫻桃楊謹仲教授有詩次韻爲謝兼簡周孟覺知縣','周必大','宋','宋诗','song-poetry','','[]','清晨自掃落花廳，小甕親篘竹葉青。',64,'全唐诗/poet.song.143000.json','["清晨自掃落花廳，小甕親篘竹葉青。", "簪盍同時過陋巷，臚傳相與記彤庭。", "階翻紅藥曾重見，敕賜朱櫻亦屢經。", "老去飄零無此夢，詩來吟咏有餘馨。"]'),
('5573e4f5-d260-4455-ae72-2629392f26a2','用舊韻爲邦衡生日壽','周必大','宋','宋诗','song-poetry','','[]','自公重踏秣陵春，便覺威加析木津。',64,'全唐诗/poet.song.143000.json','["自公重踏秣陵春，便覺威加析木津。", "尺五去天沙路近，八千爲歲壽杯新。", "休論滄海長生藥，要是清朝不死人。", "萬目睽睽觀燮理，紀元真欲稱熙淳。"]'),
('ad6fd654-d3f1-42c3-a1bc-9c04e47cf244','同年楊謹仲示薌林諸帖皆以老杜相期惟童敏德謂不合學東坡殆非知詩者輒用此意成惡語一篇爲誕辰壽祝頌之意見于末章','周必大','宋','宋诗','song-poetry','','[]','過江人物向汪曾，一世龍門未易登。',64,'全唐诗/poet.song.143000.json','["過江人物向汪曾，一世龍門未易登。", "常恐斯文無砥柱，獨推佳句有師承。", "波瀾正使來西蜀，廉陛何妨逼少陵。", "天遣百年如衛武，會賡懿戒頌中興。"]'),
('d3aa392c-8343-4c56-a3df-74aabece48cb','楊謹仲教授和徐師川中秋賞月詩邀余次韻','周必大','宋','宋诗','song-poetry','','[]','浥露清如洗，明河凈不流。',48,'全唐诗/poet.song.143000.json','["浥露清如洗，明河凈不流。", "珠圓合浦夜，潮盛浙江秋。", "朗詠陳王賦，幾成法善游。", "廣寒非獨冷，莫爲客氈謀。"]'),
('e40b505c-0439-4895-826a-bc409886bffc','寄題王公明樞使豫章佚老堂','周必大','宋','宋诗','song-poetry','','[]','君不見當年衛武髦且期，尚欲進德形箴規。',134,'全唐诗/poet.song.143000.json','["君不見當年衛武髦且期，尚欲進德形箴規。", "又不見潞公堂成過九十，精神折衝誇德威。", "公今年纔六十耳，朱顔綠鬢儼未衰。", "便從午橋樂暇佚，寧獨不畏二老譏。", "恭惟中興聖明主，焦心勞思撫四夷。", "山東河北因戎索，遠民日夜思王師。", "樓號籌邊宜屬意，堂名佚老誰敢知。", "請賡方叔壯猷雅，第入宣王復古詩。"]'),
('7a145c8c-e323-485d-ac94-e4a71604891d','蕭端偉挽詞','周必大','宋','宋诗','song-poetry','','[]','二頃良田數畝居，筆耕學殖世名儒。',64,'全唐诗/poet.song.143000.json','["二頃良田數畝居，筆耕學殖世名儒。", "蘭闈初喜携兒去，蒿里旋悲與婦俱。", "四季澆花非實相，百年種德是宏模。", "素車會葬空閭巷，試問他人得爾無。"]'),
('2f632118-f8ed-4428-8a61-ef77d97f0125','靖州太守李秀實挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','好學今康鼎，施家古計研。',48,'全唐诗/poet.song.143000.json','["好學今康鼎，施家古計研。", "旌麾更楚粵，翰墨過幽燕。", "晚厭三刀夢，歸開九秩年。", "生榮沒無憾，五福定誰先。"]'),
('8851bb98-a2d4-4fd4-b88c-fef71892365c','靖州太守李秀實挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','伊昔觀燈火，居然飲徹明。',48,'全唐诗/poet.song.143000.json','["伊昔觀燈火，居然飲徹明。", "一旬聊隠几，萬日遽成塋。", "回首歌鐘地，傷心挽鐸聲。", "朔風知客恨，猶欲返銘旌。"]'),
('f063994e-533f-47f3-b452-95728338fd73','過餘干吳師中秀才以小詩惠歙硯次韻謝之','周必大','宋','宋诗','song-poetry','','[]','舊曾起草向明光，獨與羅文近赭黄。',32,'全唐诗/poet.song.143000.json','["舊曾起草向明光，獨與羅文近赭黄。", "三載瓦池研竈墨，因君聊復夢儀凰。"]'),
('0aa900ad-a8e5-4e14-8cee-fdad39f326e9','恭和御制聞喜宴詩','周必大','宋','宋诗','song-poetry','','[]','聖武將犁老上庭，藝文先選彍中英。',64,'全唐诗/poet.song.143000.json','["聖武將犁老上庭，藝文先選彍中英。", "天扶基業生多士，世遇君師集大成。", "享備鈞臺同夏啟，果分漢會愧桓榮。", "堯言一日周天下，應陋詩人切響聲。"]'),
('592229a8-48fa-4431-9bee-e340ed508c15','次韻賀胡邦衡除龍圖閣學士且爲六月三日眉壽之祝','周必大','宋','宋诗','song-poetry','','[]','馬負羲圖二百春，榮光猶屬大河津。',64,'全唐诗/poet.song.143000.json','["馬負羲圖二百春，榮光猶屬大河津。", "細推班列論思舊，誰似耆英寵數新。", "龍閣便爲黄閣老，洞巖應繼紫巖人。", "他年笑視孫思邈，只自開皇至永淳。"]'),
('382040e9-a7af-453a-a5bb-f32324eeb877','端明殿學士王日嚴挽詞二首  其一','周必大','宋','宋诗','song-poetry','','[]','家世三珠樹，文章五鳳樓。',48,'全唐诗/poet.song.143000.json','["家世三珠樹，文章五鳳樓。", "中年穿豹尾，晚歲冠鰲頭。", "夷雅推簪橐，清醇動冕旒。", "居然似岐國，只欠啟金甌。"]'),
('7bc6eec9-46fb-4535-b814-15e5e2d66063','端明殿學士王日嚴挽詞二首  其二','周必大','宋','宋诗','song-poetry','','[]','念昔登黄甲，公時上玉堂。',48,'全唐诗/poet.song.143000.json','["念昔登黄甲，公時上玉堂。", "焉知叨儤直，尚及對批章。", "二紀光陰速，三年別恨長。", "懷賢已惆悵，感舊更凄凉。"]'),
('b5a99e44-16b2-4d00-877c-3ca9957056f2','次胡邦衡韻','周必大','宋','宋诗','song-poetry','','[]','右相虛來三見春，都人日夜望平津。',64,'全唐诗/poet.song.143000.json','["右相虛來三見春，都人日夜望平津。", "驊騮開路雲霄逼，霖雨思賢鼎鼐新。", "赤縣尚多淪異域，潢池猶自擾齊人。", "公如不爲蒼生起，風俗何由使再醇。"]'),
('5107c243-6fda-4a87-bf98-a91f6ec19949','從駕過德壽宮馬上得程泰之次庚寅玉堂舊韻有銀章金带之戲走筆爲謝','周必大','宋','宋诗','song-poetry','','[]','推敲也復從鳴鑾，鳳沼詩盟故未寒。',64,'全唐诗/poet.song.143000.json','["推敲也復從鳴鑾，鳳沼詩盟故未寒。", "兩制空煩舍人樣，外郎爭比大夫官。", "翰林今夜仍連直，講殿明朝豈兩般。", "畢竟五金如五味，莫因黄白議鹹酸。"]'),
('e64e347b-c757-41f4-8e18-749f4431c847','程泰之昨有金带銀章之句十月二十八日乃因押伴北使赤岸御筵服重金侍宴紫宸殿坐間嘗作數語爲戲後兩日復得其詩亦再次韻','周必大','宋','宋诗','song-poetry','','[]','甚日重黄侍玉鑾，幾時八座佩金寒。',64,'全唐诗/poet.song.143000.json','["甚日重黄侍玉鑾，幾時八座佩金寒。", "殿庭屬目誇新貴，部曲低頭拜舊官。", "五日尹京非細事，四時仕宦固多般。", "重行隔品詩仍健，應笑官卑語带酸。"]'),
('82461246-1509-4545-9ce9-07772e1ffd20','次韻徐元敏榷貨同年','周必大','宋','宋诗','song-poetry','','[]','當年駕鶴共驂鸞，對躡丹梯上廣寒。',64,'全唐诗/poet.song.143000.json','["當年駕鶴共驂鸞，對躡丹梯上廣寒。", "綠鬢旋同依帥府，華顛今並列王官。", "文才似我無多子，契分于君有四般。", "念舊不妨頻枉駕，甕頭隨意酌甘酸。"]'),
('7038c514-12f3-44e8-bc53-b8f6fc9acf9c','凌閣學挽詩二首  其一','周必大','宋','宋诗','song-poetry','','[]','南渡衣冠墜，俄然氣象還。',48,'全唐诗/poet.song.143000.json','["南渡衣冠墜，俄然氣象還。", "向微公數輩，誰濟國多限。", "劍履星辰上，風流水石間。", "名高仍壽考，天賦未全慳。"]'),
('857b9c3d-2db4-4784-ab34-b02fc047408b','凌閣學挽詩二首  其二','周必大','宋','宋诗','song-poetry','','[]','聖上開皇極，炎興纂異書。',48,'全唐诗/poet.song.143000.json','["聖上開皇極，炎興纂異書。", "蒼葭依玉樹，清水映汙渠。", "自爾音塵隔，思公歲月除。", "佳城空在望，無路祖喪車。"]'),
('9fe3511d-ba90-4a2a-b75d-2d931ba09ab8','韓子溫尚書以長句送江梅次韻','周必大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','憶昔歸田友麋鹿，雪裏尋梅踏瑶玉。',128,'全唐诗/poet.song.143000.json','["憶昔歸田友麋鹿，雪裏尋梅踏瑶玉。", "巡簷屢作杜陵笑，窮路幾爲步兵哭。", "忽逢綠衣鬢如雲，歌舞醉人睡昏昏。", "覺來但有風相襲，夢斷初無香返魂。", "豈知重見長安雪，喜極豐年簫鼓咽。", "更讀裴公東閣詩，仍分處士西湖月。", "皎如玉樹臨我傍，幸同待漏靴滿霜。", "但願和羹繼先業，不辭草制搜枯腸。"]'),
('22ff4afa-546f-493c-8a0f-5e7c0c1adee9','邦衡侍郎留金陵再用津字韻賦詩謝送賜茗復以丙申小春四銙寄贈','周必大','宋','宋诗','song-poetry','','[]','淳熙又貢第三春，驛騎新馳度劍津。',64,'全唐诗/poet.song.143000.json','["淳熙又貢第三春，驛騎新馳度劍津。", "七祖師泉難話舊，八功德水且嘗新。", "雪亭烹處休裝景，火閣煎時却可人。", "只恐春從官柳動，樂天還欲醉精醇。"]'),
('728bb367-6f12-43f8-bf98-4f7bc7061e3e','聞西省賞酴醿芍藥戲成小詩奉簡泰之侍講舍人年兄并以丁香橄欖百枚助筵却求殘花數枝  其一','周必大','宋','宋诗','song-poetry','','[]','羣玉圈中作主人，紫薇花底會嘉賓。',32,'全唐诗/poet.song.143000.json','["羣玉圈中作主人，紫薇花底會嘉賓。", "風光總屬程夫子，好念文昌寂寞春。"]'),
('f6222bea-734e-4961-bc49-4b329e07e4a1','聞西省賞酴醿芍藥戲成小詩奉簡泰之侍講舍人年兄并以丁香橄欖百枚助筵却求殘花數枝  其二','周必大','宋','宋诗','song-poetry','','[]','滿架冰肌合碧雲，翻階翠袖映紅裙。',32,'全唐诗/poet.song.143000.json','["滿架冰肌合碧雲，翻階翠袖映紅裙。", "玉堂只有金沙在，伴直明朝又屬君。"]'),
('519243cc-4f5f-4824-9cb0-79a46c598fbd','聞西省賞酴醿芍藥戲成小詩奉簡泰之侍講舍人年兄并以丁香橄欖百枚助筵却求殘花數枝  其三','周必大','宋','宋诗','song-poetry','','[]','酒頒挏馬莫分甘，金賜麟蹄敢搯尖。',32,'全唐诗/poet.song.143000.json','["酒頒挏馬莫分甘，金賜麟蹄敢搯尖。", "紅白賞殘堪底用，雨中折贈未傷廉。"]');
